// ════════════════════════════════════════════════════════════
// FIELDCHECK PROXY · v0.1
// ════════════════════════════════════════════════════════════
//
// The independent trust layer for sports recruiting and program evaluation.
//
// Two tracks, one substrate:
//   - PLAYER TRACK: coaches/scouts/programs vetting prospects
//   - PROGRAM TRACK: players/parents/transfer-portal players vetting programs
//
// Verdict shape (player track):
//   WALK_AWAY · VERIFY_FURTHER · REASONABLE_ADD · EDGE_DETECTED
//
// Verdict shape (program track):
//   WALK_AWAY · WORTH_A_LOOK · REASONABLE_CHOICE · EDGE_DETECTED
//
// Architecture:
//   - Cloudflare Worker with KV (caching) + D1 (corpus persistence)
//   - 8 real data adapters (Sports Reference, NCAA APR, NCAA infractions,
//     247Sports composite, transfer portal, NIL deals, news pulse, court records)
//   - Catalyst Interpreter (carryover from EdgeCheck) — structured Claude extraction
//   - Trust Ratings for Programs (the Morningstar move, quarterly published)
//   - Signed-JSON audit primitive at /v/:id/signed for partner integrations
//
// Substrate reuse from EdgeCheck:
//   - Worker scaffold + KV/D1 helpers
//   - Catalyst Interpreter pattern (renamed for sports domain)
//   - Trust Ratings template (8 dimensions adapted to programs)
//   - Stripe two-tier wiring ($29 Pro / $99 Edge)
//   - Resend integration
//
// No data provider has been paid. All sources are public records, public
// pages, or aggregations operated under fair-use rate-limits. Any program
// or player who disputes a finding can write to dispute@fieldcheck.ai
// and the methodology team will review with the standard 5-business-day SLA.

// ─── CORS + JSON helpers ─────────────────────────────────────
const CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400'
};

function json(obj, status = 200) {
  return new Response(JSON.stringify(obj, null, 2), {
    status,
    headers: { 'Content-Type': 'application/json', ...CORS }
  });
}

// ─── KV helpers ──────────────────────────────────────────────
async function kvGet(env, key) {
  if (!env.FIELDCHECK_KV) return null;
  const raw = await env.FIELDCHECK_KV.get(key);
  return raw ? JSON.parse(raw) : null;
}
async function kvPut(env, key, value, ttlSeconds = 86400) {
  if (!env.FIELDCHECK_KV) return false;
  await env.FIELDCHECK_KV.put(key, JSON.stringify(value), { expirationTtl: ttlSeconds });
  return true;
}

// ─── D1 helpers ──────────────────────────────────────────────
async function dbExec(env, sql, params = []) {
  if (!env.FIELDCHECK_DB) return { ok: false, error: 'no_db' };
  try {
    const result = await env.FIELDCHECK_DB.prepare(sql).bind(...params).run();
    return { ok: true, ...result };
  } catch (e) { return { ok: false, error: String(e).slice(0, 200) }; }
}
async function dbAll(env, sql, params = []) {
  if (!env.FIELDCHECK_DB) return [];
  try {
    const r = await env.FIELDCHECK_DB.prepare(sql).bind(...params).all();
    // D1 returns { results, success, meta } — extract array consistently
    return (r && r.results) ? r.results : (Array.isArray(r) ? r : []);
  } catch (e) {
    return [];
  }
}

// ════════════════════════════════════════════════════════════
// SPORTS REGISTRY — the multi-sport abstraction
// ════════════════════════════════════════════════════════════
//
// The single most important architectural decision in this worker:
// every sport-specific behavior is defined ONCE, here, in this registry.
// Adapters and scoring engines consult SPORTS[key] rather than hardcoding
// 'basketball' branches.
//
// To add a new sport (hockey, lacrosse, volleyball, etc.):
//   1. Add an entry to SPORTS with url builders, stat keys, thresholds,
//      and ranking tiers. ~40 lines.
//   2. Add Trust Ratings entries for marquee programs in PROGRAM_RATINGS.
//   3. That's it. Adapters and scoring engines pick up the new sport
//      automatically.
//
// Sports supported in v0.3:
//   - mens-basketball   (D1 NCAA, sports-reference /cbb/)
//   - womens-basketball (D1 NCAA, sports-reference /cbb-women/ + NCAA stats)
//   - football          (FBS, sports-reference /cfb/)
//   - baseball          (D1 NCAA, NCAA stats portal primary)
//   - mens-soccer       (D1 NCAA + FBref international links)
//   - tennis            (NCAA Tennis + ITA rankings + UTR public profiles)

