      player_url:  s => `https://www.sports-reference.com/cbb/players/${s}.html`,
      coach_url:   s => `https://www.sports-reference.com/cbb/coaches/${s}.html`,
      schools_url: s => `https://www.sports-reference.com/cbb/schools/${s}/`
