// ════════════════════════════════════════════════════════════
// NAME RESOLVER — name-based input, the demo-critical layer
// ════════════════════════════════════════════════════════════
//
// Coaches don't memorize Sports Reference slugs. They type names. The
// resolver fans out across sources and returns either:
//   - A high-confidence single match with a slug we can use for deep stats
//   - A list of candidate matches with confidence scores for the user to disambiguate
//   - "Insufficient Data" — honest signal that we don't have enough on this athlete
//
// This is the layer that makes the demo work for Arnav Nalani at SJSU
// (where Sports Reference has nothing) just as well as Cooper Flagg at
// Duke (where it has everything).

async function resolvePlayerName(env, { name, sport, schoolHint, profileUrls }) {
  if (!name || name.trim().length < 3) {
    return { error: 'name required (minimum 3 chars)' };
  }
  const sportKey = sport || 'mens-basketball';
  const cfg = SPORTS[sportKey];
  if (!cfg) return { error: 'unknown_sport', sport: sportKey };

  // Generate a sports-reference style slug from the name
  // (firstname-lastname-1 pattern — works for many SR pages)
  const slugBase = name.toLowerCase()
    .normalize('NFKD').replace(/[\u0300-\u036f]/g, '') // strip accents
    .replace(/[^a-z0-9 ]/g, '').trim().replace(/\s+/g, '-');

  const candidates = [];
  const sourceResults = {};

  // 1. Try Sports Reference (works well for power-five MBB/FB)
  if (cfg.has_deep_data === true || cfg.has_deep_data === 'partial') {
    for (const suffix of ['-1', '-2', '']) {
      const slug = slugBase + suffix;
      const sr = await fetchSportsRefPlayer(slug, sportKey);
      if (sr && !sr.error && sr.name) {
        candidates.push({
          source: 'sports-reference',
          slug,
          name: sr.name,
          school: sr.school,
          confidence: 'high',
          why: `Direct match on Sports Reference (${suffix || 'base slug'}).`
        });
        sourceResults.sports_reference = sr;
        break;
      }
    }
  }

  // 2. School roster confirmation — the most reliable source for tennis,
  //    women's sports, mid-major programs.
  if (schoolHint) {
    const roster = await fetchSchoolRoster(name, schoolHint, sportKey);
    sourceResults.school_roster = roster;
    if (roster.roster_confirmed) {
      candidates.push({
        source: 'school-roster',
        name: name,
        school: schoolHint,
        confidence: 'high',
        roster_url: roster.source_url,
        why: `Confirmed on official ${schoolHint} ${sportKey} roster page.`
      });
    }
  }

  // 3. Tennis-specific: ITA + UTR
  if (sportKey === 'tennis') {
    sourceResults.ita = await fetchITAPlayer(name);
    if (profileUrls && profileUrls.utr) {
      sourceResults.utr = await fetchUTRProfile(profileUrls.utr);
      if (sourceResults.utr && sourceResults.utr.utr) {
        candidates.push({
          source: 'utr',
          name: sourceResults.utr.name || name,
          confidence: 'high',
          utr: sourceResults.utr.utr,
          why: `UTR profile resolved with rating ${sourceResults.utr.utr}.`
        });
      }
    }
  }

  // 4. Composite ranking lookup (247) — for football/MBB power-five
  if (cfg.has_deep_data === true) {
    const slug247 = slugBase;
    const c247 = await fetch247Composite(slug247, null, sportKey);
    if (c247 && !c247.error && c247.composite_rank) {
      sourceResults.composite_247 = c247;
      candidates.push({
        source: '247sports',
        name: name,
        confidence: 'medium',
        composite_rank: c247.composite_rank,
        stars: c247.stars,
        why: `247Sports composite rank ${c247.composite_rank}, ${c247.stars}-star.`
      });
    }
  }

  // Determine resolution status
  const highConfidence = candidates.filter(c => c.confidence === 'high');
  const status = highConfidence.length > 0 ? 'resolved'
              : candidates.length > 0 ? 'partial'
              : 'insufficient_data';

  return {
    status,
    name,
    sport: sportKey,
    school_hint: schoolHint,
    candidate_count: candidates.length,
    candidates,
    source_results: sourceResults,
    methodology: 'Name resolver fans out across Sports Reference, school athletics roster pages, sport-specific registries (ITA/UTR for tennis, 247 for football/MBB), and the corpus. High-confidence resolution requires at least one direct match (SR slug, roster confirmation, or UTR profile). Insufficient Data when no source returns a confident match.'
  };
}

// ════════════════════════════════════════════════════════════
// EDGE ENGINES — where the moat lives
// ════════════════════════════════════════════════════════════
//
// The aggregation work above is hygiene. Anyone with a few weeks could
// build it. The actual edge — the thing competitors cannot replicate by
// reading the same websites — lives in these four engines:
//
//   1. Trajectory Delta — actual outcome vs incoming-ranking expectation
//   2. Coachability Extraction — structured signal from public quotes
//   3. Coach Culture Extraction — what the coach actually values
//   4. Honest Unknowns — refuse to fake confidence we don't have
//
// Engines 2 and 3 are LLM-driven; engines 1 and 4 are deterministic.

// ─── EDGE ENGINE 1: TRAJECTORY DELTA ─────────────────────────
// The single most important player-side signal: actual outcome vs
// what incoming ranking predicted. NOBODY publishes this for individual
// players. The math is simple; the synthesis across sources is the moat.
function computeTrajectoryDelta({ sport, incomingRank, careerStats, careerYears }) {
  const cfg = SPORTS[sport];
  if (!cfg || !careerStats) {
    return { delta: 0, confidence: 'insufficient_data',
             reason: 'Missing sport config or career stats; trajectory delta cannot be computed.' };
  }

  const primaryStat = parseFloat(careerStats[cfg.stat_keys.primary]);
  if (isNaN(primaryStat) || primaryStat === 0) {
    return { delta: 0, confidence: 'insufficient_data',
             reason: `${cfg.stat_keys.label} not parseable from career stats.` };
  }

  let expected, rankBucket;
  if (!incomingRank) {
    expected = cfg.trajectory_thresholds.primary_role;
    rankBucket = 'unranked';
  } else if (incomingRank <= cfg.ranking_tiers.elite) {
    expected = cfg.trajectory_thresholds.primary_high;
    rankBucket = 'elite';
  } else if (incomingRank <= cfg.ranking_tiers.high_major) {
    expected = cfg.trajectory_thresholds.primary_starter;
    rankBucket = 'high_major';
  } else if (incomingRank <= cfg.ranking_tiers.mid_major) {
    expected = cfg.trajectory_thresholds.primary_role;
    rankBucket = 'mid_major';
  } else {
    expected = cfg.trajectory_thresholds.primary_role / 2;
    rankBucket = 'unranked';
  }

  const ratio = (primaryStat - expected) / Math.max(expected, 0.01);
  const delta = Math.max(-10, Math.min(10, Math.round(ratio * 6)));

  let interpretation;
  if (delta >= 4) interpretation = 'Significant overperformance vs incoming ranking — late-bloomer or undervalued recruit signal.';
  else if (delta >= 2) interpretation = 'Modest overperformance vs ranking.';
  else if (delta <= -4) interpretation = 'Significant underperformance vs incoming ranking — character/development questions warranted.';
  else if (delta <= -2) interpretation = 'Modest underperformance vs ranking.';
  else interpretation = 'Outcome roughly matched what ranking predicted.';

  let confidence = 'medium';
  if (careerYears && careerYears >= 3) confidence = 'high';
  else if (careerYears && careerYears <= 1) confidence = 'low';

  return {
    delta, rankBucket, expected_stat: expected, actual_stat: primaryStat,
    stat_label: cfg.stat_keys.label, confidence, interpretation,
    methodology: 'Compares actual career-stat against expected stat for the player\'s incoming composite ranking tier. Tier thresholds are sport-specific.'
  };
}

// ─── EDGE ENGINE 2: COACHABILITY EXTRACTION ─────────────────
// Take a player's public quotes and extract structured coachability
// signals. Default to neutral. Confidence reflects volume and clarity.
async function extractCoachability(env, { playerName, recentQuotes, contextLosses }) {
  if (!env.ANTHROPIC_API_KEY || !recentQuotes || recentQuotes.length === 0) {
    return { score: null, confidence: 'insufficient_data',
             note: 'No public quotes available for analysis.' };
  }

  const prompt = `You are an analyst extracting coachability signals from a college athlete's public quotes.

Player: ${playerName}
Recent quotes (verbatim from public interviews):

${recentQuotes.map((q, i) => `[${i+1}] ${q}`).join('\n')}

${contextLosses ? `Context — recent losses: ${contextLosses}` : ''}

Extract a structured coachability assessment as JSON only:
{
  "score": integer 1-10 (5 = neutral, 7+ = strong positive, 3- = warning),
  "confidence": "low" | "medium" | "high",
  "positive_signals": array of {phrase, why} — exact quotes,
  "warning_signals": array of {phrase, why} — exact quotes,
  "summary": one factual sentence
}

Rules:
- Never invent quotes. Every "phrase" must be exact text from the input.
- Default to neutral (5) when evidence is thin.
- Confidence "low" if fewer than 3 quotes or quotes are short/generic.`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify({ model: 'claude-sonnet-4-5-20250929', max_tokens: 800, messages: [{ role: 'user', content: prompt }] })
    });
    if (!r.ok) return { score: null, confidence: 'extract_failed', error: 'http_' + r.status };
    const data = await r.json();
    const text = data.content?.[0]?.text || '';
    const m = text.match(/\{[\s\S]*\}/);
    if (!m) return { score: null, confidence: 'no_json' };
    const parsed = JSON.parse(m[0]);
    return {
      score: Math.max(1, Math.min(10, parseInt(parsed.score, 10) || 5)),
      confidence: parsed.confidence || 'low',
      positive_signals: Array.isArray(parsed.positive_signals) ? parsed.positive_signals.slice(0, 4) : [],
      warning_signals: Array.isArray(parsed.warning_signals) ? parsed.warning_signals.slice(0, 4) : [],
      summary: parsed.summary || '',
      methodology: 'Structured Claude extraction from public quotes. Confidence reflects volume and clarity.'
    };
  } catch (e) {
    return { score: null, confidence: 'extract_failed', error: String(e).slice(0, 120) };
  }
}

// ─── EDGE ENGINE 3: COACH CULTURE EXTRACTION ────────────────
// The killer feature for the program track. Reads everything a coach
// has said publicly about player development and team culture, then
// extracts a structured culture profile that surfaces what they actually
// believe vs what their PR says. Cross-referenced with their actual
// roster outcomes for delivery-vs-promise scoring.
async function extractCoachCulture(env, { coachName, programName, publicQuotes, rosterOutcomes }) {
  if (!env.ANTHROPIC_API_KEY || !publicQuotes || publicQuotes.length === 0) {
    return { profile: null, confidence: 'insufficient_data',
             note: 'No public quotes available for coach culture extraction.' };
  }

  const prompt = `You are an analyst extracting structured culture signals from a college coach's public statements.

Coach: ${coachName}
Program: ${programName || 'unknown'}
Public quotes (verbatim from interviews, press conferences, podcasts):

${publicQuotes.map((q, i) => `[${i+1}] ${q}`).join('\n')}

${rosterOutcomes ? `Roster outcomes context: ${rosterOutcomes}` : ''}

Extract a structured culture profile as JSON only:
{
  "values_emphasized": array of {value, evidence_phrase} — what the coach actually emphasizes (max 5),
  "development_philosophy": one-sentence summary of how this coach talks about developing players,
  "loss_response_pattern": one-sentence summary of how this coach handles losses publicly,
  "player_treatment_signal": "supportive" | "demanding" | "transactional" | "mixed" | "insufficient_signal",
  "promise_pattern": one-sentence summary of what this coach typically promises in recruiting,
  "delivery_alignment": "aligned" | "misaligned" | "unclear" — based on roster outcomes context if provided,
  "culture_score": integer 1-10 (5 = neutral, 7+ = strong positive culture signals, 3- = warning),
  "confidence": "low" | "medium" | "high",
  "summary": two-sentence factual summary
}

Rules:
- Never invent quotes. Every "evidence_phrase" must be exact text from input.
- Default to neutral / unclear when evidence is thin.
- "values_emphasized" should be the actual values shown in quotes, not a generic list.
- Confidence "low" if fewer than 5 quotes or quotes are generic media-trained boilerplate.`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify({ model: 'claude-sonnet-4-5-20250929', max_tokens: 1200, messages: [{ role: 'user', content: prompt }] })
    });
    if (!r.ok) return { profile: null, confidence: 'extract_failed', error: 'http_' + r.status };
    const data = await r.json();
    const text = data.content?.[0]?.text || '';
    const m = text.match(/\{[\s\S]*\}/);
    if (!m) return { profile: null, confidence: 'no_json' };
    const parsed = JSON.parse(m[0]);
    return {
      profile: {
        values_emphasized: Array.isArray(parsed.values_emphasized) ? parsed.values_emphasized.slice(0, 5) : [],
        development_philosophy: parsed.development_philosophy || '',
        loss_response_pattern: parsed.loss_response_pattern || '',
        player_treatment_signal: parsed.player_treatment_signal || 'insufficient_signal',
        promise_pattern: parsed.promise_pattern || '',
        delivery_alignment: parsed.delivery_alignment || 'unclear',
        summary: parsed.summary || ''
      },
      culture_score: Math.max(1, Math.min(10, parseInt(parsed.culture_score, 10) || 5)),
      confidence: parsed.confidence || 'low',
      methodology: 'Structured Claude extraction from public coach quotes. Cross-referenced with roster outcomes when provided. The single most defensible moat in the program track — synthesizes what coaches say with what their players actually experience.'
    };
  } catch (e) {
    return { profile: null, confidence: 'extract_failed', error: String(e).slice(0, 120) };
  }
}

// ─── EDGE ENGINE 4: HONEST UNKNOWNS ─────────────────────────
// The integrity layer. When data is too thin to score honestly, we say so
// loudly and refuse to fake a verdict. Three levels:
//   - 'rich'         — at least 3 sources returned signal-bearing data
//   - 'partial'      — 1-2 sources, scoring suspended on dimensions without data
//   - 'insufficient' — no signal-bearing sources; verdict = INSUFFICIENT_DATA
function assessDataFoundation(sourceResults) {
  if (!sourceResults || typeof sourceResults !== 'object') {
    return { tier: 'insufficient', signal_count: 0, signals: [], attempts: [] };
  }
  const signals = [];
  const attempts = [];

  // v0.4 rebalanced source weights:
  //   4 = bedrock — direct identity confirmation or quantitative rating
  //   3 = strong — career stats, composite ranking
  //   2 = moderate — program data point (APR, retention, infractions)
  //   1 = weak — reachability only, news mention
  for (const [key, val] of Object.entries(sourceResults)) {
    if (!val) {
      attempts.push({ source: key, status: 'no_response', strength: 0 });
      continue;
    }
    if (val.error) {
      attempts.push({ source: key, status: 'error', detail: val.error, strength: 0 });
      continue;
    }
    let signal_strength = 0;
    let signal_label = null;

    // Bedrock — direct identity
    if (val.roster_confirmed) {
      signal_strength = 4;
      signal_label = `Roster confirmation at ${val.school || 'school'}`;
    }
    else if (val.utr) {
      signal_strength = 4;
      signal_label = `UTR rating ${val.utr}`;
    }
    // Strong — career stats
    else if (val.career_stats && Object.keys(val.career_stats).length > 0) {
      signal_strength = 3;
      signal_label = 'Career stats present';
    }
    else if (val.composite_rank) {
      signal_strength = 3;
      signal_label = `247 composite rank ${val.composite_rank}`;
    }
    // Moderate — program-level
    else if (val.data && val.data.retention_pct) {
      signal_strength = 2;
      signal_label = `Retention ${val.data.retention_pct}%`;
    }
    else if (val.apr || val.four_year_avg) {
      signal_strength = 2;
      signal_label = `APR ${val.apr || val.four_year_avg}`;
    }
    else if (val.cases !== undefined && val.cases.length >= 0) {
      signal_strength = 2;
      signal_label = `${val.cases.length} infraction case(s) on file`;
    }
    // Weak — presence only
    else if (val.reachable) {
      signal_strength = 1;
      signal_label = 'Source reachable';
    }

    if (signal_strength > 0) {
      signals.push({ source: key, strength: signal_strength, label: signal_label });
      attempts.push({ source: key, status: 'signal', strength: signal_strength });
    } else {
      attempts.push({ source: key, status: 'no_signal', strength: 0,
                      detail: val.note || 'Source returned no signal-bearing data.' });
    }
  }

  // v0.29: Marquee program profile is a bedrock signal (rich curated dataset).
  // If sourceResults includes a `marquee_profile` key with profile data, it
  // counts as 5 signal strength — guarantees rich tier for marquee programs.
  if (sourceResults.marquee_profile && sourceResults.marquee_profile.slug) {
    signals.push({
      source: 'marquee_profile',
      strength: 5,
      label: 'FieldCheck curated marquee profile (championships, NFL pipeline, NIL, stadium, iconic moments)'
    });
    attempts.push({ source: 'marquee_profile', status: 'signal', strength: 5 });
  }

  const totalStrength = signals.reduce((a, b) => a + b.strength, 0);
  let tier;
  if (totalStrength >= 6) tier = 'rich';
  else if (totalStrength >= 3) tier = 'partial';
  else tier = 'insufficient';
  return { tier, signal_count: signals.length, total_strength: totalStrength, signals, attempts };
}

// ════════════════════════════════════════════════════════════
// CATALYST INTERPRETER (carryover from EdgeCheck, sports-tuned)
// ════════════════════════════════════════════════════════════
//
// Same structured-Claude pattern as EdgeCheck. The corpus IS the moat —
// every news event, infraction, transfer, NIL deal becomes a permanent
// time-stamped, source-attributed Catalyst object that future verdicts
// can cite. After 6 months of running, no competitor can backfill.
//
// Sports-specific catalyst types:
//   coaching_change · ncaa_infraction · transfer_event · injury_report
//   recruiting_event · nil_deal · academic_event · cultural_event

async function extractSportsCatalyst(env, sourceText, sourceUrl, sourceLabel, contextEntity) {
  if (!env.ANTHROPIC_API_KEY) return { error: 'ANTHROPIC_API_KEY not configured', skipped: true };
  if (!sourceText || sourceText.length < 30) return { error: 'source_too_short' };

  // Pre-filter: reject obvious non-college content before spending a Claude call.
  // URL-based: ESPN/Yahoo/etc. URLs containing pro-league path segments are unambiguous.
  const urlLower = (sourceUrl || '').toLowerCase();
  const proUrlMarkers = ['/nfl/', '/nba/', '/mlb/', '/nhl/', '/wnba/', '/mls/',
                         '/pga/', '/lpga/', '/tennis/atp/', '/tennis/wta/',
                         '/boxing/', '/mma/', '/ufc/', '/f1/', '/nascar/',
                         '/soccer/premier', '/soccer/champions', '/soccer/laliga',
                         '/highschool/', '/preps/'];
  for (const marker of proUrlMarkers) {
    if (urlLower.includes(marker)) {
      return { skipped: true, reason: 'pro_url_pattern', marker, source_label: sourceLabel };
    }
  }
  // Text-based pre-filter: pro team names that mean unambiguous pro content.
  // Some college teams share names (Tigers, Eagles, Hawks) so we keep this list to
  // *unique* pro team names that no D1 college program uses.
  const textLower = sourceText.toLowerCase().slice(0, 400);
  const proExclusiveNames = ['knicks', 'celtics', 'lakers', 'warriors', 'nuggets', 'timberwolves',
    'mavericks', 'thunder', 'pelicans', 'grizzlies', 'jazz', 'rockets', 'spurs', 'suns',
    'pistons', 'cavaliers', 'pacers', 'bucks', '76ers', 'sixers', 'raptors', 'nets',
    'hornets', 'magic', 'wizards',
    'patriots', 'cowboys', 'packers', 'steelers', 'eagles nfl',
    'yankees', 'red sox', 'mets', 'dodgers', 'astros', 'phillies', 'braves',
    'rangers nhl', 'maple leafs', 'canadiens', 'penguins', 'flyers'];
  for (const name of proExclusiveNames) {
    if (textLower.includes(name)) {
      return { skipped: true, reason: 'pro_team_name', name, source_label: sourceLabel };
    }
  }

  const dedupKey = (sourceUrl || '') + '|' + sourceText.slice(0, 200).toLowerCase().replace(/\s+/g, ' ').trim();
  const dedupBuf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(dedupKey));
  const dedupHash = Array.from(new Uint8Array(dedupBuf)).map(b => b.toString(16).padStart(2, '0')).join('').slice(0, 16);

  const cached = await kvGet(env, 'sport_catalyst:' + dedupHash);
  if (cached) return cached;

  const prompt = 'You are an analyst extracting a structured catalyst object from a sports news source for use in a COLLEGE sports player/program verdict engine.\n\n' +
    'Source: ' + (sourceLabel || 'unknown') + (sourceUrl ? ' (' + sourceUrl + ')' : '') + '\n' +
    (contextEntity ? 'Context entity: ' + contextEntity + '\n' : '') + '\n' +
    'Content:\n' + sourceText.slice(0, 3500) + '\n\n' +
    'CRITICAL FIRST STEP: Determine if this content is about NCAA Division I COLLEGE sports specifically (men\'s/women\'s basketball, football, baseball, men\'s soccer, tennis at NCAA D1 level). If the content is primarily about professional sports (NBA, NFL, MLB, NHL, MLS, ATP, WTA), high school sports, international leagues, or non-sports topics, set college_sports=false and return ONLY {"college_sports": false}. Do not extract a catalyst.\n\n' +
    'Output ONLY valid JSON, no preamble:\n' +
    '{\n' +
    '  "college_sports": true,\n' +
    '  "type": one of:\n' +
    '    "recruiting_event"  — commits, decommits, signing day, official visits, recruit rankings\n' +
    '    "coaching_change"   — hires, fires, retirements, contract extensions, assistant moves\n' +
    '    "transfer_event"    — portal entries/exits, transfer commitments, eligibility decisions\n' +
    '    "nil_deal"          — NIL contracts, collective announcements, valuation changes\n' +
    '    "ncaa_infraction"   — violations, sanctions, investigations, settlements\n' +
    '    "injury_report"     — significant injuries, return timelines, season-ending news\n' +
    '    "academic_event"    — APR/GSR changes, academic eligibility, graduation news\n' +
    '    "cultural_event"    — abuse allegations, departures over culture, protest, leadership controversy\n' +
    '    "team_news"         — game results with significance, season previews, power rankings, conference realignment, big roster milestones, championship implications\n' +
    '    "other"             — only if content is genuinely college sports but doesn\'t fit any other bucket,\n' +
    '  "sentiment": one of "positive" | "negative" | "neutral",\n' +
    '  "summary": one-sentence factual summary, no editorializing,\n' +
    '  "key_phrases": array of {phrase, weight 0-1} — exact text from source (max 5),\n' +
    '  "entities": array of {name, role: "player" | "coach" | "program" | "conference" | "ncaa"},\n' +
    '  "affects_verdicts_for": array of brief player or program names this catalyst would change a verdict on (max 4),\n' +
    '  "confidence": integer 1-10,\n' +
    '  "expires_at_hours": integer 24-720 (24h breaking news, 168h coaching change, 720h NCAA infraction),\n' +
    '  "thesis_change": one-sentence on how this changes verdict thesis\n' +
    '}\n\n' +
    'Critical rules:\n' +
    '- Never invent quotes. Every key_phrase must be exact text from source.\n' +
    '- "neutral" sentiment is allowed and often correct.\n' +
    '- For ncaa_infraction or cultural_event with negative sentiment, confidence threshold should reflect dispositive vs allegation.\n' +
    '- Use "team_news" liberally for significant college sports content that doesn\'t fit recruiting/coaching/transfer/NIL/infraction/injury — game results, conference news, season storylines all qualify.\n' +
    '- Reserve "other" for college sports content with no clear narrative hook.';

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-5-20250929',
        max_tokens: 800,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!r.ok) {
      const errBody = await r.text();
      return { error: 'anthropic_' + r.status, detail: errBody.slice(0, 200) };
    }
    const data = await r.json();
    const responseText = data.content?.[0]?.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { error: 'no_json_in_response' };
    let parsed;
    try { parsed = JSON.parse(jsonMatch[0]); }
    catch (e) { return { error: 'json_parse_failed', detail: e.message }; }

    // Gate 1: reject non-college content
    if (parsed.college_sports === false) {
      return { skipped: true, reason: 'not_college_sports', source_label: sourceLabel };
    }

    // Gate 2: reject "other" type — those are typically pro game recaps that
    // slipped through. The structured types (recruiting_event, coaching_change,
    // transfer_event, etc.) are the ones that actually inform a verdict.
    if (parsed.type === 'other') {
      return { skipped: true, reason: 'type_other_not_actionable', source_label: sourceLabel };
    }

    const expiresHours = Math.max(24, Math.min(720, parseInt(parsed.expires_at_hours, 10) || 168));
    const catalyst = {
      id: 'spcat_' + dedupHash,
      source_url: sourceUrl || null,
      source_label: sourceLabel || null,
      captured_at: new Date().toISOString(),
      type: parsed.type || 'other',
      sentiment: parsed.sentiment || 'neutral',
      summary: parsed.summary || '',
      key_phrases: Array.isArray(parsed.key_phrases) ? parsed.key_phrases.slice(0, 5) : [],
      entities: Array.isArray(parsed.entities) ? parsed.entities.slice(0, 8) : [],
      affects_verdicts_for: Array.isArray(parsed.affects_verdicts_for) ? parsed.affects_verdicts_for.slice(0, 4) : [],
      confidence: Math.max(1, Math.min(10, parseInt(parsed.confidence, 10) || 5)),
      thesis_change: parsed.thesis_change || '',
      expires_at: new Date(Date.now() + expiresHours * 3600 * 1000).toISOString(),
      hash: dedupHash
    };
    await kvPut(env, 'sport_catalyst:' + dedupHash, catalyst, 86400);
    try {
      await dbExec(env,
        'INSERT OR REPLACE INTO sport_catalysts (id, source_url, source_label, captured_at, type, sentiment, summary, key_phrases_json, entities_json, affects_for_json, confidence, thesis_change, expires_at, hash) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)',
        [
          catalyst.id, catalyst.source_url, catalyst.source_label, catalyst.captured_at,
          catalyst.type, catalyst.sentiment, catalyst.summary,
          JSON.stringify(catalyst.key_phrases), JSON.stringify(catalyst.entities),
          JSON.stringify(catalyst.affects_verdicts_for),
          catalyst.confidence, catalyst.thesis_change, catalyst.expires_at, catalyst.hash
        ]
      );
    } catch (e) { /* table may not be migrated yet */ }
    return catalyst;
  } catch (e) {
    return { error: 'extract_failed', detail: String(e).slice(0, 200) };
  }
}

// ════════════════════════════════════════════════════════════
// SCORING ENGINES
// ════════════════════════════════════════════════════════════
//
// Each track produces 4 dimension scores, each on 1-10 scale.
// The scoring is rule-based on top of the data adapter outputs, NOT
// LLM-based — this is critical for auditability. A coach must be able
// to ask "why did this player get a 4 on Verification?" and we must
// answer with the exact rule and the exact data input.
//
// LLM is used for the NARRATIVE (the verdict summary) but not the SCORES.
// This is the same posture as EdgeCheck.

// ─── PLAYER SCORING ──────────────────────────────────────────
// Four dimensions:
//   1. Trajectory   — does development match recruit ranking?
//   2. Coachability — proxies from social/film/team behavior
//   3. Stability    — how often did they switch programs / why?
//   4. Verification — do reported stats match game logs?
function scorePlayer({ sportsRef, composite247, transferEvents, nilDeals }) {
  const dims = { trajectory: 5, coachability: 5, stability: 5, verification: 5 };
  const reasons = { trajectory: [], coachability: [], stability: [], verification: [] };

  // TRAJECTORY: did stats improve over career? Did they exceed/match composite rank?
  if (sportsRef && sportsRef.career_stats) {
    const ppg = parseFloat(sportsRef.career_stats.pts_per_g || 0);
    const rank = composite247 && composite247.composite_rank;
    if (ppg >= 18) { dims.trajectory += 2; reasons.trajectory.push('Career PPG >= 18 (high)'); }
    else if (ppg >= 12) { dims.trajectory += 1; reasons.trajectory.push('Career PPG >= 12 (above starter level)'); }
    if (rank && rank <= 50 && ppg < 10) {
      dims.trajectory -= 2;
      reasons.trajectory.push('Top-50 recruit but career PPG below 10 — underperformance vs ranking');
    }
    if (rank && rank > 200 && ppg >= 15) {
      dims.trajectory += 2;
      reasons.trajectory.push('Sub-200 recruit but career PPG >= 15 — late bloomer signal');
    }
  }

  // COACHABILITY: not directly observable from this dataset; we lean on
  // catalyst signals (social media patterns, post-game interview tone)
  // when available. Default 5 means "no signal either way."
  reasons.coachability.push('Default 5: requires film + social-signal catalyst extraction (Phase 2 enrichment).');

  // STABILITY: program-switching = lower stability
  if (transferEvents && Array.isArray(transferEvents.events)) {
    const transfers = transferEvents.events.length;
    if (transfers === 0) { dims.stability += 2; reasons.stability.push('No transfers — high stability'); }
    else if (transfers === 1) { dims.stability += 0; reasons.stability.push('One transfer — common, no signal'); }
    else if (transfers === 2) { dims.stability -= 2; reasons.stability.push('Two transfers — elevated risk'); }
    else if (transfers >= 3) { dims.stability -= 4; reasons.stability.push('Three+ transfers — major instability flag'); }
  } else {
    reasons.stability.push('Default 5: no transfer history data available for this player.');
  }

  // VERIFICATION: do Sports Reference stats look internally consistent?
  if (sportsRef && sportsRef.career_stats) {
    const ppg = parseFloat(sportsRef.career_stats.pts_per_g || 0);
    const fgPct = parseFloat(sportsRef.career_stats.fg_pct || 0);
    if (ppg > 0 && fgPct > 0 && fgPct <= 1) {
      dims.verification += 2;
      reasons.verification.push('Career stats present and internally consistent on Sports Reference.');
    }
  } else {
    dims.verification -= 2;
    reasons.verification.push('No verifiable career stats found on Sports Reference — high verification risk.');
  }

  // Clamp all to [1, 10]
  for (const k of Object.keys(dims)) {
    dims[k] = Math.max(1, Math.min(10, dims[k]));
  }
  return { scores: dims, reasons };
}

// ─── PROGRAM SCORING ─────────────────────────────────────────
// Four dimensions:
//   1. Development     — recruits' outcomes vs incoming rank (Trajectory Delta)
//   2. Retention       — what % stay vs transfer/quit
//   3. Cultural Health — assistant turnover, infractions, abuse signals
//   4. Promise Delivery — recruiting promises vs actual playing time/development
function scoreProgram({ apr, infractions, transferData, sportsRefCoach, recentCatalysts, profile }) {
  // v0.29: 8-dimension proprietary grid. When a rich PROGRAM_PROFILE exists,
  // dimensions are computed from PROFILE DATA (championship history, NFL pipeline,
  // coach lineage, NIL spend, stadium, traditions). For programs without a
  // curated profile, falls back to thin rules-based scoring on external sources.
  if (profile) return scoreProgramFromProfile({ profile, apr, infractions, transferData, recentCatalysts });

  // Legacy 4-dim grid for non-marquee programs (keeps backward compat)
  const dims = { development: 5, retention: 5, cultural_health: 5, promise_delivery: 5 };
  const reasons = { development: [], retention: [], cultural_health: [], promise_delivery: [] };

  if (sportsRefCoach && Array.isArray(sportsRefCoach.seasons) && sportsRefCoach.seasons.length >= 5) {
    dims.development += 1;
    reasons.development.push('Coach has 5+ seasons of trackable record');
  }
  if (apr && apr.data_present && apr.four_year_avg >= 985) {
    dims.development += 2;
    reasons.development.push('NCAA APR 4-year avg >= 985 (top-quartile academic-athletic balance)');
  } else if (apr && apr.data_present && apr.four_year_avg < 950) {
    dims.development -= 2;
    reasons.development.push('NCAA APR 4-year avg below 950 — academic eligibility risk');
  }
  if (transferData && transferData.data) {
    const ret = transferData.data.retention_pct;
    if (ret >= 85) { dims.retention += 3; reasons.retention.push('Retention >= 85% — top-quartile retention'); }
    else if (ret >= 75) { dims.retention += 1; reasons.retention.push('Retention 75-84% — above median'); }
    else if (ret < 65) { dims.retention -= 3; reasons.retention.push('Retention below 65% — major outflow concern'); }
    else if (ret < 75) { dims.retention -= 1; reasons.retention.push('Retention 65-74% — below median'); }
  }
  if (infractions && Array.isArray(infractions.cases)) {
    const recent = infractions.cases.filter(c => c.year >= new Date().getFullYear() - 5);
    const level1 = recent.filter(c => c.type && c.type.includes('Level I'));
    const level2 = recent.filter(c => c.type && c.type.includes('Level II'));
    if (level1.length > 0) {
      dims.cultural_health -= 4;
      reasons.cultural_health.push(`${level1.length} Level I NCAA infraction(s) in last 5 years — major cultural flag`);
    } else if (level2.length > 0) {
      dims.cultural_health -= 2;
      reasons.cultural_health.push(`${level2.length} Level II NCAA infraction(s) in last 5 years`);
    } else {
      dims.cultural_health += 1;
      reasons.cultural_health.push('No major NCAA infractions in last 5 years');
    }
  }
  if (apr && apr.data_present && transferData && transferData.data) {
    const academic = apr.four_year_avg >= 980;
    const retention = transferData.data.retention_pct >= 80;
    if (academic && retention) {
      dims.promise_delivery += 3;
      reasons.promise_delivery.push('Both APR and retention strong — program delivers what it sells');
    } else if (!academic && !retention) {
      dims.promise_delivery -= 3;
      reasons.promise_delivery.push('Both APR and retention weak — promise-delivery gap is real');
    }
  }
  if (Array.isArray(recentCatalysts)) {
    const negCultural = recentCatalysts.filter(c =>
      (c.type === 'cultural_event' || c.type === 'ncaa_infraction') &&
      c.sentiment === 'negative' && c.confidence >= 7
    );
    if (negCultural.length > 0) {
      dims.cultural_health -= negCultural.length;
      reasons.cultural_health.push(`${negCultural.length} recent negative cultural catalyst(s) from corpus — ${negCultural.map(c => c.summary).slice(0, 2).join('; ')}`);
    }
  }
  for (const k of Object.keys(dims)) dims[k] = Math.max(1, Math.min(10, dims[k]));
  return { scores: dims, reasons, grid_version: 'v1_legacy_4d' };
}

// ════════════════════════════════════════════════════════════
// v0.29: 8-DIMENSION PROPRIETARY GRID — derived from PROGRAM_PROFILE
// Marquee programs get scored on:
//   1. Player Development     (NFL pipeline depth, Pro Bowlers, Heismans)
//   2. Championship Pedigree  (national + conference titles, era-weighted)
//   3. Coach Quality          (current coach record + lineage stability)
//   4. NIL Investment         (collective spend midpoint vs peers)
//   5. Facilities & Stadium   (capacity + atmosphere ranking + traditions)
//   6. Recruiting Power       (class rankings, blue-chip pipeline)
//   7. Academic & Compliance  (APR, infractions, retention)
//   8. Cultural Authenticity  (iconic moments, traditions, identity strength)
// ════════════════════════════════════════════════════════════
function scoreProgramFromProfile({ profile, apr, infractions, transferData, recentCatalysts }) {
  const dims = {
    player_development: 5,
    championship_pedigree: 5,
    coach_quality: 5,
    nil_investment: 5,
    facilities_stadium: 5,
    recruiting_power: 5,
    academic_compliance: 5,
    cultural_authenticity: 5
  };
  const reasons = {
    player_development: [],
    championship_pedigree: [],
    coach_quality: [],
    nil_investment: [],
    facilities_stadium: [],
    recruiting_power: [],
    academic_compliance: [],
    cultural_authenticity: []
  };

  // ─── 1. PLAYER DEVELOPMENT ──────────────────────────────────
  // Anchored on pro pipeline. Field names adapt per sport:
  //   football  → nfl_pipeline (total_drafted_all_time, current_nfl_roster_count_2024)
  //   basketball→ nba_pipeline (total_drafted_all_time, current_nba_roster_count, hall_of_famers)
  //   wbball    → wnba_pipeline
  //   baseball  → mlb_pipeline (total_drafted_all_time, current_mlb_roster_count)
  //   soccer    → mls_pipeline + national_team_pipeline
  //   tennis    → atp_wta_pipeline
  //   volleyball→ pro_pipeline (LOVB, Athletes Unlimited, national team)
  // Engine reads any of these via field aliasing — coverage across sports.
  const np = profile.nfl_pipeline || profile.nba_pipeline || profile.wnba_pipeline || profile.mlb_pipeline || profile.mls_pipeline || profile.atp_wta_pipeline || profile.pro_pipeline || {};
  const totalDrafted = np.total_drafted_all_time || np.total_pro_all_time || 0;
  const firstRounders = np.first_round_picks_all_time || np.top_picks_all_time || np.lottery_picks_all_time || 0;
  const currentPros = np.current_nfl_roster_count_2024 || np.current_nba_roster_count || np.current_wnba_roster_count || np.current_mlb_roster_count || np.current_mls_roster_count || np.current_pro_count || 0;
  const proBowlers = np.pro_bowlers_active || np.allstars_active || np.allnba_active || np.allmlb_active || 0;
  const hofs = np.hall_of_famers || 0;

  // Pro-pipeline scoring — calibrated to sport-realistic numbers
  // For football 350+ drafted = elite. For basketball where rosters are smaller, 100+ = elite.
  // We branch on sport to apply the right thresholds AND the right league names.
  const sport = profile.sport || 'football';
  const isFootball = sport === 'football';
  const isMHoops = sport === 'mens-basketball';
  const isWHoops = sport === 'womens-basketball';
  const isHoops = isMHoops || isWHoops;
  const isBaseball = sport === 'baseball';
  const isMSoccer = sport === 'mens-soccer';
  const isWSoccer = sport === 'womens-soccer';
  const isSoccer = isMSoccer || isWSoccer;
  const isTennis = sport === 'tennis';
  const isMVball = sport === 'mens-volleyball';
  const isWVball = sport === 'womens-volleyball';
  const isVball = isMVball || isWVball;

  // Sport-specific league name for reasoning text
  const leagueName =
    isFootball ? 'NFL' :
    isMHoops   ? 'NBA' :
    isWHoops   ? 'WNBA' :
    isBaseball ? 'MLB' :
    isMSoccer  ? 'MLS' :
    isWSoccer  ? 'NWSL' :
    isTennis   ? 'ATP/WTA tour' :
    isWVball   ? 'LOVB / Athletes Unlimited' :
    isMVball   ? 'pro / national team' :
    'pro';

  // Pick-terminology per sport (drafted vs pro alumni vs ranked tour player)
  const draftTerm = (isFootball || isHoops || isBaseball || isMSoccer) ? 'draftees' : 'pro alumni';
  const firstRoundTerm = isHoops ? 'lottery picks' : isFootball ? 'first-round picks' : isBaseball ? 'first-round picks' : 'top picks';

  let pdScore = 5;
  const pdReasons = [];

  if (isFootball) {
    if (totalDrafted >= 350) { pdScore += 3; pdReasons.push(`${totalDrafted} all-time NFL draftees — elite pipeline`); }
    else if (totalDrafted >= 250) { pdScore += 2; pdReasons.push(`${totalDrafted} all-time NFL draftees — top-tier pipeline`); }
    else if (totalDrafted >= 150) { pdScore += 1; pdReasons.push(`${totalDrafted} all-time NFL draftees — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} all-time NFL draftees`);
  } else if (isHoops) {
    if (totalDrafted >= 100) { pdScore += 3; pdReasons.push(`${totalDrafted} all-time ${leagueName} draftees — elite pipeline`); }
    else if (totalDrafted >= 60) { pdScore += 2; pdReasons.push(`${totalDrafted} all-time ${leagueName} draftees — top-tier pipeline`); }
    else if (totalDrafted >= 30) { pdScore += 1; pdReasons.push(`${totalDrafted} all-time ${leagueName} draftees — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} all-time ${leagueName} draftees`);
  } else if (isBaseball) {
    if (totalDrafted >= 200) { pdScore += 3; pdReasons.push(`${totalDrafted} all-time MLB draftees — elite pipeline`); }
    else if (totalDrafted >= 120) { pdScore += 2; pdReasons.push(`${totalDrafted} all-time MLB draftees — top-tier pipeline`); }
    else if (totalDrafted >= 60) { pdScore += 1; pdReasons.push(`${totalDrafted} all-time MLB draftees — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} all-time MLB draftees`);
  } else if (isMSoccer) {
    if (totalDrafted >= 60) { pdScore += 3; pdReasons.push(`${totalDrafted} MLS / national-team alumni — elite pipeline`); }
    else if (totalDrafted >= 30) { pdScore += 2; pdReasons.push(`${totalDrafted} MLS / national-team alumni — top-tier pipeline`); }
    else if (totalDrafted >= 15) { pdScore += 1; pdReasons.push(`${totalDrafted} MLS alumni — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} MLS / pro alumni`);
  } else if (isTennis) {
    if (totalDrafted >= 40) { pdScore += 3; pdReasons.push(`${totalDrafted} ATP/WTA tour pros — elite pipeline for college tennis`); }
    else if (totalDrafted >= 20) { pdScore += 2; pdReasons.push(`${totalDrafted} ATP/WTA tour pros — top-tier pipeline`); }
    else if (totalDrafted >= 10) { pdScore += 1; pdReasons.push(`${totalDrafted} ATP/WTA tour pros — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} ATP/WTA tour pros`);
  } else if (isWVball) {
    if (totalDrafted >= 40) { pdScore += 3; pdReasons.push(`${totalDrafted} LOVB / Athletes Unlimited / national-team alumni — elite pipeline`); }
    else if (totalDrafted >= 20) { pdScore += 2; pdReasons.push(`${totalDrafted} LOVB / Athletes Unlimited alumni — top-tier pipeline`); }
    else if (totalDrafted >= 10) { pdScore += 1; pdReasons.push(`${totalDrafted} LOVB / pro alumni — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} LOVB / pro alumni`);
  } else if (isMVball) {
    if (totalDrafted >= 40) { pdScore += 3; pdReasons.push(`${totalDrafted} pro & national-team alumni — elite pipeline for men's volleyball`); }
    else if (totalDrafted >= 20) { pdScore += 2; pdReasons.push(`${totalDrafted} pro & national-team alumni — top-tier pipeline`); }
    else if (totalDrafted >= 10) { pdScore += 1; pdReasons.push(`${totalDrafted} pro & national-team alumni — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} pro & national-team alumni`);
  } else {
    // Generic fallback (e.g. women's soccer if added later)
    if (totalDrafted >= 40) { pdScore += 3; pdReasons.push(`${totalDrafted} ${leagueName} alumni — elite pipeline`); }
    else if (totalDrafted >= 20) { pdScore += 2; pdReasons.push(`${totalDrafted} ${leagueName} alumni — top-tier pipeline`); }
    else if (totalDrafted >= 10) { pdScore += 1; pdReasons.push(`${totalDrafted} ${leagueName} alumni — strong pipeline`); }
    else if (totalDrafted > 0) pdReasons.push(`${totalDrafted} ${leagueName} alumni`);
  }

  // First-round / lottery / top-pick boost (sport-specific terminology)
  if (isFootball && firstRounders >= 60) { pdScore += 1; pdReasons.push(`${firstRounders} first-round NFL picks — elite blue-chip development`); }
  else if (isFootball && firstRounders >= 40) { pdScore += 1; pdReasons.push(`${firstRounders} first-round NFL picks — strong blue-chip development`); }
  else if (isHoops && firstRounders >= 20) { pdScore += 1; pdReasons.push(`${firstRounders} ${leagueName} lottery picks — elite blue-chip development`); }
  else if (isHoops && firstRounders >= 10) { pdScore += 1; pdReasons.push(`${firstRounders} ${leagueName} lottery picks — strong blue-chip development`); }
  else if (isBaseball && firstRounders >= 20) { pdScore += 1; pdReasons.push(`${firstRounders} first-round MLB picks — elite blue-chip development`); }
  else if (isBaseball && firstRounders >= 10) { pdScore += 1; pdReasons.push(`${firstRounders} first-round MLB picks — strong blue-chip development`); }
  else if (firstRounders >= 5) { pdScore += 1; pdReasons.push(`${firstRounders} top picks — strong blue-chip development`); }

  // Currently active in the league (sport-specific phrasing)
  if (isFootball && currentPros >= 50) { pdScore += 1; pdReasons.push(`${currentPros} active in the NFL today — sustained development engine`); }
  else if (isFootball && currentPros > 0) pdReasons.push(`${currentPros} active in the NFL today`);
  else if (isHoops && currentPros >= 15) { pdScore += 1; pdReasons.push(`${currentPros} active in the ${leagueName} today — sustained development engine`); }
  else if (isHoops && currentPros > 0) pdReasons.push(`${currentPros} active in the ${leagueName} today`);
  else if (isBaseball && currentPros >= 15) { pdScore += 1; pdReasons.push(`${currentPros} active in MLB today — sustained development engine`); }
  else if (isBaseball && currentPros > 0) pdReasons.push(`${currentPros} active in MLB today`);
  else if (isMSoccer && currentPros >= 15) { pdScore += 1; pdReasons.push(`${currentPros} active in MLS today — sustained development engine`); }
  else if (isMSoccer && currentPros > 0) pdReasons.push(`${currentPros} active in MLS today`);
  else if (isWVball && currentPros >= 10) { pdScore += 1; pdReasons.push(`${currentPros} active in LOVB / Athletes Unlimited today — sustained development engine`); }
  else if (isWVball && currentPros > 0) pdReasons.push(`${currentPros} active in LOVB / Athletes Unlimited today`);
  else if (currentPros >= 10) { pdScore += 1; pdReasons.push(`${currentPros} active pros today`); }
  else if (currentPros > 0) pdReasons.push(`${currentPros} active pros today`);

  if (proBowlers >= 5) {
    const allStarLabel = isFootball ? 'active Pro Bowlers / All-Pros' :
                         isHoops    ? `active ${leagueName} All-Stars` :
                         isBaseball ? 'active MLB All-Stars' :
                         'active All-Stars';
    pdScore += 1; pdReasons.push(`${proBowlers} ${allStarLabel} — top-tier outcomes`);
  }
  if (hofs >= 3) {
    const hofLabel = isFootball ? 'Pro Football Hall of Famers' :
                     isHoops    ? 'Naismith Hall of Famers' :
                     isBaseball ? 'MLB Hall of Famers' :
                     isTennis   ? 'Tennis Hall of Famers' :
                     isVball    ? 'Volleyball Hall of Famers' :
                     isSoccer   ? 'Soccer Hall of Famers' :
                     'Pro Hall of Famers';
    pdReasons.push(`${hofs} ${hofLabel} — generational alumni`);
  }
  if (np.ranking_note) pdReasons.push(np.ranking_note);
  dims.player_development = Math.max(1, Math.min(10, pdScore));
  reasons.player_development = pdReasons;

  // ─── 2. CHAMPIONSHIP PEDIGREE ───────────────────────────────
  const t = profile.tradition || {};
  const titles = t.national_titles || [];
  const titleCount = titles.length || t.national_titles_count || 0;
  const recentTitles = titles.filter(x => x.year >= 2000).length;
  const veryRecent = titles.filter(x => x.year >= 2015).length;
  const heismans = (t.heisman_winners || []).length;
  const woodenWinners = (t.wooden_award_winners || []).length;
  const playerOfYear = (t.player_of_year_winners || []).length;
  const finalFours = t.final_fours_count || 0;
  const collegeWorldSeries = t.college_world_series_appearances || 0;
  const confTitles = t.conference_titles_count || 0;

  let cpScore = 5;
  const cpReasons = [];
  if (titleCount >= 10) { cpScore += 3; cpReasons.push(`${titleCount} national titles — among the most decorated programs in college sports`); }
  else if (titleCount >= 5) { cpScore += 2; cpReasons.push(`${titleCount} national titles — championship pedigree confirmed`); }
  else if (titleCount >= 2) { cpScore += 1; cpReasons.push(`${titleCount} national titles`); }
  else if (titleCount === 1) cpReasons.push(`1 national title (${titles[0]?.year || ''})`);
  if (veryRecent >= 1) { cpScore += 2; cpReasons.push(`${veryRecent} title(s) in the last decade — current championship contender`); }
  else if (recentTitles >= 1) { cpScore += 1; cpReasons.push(`${recentTitles} modern-era (2000+) title(s) — credibility in current playoff era`); }

  // Sport-specific signal boosts
  if (heismans >= 4) { cpScore += 1; cpReasons.push(`${heismans} Heisman winners — consistent national-level individual excellence`); }
  else if (heismans >= 1) cpReasons.push(`${heismans} Heisman winner${heismans === 1 ? '' : 's'}`);
  if (woodenWinners >= 3) { cpScore += 1; cpReasons.push(`${woodenWinners} Wooden Award winners — best-player-in-college-basketball recognition`); }
  else if (woodenWinners >= 1) cpReasons.push(`${woodenWinners} Wooden Award winner${woodenWinners === 1 ? '' : 's'}`);
  if (playerOfYear >= 5) { cpScore += 1; cpReasons.push(`${playerOfYear} National Player of the Year recipients`); }
  if (finalFours >= 15) { cpScore += 1; cpReasons.push(`${finalFours} NCAA Final Fours — elite tournament pedigree`); }
  else if (finalFours >= 8) cpReasons.push(`${finalFours} NCAA Final Fours`);
  if (collegeWorldSeries >= 15) { cpScore += 1; cpReasons.push(`${collegeWorldSeries} College World Series appearances`); }
  else if (collegeWorldSeries >= 8) cpReasons.push(`${collegeWorldSeries} College World Series appearances`);
  if (confTitles >= 10) cpReasons.push(`${confTitles} conference titles`);
  dims.championship_pedigree = Math.max(1, Math.min(10, cpScore));
  reasons.championship_pedigree = cpReasons;

  // ─── 3. COACH QUALITY ───────────────────────────────────────
  const coaches = profile.coach_lineage || [];
  const current = coaches.find(c => c.current);
  let cqScore = 5;
  const cqReasons = [];
  if (current) {
    cqScore += 1;
    cqReasons.push(`Current head coach: ${current.name}`);
    if (current.championships && current.championships >= 1) {
      cqScore += 2;
      cqReasons.push(`Current coach has ${current.championships} national title${current.championships === 1 ? '' : 's'} at this program`);
    }
    if (current.notes) cqReasons.push(current.notes);
  }
  // Lineage strength — multiple legendary coaches in history
  const legendaryCoaches = coaches.filter(c => c.championships && c.championships >= 1).length;
  if (legendaryCoaches >= 4) { cqScore += 2; cqReasons.push(`${legendaryCoaches} championship-winning head coaches in program history — coaching tree pedigree`); }
  else if (legendaryCoaches >= 2) { cqScore += 1; cqReasons.push(`${legendaryCoaches} championship-winning coaches in program history`); }
  // SR-coach signal if available
  if (current && current.years && /present/i.test(current.years)) {
    cqScore += 1;
    cqReasons.push('Current coach actively in seat — leadership continuity');
  }
  dims.coach_quality = Math.max(1, Math.min(10, cqScore));
  reasons.coach_quality = cqReasons;

  // ─── 4. NIL INVESTMENT ──────────────────────────────────────
  const nil = profile.nil || {};
  const nilMid = ((nil.annual_spend_estimate_low || 0) + (nil.annual_spend_estimate_high || 0)) / 2;
  let niScore = 5;
  const niReasons = [];
  if (nilMid >= 15000000) { niScore += 4; niReasons.push(`$${(nilMid/1000000).toFixed(0)}M+ annual collective spend midpoint — top-3 nationally`); }
  else if (nilMid >= 10000000) { niScore += 3; niReasons.push(`$${(nilMid/1000000).toFixed(0)}M annual collective spend midpoint — top-10 nationally`); }
  else if (nilMid >= 5000000) { niScore += 2; niReasons.push(`$${(nilMid/1000000).toFixed(0)}M annual collective spend midpoint — credible NIL investment`); }
  else if (nilMid > 0) { niScore += 1; niReasons.push(`$${(nilMid/1000000).toFixed(1)}M annual collective spend estimate`); }
  if (nil.collective_name) niReasons.push(`Collective: ${nil.collective_name}`);
  if (nil.peer_rank_note) niReasons.push(nil.peer_rank_note);
  dims.nil_investment = Math.max(1, Math.min(10, niScore));
  reasons.nil_investment = niReasons;

  // ─── 5. FACILITIES & STADIUM ────────────────────────────────
  const stadium = profile.stadium || {};
  let fsScore = 5;
  const fsReasons = [];
  if (stadium.capacity >= 100000) { fsScore += 3; fsReasons.push(`${stadium.capacity.toLocaleString()} capacity — among largest stadiums in college sports`); }
  else if (stadium.capacity >= 80000) { fsScore += 2; fsReasons.push(`${stadium.capacity.toLocaleString()} capacity — major-program scale`); }
  else if (stadium.capacity >= 50000) { fsScore += 1; fsReasons.push(`${stadium.capacity.toLocaleString()} capacity`); }
  if (stadium.atmosphere_quote) { fsScore += 1; fsReasons.push(`Atmosphere: "${(stadium.atmosphere_quote.text || '').slice(0, 100)}${(stadium.atmosphere_quote.text || '').length > 100 ? '…' : ''}" — ${stadium.atmosphere_quote.attribution}`); }
  if (stadium.ranking_note) { fsScore += 1; fsReasons.push(stadium.ranking_note); }
  if (stadium.iconic_traditions && stadium.iconic_traditions.length >= 3) fsReasons.push(`${stadium.iconic_traditions.length} iconic gameday traditions`);
  if (stadium.nickname) fsReasons.push(`Known as "${stadium.nickname}"`);
  dims.facilities_stadium = Math.max(1, Math.min(10, fsScore));
  reasons.facilities_stadium = fsReasons;

  // ─── 6. RECRUITING POWER ────────────────────────────────────
  // Inferred from championship + NFL pipeline + NIL — programs that produce these
  // outcomes also recruit at the level required to produce them.
  let rpScore = 5;
  const rpReasons = [];
  if (totalDrafted >= 250 && nilMid >= 10000000) { rpScore += 3; rpReasons.push('Pipeline + NIL combined indicate elite recruiting class infrastructure'); }
  else if (totalDrafted >= 150 || nilMid >= 8000000) { rpScore += 2; rpReasons.push('Pipeline OR NIL signals strong recruiting infrastructure'); }
  else if (totalDrafted >= 80) { rpScore += 1; rpReasons.push('Track record of producing professional players signals competitive recruiting'); }
  if (recentTitles >= 1) { rpScore += 1; rpReasons.push('Recent title history attracts blue-chip recruits'); }
  if (profile.tradition && profile.tradition.conference) rpReasons.push(`Conference: ${profile.tradition.conference} — recruiting territory advantage`);
  // Honest caveat: we don't have live class rankings yet
  rpReasons.push('Honest scope: live class rankings (247/On3) not yet integrated; score is inferred from outcomes.');
  dims.recruiting_power = Math.max(1, Math.min(10, rpScore));
  reasons.recruiting_power = rpReasons;

  // ─── 7. ACADEMIC & COMPLIANCE ───────────────────────────────
  let acScore = 6; // marquee D1 baseline above 5 (these programs maintain APR or they wouldn't be marquee)
  const acReasons = [];
  if (apr && apr.data_present && apr.four_year_avg >= 985) { acScore += 2; acReasons.push(`NCAA APR 4-yr avg ${apr.four_year_avg} — top-quartile`); }
  else if (apr && apr.data_present && apr.four_year_avg >= 970) { acScore += 1; acReasons.push(`NCAA APR 4-yr avg ${apr.four_year_avg} — above median`); }
  else if (apr && apr.data_present && apr.four_year_avg < 950) { acScore -= 3; acReasons.push(`NCAA APR 4-yr avg ${apr.four_year_avg} — eligibility risk`); }
  else acReasons.push('Live NCAA APR data not retrieved this run; baseline applied for marquee D1 program.');

  if (infractions && Array.isArray(infractions.cases)) {
    const recent = infractions.cases.filter(c => c.year >= new Date().getFullYear() - 5);
    const level1 = recent.filter(c => c.type && c.type.includes('Level I'));
    if (level1.length > 0) { acScore -= 4; acReasons.push(`${level1.length} Level I NCAA infraction(s) in last 5 years`); }
    else if (recent.length === 0) { acScore += 1; acReasons.push('No NCAA infractions in last 5 years'); }
  }
  if (transferData && transferData.data && transferData.data.retention_pct >= 80) {
    acScore += 1; acReasons.push(`Retention ${transferData.data.retention_pct}% — above-median retention`);
  }
  dims.academic_compliance = Math.max(1, Math.min(10, acScore));
  reasons.academic_compliance = acReasons;

  // ─── 8. CULTURAL AUTHENTICITY ───────────────────────────────
  const c = profile.culture || {};
  const moments = profile.iconic_moments || [];
  const traditions = (stadium.iconic_traditions || []).length;
  let caScore = 5;
  const caReasons = [];
  if (c.identity_quote) { caScore += 1; caReasons.push(`Identity: "${c.identity_quote}"${c.identity_attribution ? ' — ' + c.identity_attribution : ''}`); }
  if (c.signature) caReasons.push(c.signature);
  if (moments.length >= 4) { caScore += 2; caReasons.push(`${moments.length} iconic program moments documented — deep cultural archive`); }
  else if (moments.length >= 2) { caScore += 1; caReasons.push(`${moments.length} iconic program moments documented`); }
  if (traditions >= 3) { caScore += 1; caReasons.push(`${traditions} active gameday traditions`); }
  if (t.founded && (2026 - t.founded) >= 100) { caScore += 1; caReasons.push(`${2026 - t.founded} years of program history (founded ${t.founded})`); }
  if (Array.isArray(recentCatalysts)) {
    const negCultural = recentCatalysts.filter(c => c.sentiment === 'negative' && c.confidence >= 7);
    if (negCultural.length > 0) { caScore -= negCultural.length; caReasons.push(`${negCultural.length} recent negative cultural catalysts from monitoring corpus`); }
  }
  dims.cultural_authenticity = Math.max(1, Math.min(10, caScore));
  reasons.cultural_authenticity = caReasons;

  return { scores: dims, reasons, grid_version: 'v2_proprietary_8d' };
}

// ─── VERDICT MAPPING ─────────────────────────────────────────
// Verdicts now include INSUFFICIENT_DATA when foundation tier is too thin.
// This is the integrity move — refuse to fake confidence we don't have.
function playerVerdict(scores, foundation, sourceResults) {
  // v0.5.1 — verdict logic differentiates "thin data" from "actual integrity flag"
  // WALK_AWAY should fire on EVIDENCE of problems, not absence of evidence.
  // INSUFFICIENT_DATA fires when we genuinely don't have enough to score.
  if (foundation && foundation.tier === 'insufficient') return 'INSUFFICIENT_DATA';

  // If we have a confirmed roster but thin career stats, that's VERIFY_FURTHER, not WALK_AWAY.
  // Confirmed roster = the athlete exists, plays varsity at the named school. Real foundation.
  // Missing career stats ≠ red flag; it just means SR adapter or sport's coverage is thin.
  const rosterConfirmed = sourceResults && sourceResults.school_roster && sourceResults.school_roster.roster_confirmed;
  const hasIntegrityFlag = sourceResults && (
    (sourceResults.ncaa_infractions && sourceResults.ncaa_infractions.cases && sourceResults.ncaa_infractions.cases.length > 0) ||
    (sourceResults.transfer && sourceResults.transfer.events && sourceResults.transfer.events.length >= 3)
  );

  const avg = (scores.trajectory + scores.coachability + scores.stability + scores.verification) / 4;
  const min = Math.min(scores.trajectory, scores.coachability, scores.stability, scores.verification);

  // Only fire WALK_AWAY on actual integrity flag — not on thin verification scores
  if (hasIntegrityFlag) return 'WALK_AWAY';
  if (min <= 2) return 'WALK_AWAY';

  if (avg >= 7.5 && min >= 6) return 'EDGE_DETECTED';
  if (avg >= 6 && min >= 5) return 'REASONABLE_ADD';
  // Roster confirmed but thin stats → VERIFY_FURTHER (the right verdict for "you need more data")
  return 'VERIFY_FURTHER';
}
function programVerdict(scores, foundation, sourceResults, gridVersion) {
  // v0.29: 8-dim path — marquee programs with rich profiles never show INSUFFICIENT_DATA
  if (gridVersion === 'v2_proprietary_8d') {
    const dimKeys = Object.keys(scores);
    const avg = dimKeys.reduce((s, k) => s + scores[k], 0) / dimKeys.length;
    const min = Math.min(...dimKeys.map(k => scores[k]));
    // Integrity flags
    const hasIntegrityFlag = sourceResults && sourceResults.ncaa_infractions && Array.isArray(sourceResults.ncaa_infractions.cases) && sourceResults.ncaa_infractions.cases.some(c => c.type && c.type.includes('Level I'));
    if (hasIntegrityFlag && scores.academic_compliance <= 4) return 'WALK_AWAY';
    if (min <= 2) return 'WALK_AWAY';
    if (avg >= 8.5 && min >= 7) return 'ELITE_PROGRAM';
    if (avg >= 7.5 && min >= 6) return 'EDGE_DETECTED';
    if (avg >= 6.5 && min >= 5) return 'REASONABLE_CHOICE';
    return 'WORTH_A_LOOK';
  }
  // Legacy 4-dim path
  if (foundation && foundation.tier === 'insufficient') return 'INSUFFICIENT_DATA';
  const hasIntegrityFlag = sourceResults && (
    (sourceResults.ncaa_infractions && sourceResults.ncaa_infractions.cases && sourceResults.ncaa_infractions.cases.length > 0)
  );
  const avg = (scores.development + scores.retention + scores.cultural_health + scores.promise_delivery) / 4;
  const min = Math.min(scores.development, scores.retention, scores.cultural_health, scores.promise_delivery);
  if (hasIntegrityFlag && scores.cultural_health <= 4) return 'WALK_AWAY';
  if (min <= 2) return 'WALK_AWAY';
  if (avg >= 7.5 && min >= 6) return 'EDGE_DETECTED';
  if (avg >= 6 && min >= 5) return 'REASONABLE_CHOICE';
  return 'WORTH_A_LOOK';
}

// ─── PLAYER VERDICT HANDLER (v0.3 — name-based) ─────────────
async function handlePlayerVerdict(env, body) {
  // v0.3 supports both name-based (preferred) and slug-based (legacy) input.
  // Name-based: { name: "Cooper Flagg", sport: "mens-basketball", schoolHint: "Duke" }
  // Slug-based: { playerSlug: "cooper-flagg-1", sport: "mens-basketball" }
  // v0.15: timing instrumentation. Every phase records its wall-clock duration.
  // The response includes a `timing` object so we can find the actual bottleneck.
  const t0 = Date.now();
  const timing = {};
  const { name, playerSlug, sport: rawSport, schoolHint, profileUrls } = body;
  const sport = rawSport === 'basketball' ? 'mens-basketball' : (rawSport || 'mens-basketball');
  if (!name && !playerSlug) return { error: 'name or playerSlug required', status: 400 };
  if (!SPORTS[sport]) return { error: 'unknown_sport', sport, supported: Object.keys(SPORTS), status: 400 };

  const cfg = SPORTS[sport];

  // 1. Resolve the name to candidate matches across sources
  let resolution;
  if (name) {
    resolution = await resolvePlayerName(env, { name, sport, schoolHint, profileUrls });
  } else {
    // Legacy slug path
    const sr = await fetchSportsRefPlayer(playerSlug, sport);
    resolution = {
      status: sr && !sr.error && sr.name ? 'resolved' : 'insufficient_data',
      name: playerSlug,
      sport,
      candidates: [],
      source_results: { sports_reference: sr }
    };
  }

  // 2. Pull additional sources based on what resolved + sport
  const sourceResults = { ...resolution.source_results };

  // For tennis specifically, ensure we hit ITA + UTR + roster
  if (sport === 'tennis' && !sourceResults.ita) {
    sourceResults.ita = await fetchITAPlayer(name);
  }
  if (sport === 'tennis' && profileUrls && profileUrls.utr && !sourceResults.utr) {
    sourceResults.utr = await fetchUTRProfile(profileUrls.utr);
  }
  if (schoolHint && !sourceResults.school_roster) {
    sourceResults.school_roster = await fetchSchoolRoster(name, schoolHint, sport);
  }
  // NIL is universal
  if (!sourceResults.nil) {
    sourceResults.nil = await fetchNILDeals(name);
  }

  // 3. Assess foundation — do we have enough to score honestly?
  const foundation = assessDataFoundation(sourceResults);

  // 4. Score
  const sportsRef = sourceResults.sports_reference;
  const composite247 = sourceResults.composite_247;
  const { scores, reasons } = scorePlayer({ sportsRef, composite247, transferEvents: null, nilDeals: sourceResults.nil, sport });

  // 5. Trajectory Delta — Edge Engine 1
  let trajectoryDelta = null;
  if (sportsRef && sportsRef.career_stats) {
    const incomingRank = composite247 && composite247.composite_rank;
    const careerYears = (sportsRef.seasons && sportsRef.seasons.length) || null;
    trajectoryDelta = computeTrajectoryDelta({
      sport, incomingRank, careerStats: sportsRef.career_stats, careerYears
    });
  }

  // 6. Tennis-specific score override using UTR if present
  if (sport === 'tennis' && sourceResults.utr && sourceResults.utr.utr) {
    const utr = sourceResults.utr.utr;
    if (utr >= cfg.trajectory_thresholds.primary_high) {
      scores.trajectory = Math.min(10, 8 + Math.floor((utr - cfg.trajectory_thresholds.primary_high) / 2));
      reasons.trajectory.push(`UTR ${utr.toFixed(2)} — at or above elite-college threshold (${cfg.trajectory_thresholds.primary_high}).`);
    } else if (utr >= cfg.trajectory_thresholds.primary_starter) {
      scores.trajectory = 6;
      reasons.trajectory.push(`UTR ${utr.toFixed(2)} — solid D1 starter range.`);
    } else if (utr >= cfg.trajectory_thresholds.primary_role) {
      scores.trajectory = 4;
      reasons.trajectory.push(`UTR ${utr.toFixed(2)} — entry-level D1 range.`);
    }
    scores.verification = sourceResults.utr.utr ? 8 : scores.verification;
    if (sourceResults.school_roster && sourceResults.school_roster.roster_confirmed) {
      reasons.verification.push(`Roster confirmed at ${schoolHint} (${sourceResults.school_roster.source_url}).`);
    }
  }

  // 7. Determine verdict (honest unknowns first)
  const verdict = playerVerdict(scores, foundation, sourceResults);

  // 8a-8b. v0.13 PARALLEL FAN-OUT — all independent fetches run together.
  // News catalysts, Wikipedia, open web, school coaching staff, YouTube highlights
  // all kick off at the same time. Saves 3-5s vs. the previous sequential approach.
  // v0.15: each fetch wrapped with individual timing so we know which one is slowest.
  const sportLabelForFetch = cfg.label || sport;
  const tFanout = Date.now();
  const phaseTimings = {};
  const timed = (key, p) => {
    const start = Date.now();
    return p.then(r => { phaseTimings[key] = Date.now() - start; return r; })
            .catch(e => { phaseTimings[key] = Date.now() - start; throw e; });
  };
  const [recentNewsMentions, wikipedia, openWeb, coachingStaff, videos] = await Promise.all([
    timed('news_catalysts_ms', findRecentNewsMentions(env, name || playerSlug)).catch(() => []),
    timed('wikipedia_ms', fetchWikipediaPlayer(name || playerSlug, schoolHint || null, sport)).catch(e => ({ source: 'wikipedia', error: 'fetch_failed', detail: String(e).slice(0, 100) })),
    timed('open_web_ms', fetchOpenWebForPlayer(name || playerSlug, schoolHint || null, sport, 4)).catch(e => ({ source: 'open_web', error: 'fetch_failed', detail: String(e).slice(0, 100) })),
    timed('coaching_staff_ms', schoolHint ? fetchSchoolCoachingStaff(schoolHint, sport) : Promise.resolve({ source: 'school_coaching_staff', error: 'no_school' })).catch(() => ({ source: 'school_coaching_staff', error: 'fetch_failed' })),
    timed('youtube_ms', fetchYouTubeHighlights(name || playerSlug, schoolHint || null, sport, 3)).catch(() => [])
  ]);
  Object.assign(timing, phaseTimings);
  timing.fanout_total_ms = Date.now() - tFanout;

  // v0.24: merge player-uploaded videos (from /social/video) into the videos list.
  // User-uploaded videos take priority — they're THEIR footage, not whatever YouTube serves.
  let mergedVideos = Array.isArray(videos) ? videos : [];
  try {
    const tUserVideos = Date.now();
    const uploadedRows = await dbAll(env,
      "SELECT id, source, url, title, season, created_at FROM player_videos WHERE LOWER(player_name) = LOWER(?) AND visibility = 'public' ORDER BY created_at DESC LIMIT 6",
      [name || playerSlug]
    );
    const uploaded = (uploadedRows || []).map(v => ({
      url: v.url,
      title: v.title || ((v.source || 'Player').toUpperCase() + ' highlight' + (v.season ? ' · ' + v.season : '')),
      source: v.source || 'player_upload',
      thumbnail: null,
      uploaded_by_player: true,
      season: v.season,
      uploaded_at: v.created_at
    }));
    timing.player_videos_ms = Date.now() - tUserVideos;
    timing.player_videos_count = uploaded.length;
    // Player-uploaded first, then YouTube auto-fetch
    mergedVideos = [...uploaded, ...mergedVideos];
  } catch (e) {
    timing.player_videos_error = String(e).slice(0, 100);
  }

  // 8c. v0.8 PASS 1: extract structured facts from ALL sources via Claude
  const tFacts = Date.now();
  const facts = await extractPlayerFacts(env, {
    playerName: name || playerSlug,
    schoolHint: schoolHint || null,
    sportLabel: sportLabelForFetch,
    sport: sport,
    wikipedia, openWeb,
    schoolRoster: sourceResults.school_roster,
    sportsRef: sourceResults.sports_reference,
    composite247: composite247 || sourceResults.composite_247,
    recentNewsMentions
  });
  timing.facts_claude_ms = Date.now() - tFacts;

  // 8d + 8e. PARALLEL — eval grid + take. Take used to depend on grid;
  // now it runs in parallel and works without grid context (gracefully). Saves
  // ~10-15s of wall-clock per verdict.
  // v0.15: instrument both Claude calls separately to see which is slower.
  const tGridTake = Date.now();
  const claudeTimings = {};
  const timedC = (key, p) => {
    const s = Date.now();
    return p.then(r => { claudeTimings[key] = Date.now() - s; return r; })
            .catch(e => { claudeTimings[key] = Date.now() - s; throw e; });
  };
  const [evalGrid, take] = await Promise.all([
    timedC('grid_claude_ms', generateCoachEvalGrid(env, {
      playerName: name || playerSlug,
      sport, sportLabel: sportLabelForFetch,
      facts,
      fallbackPosition: sourceResults.school_roster?.bio?.position || null
    })),
    timedC('take_claude_ms', generateTakeOnly(env, {
      playerName: name || playerSlug,
      schoolHint: schoolHint || null,
      sport, sportLabel: sportLabelForFetch,
      verdict, foundation,
      facts, coachingStaff, recentNewsMentions,
      evalGrid: null
    }))
  ]);
  Object.assign(timing, claudeTimings);
  timing.grid_take_total_ms = Date.now() - tGridTake;

  // Legacy narrative stub for DB compat.
  const narrative = '[v0.13: Legacy narrative replaced by encyclopedia.take.]';

  // 8g. Build encyclopedia object — what the new UI renders
  // Aggregate photos with a per-URL HEAD test rather than a static domain allowlist.
  // The static list was too narrow (dropped legit on3/kwtx/tigerrag photos).
  // HEAD-test approach: try each URL with a browser UA; keep those that 200 with
  // an image content-type. Hotlinking-blocked CDNs like ESPN return 403/404.
  const photoCandidates = [];
  const seenPhotoUrls = new Set();
  const addCandidate = (p) => {
    if (!p || !p.url) return;
    const norm = p.url.replace(/^https?:/, '').split('?')[0];
    if (seenPhotoUrls.has(norm)) return;
    seenPhotoUrls.add(norm);
    photoCandidates.push(p);
  };

  // v0.30.5.171: Photo cache lookup. If a previous verdict found a photo for this
  // slug, surface it instantly. Cache key: photo-cache:{playerSlug}. 30-day TTL
  // since photos rotate slowly. Best-effort — KV failure falls back cleanly.
  if (env && env.FIELDCHECK_KV && playerSlug) {
    try {
      const cached = await env.FIELDCHECK_KV.get('photo-cache:' + playerSlug);
      if (cached) {
        const parsed = JSON.parse(cached);
        if (parsed && parsed.url) {
          addCandidate({ url: parsed.url, source: (parsed.source || 'cached') + ' (cached)', page_url: parsed.page_url || null });
        }
      }
    } catch (_) { /* cache miss is silent */ }
  }

  if (sourceResults.school_roster?.bio?.photo_url) {
    const rosterUrl = sourceResults.school_roster.bio.photo_url;
    addCandidate({ url: rosterUrl, source: sourceResults.school_roster.school + ' Athletics', page_url: sourceResults.school_roster.source_url });
    // v0.30.5.171: cache the successful roster scrape for future verdicts.
    if (env && env.FIELDCHECK_KV && playerSlug) {
      try {
        await env.FIELDCHECK_KV.put('photo-cache:' + playerSlug, JSON.stringify({
          url: rosterUrl,
          source: sourceResults.school_roster.school + ' Athletics',
          page_url: sourceResults.school_roster.source_url,
          cached_at: new Date().toISOString()
        }), { expirationTtl: 60 * 60 * 24 * 30 });
      } catch (_) { /* best-effort */ }
    }
  }
  if (wikipedia && !wikipedia.error && wikipedia.thumbnail) {
    // v0.30.5.1: STRICT match before adding Wikipedia photo. The Wikipedia search
    // sometimes returns the wrong person (e.g. "Beres Reilly" male wrestler for
    // "Bergen Reilly" female setter, "Andre Jackson Jr" for "Andi Jackson"). If
    // the Wikipedia title's last name doesn't match the player's last name, the
    // thumbnail is the wrong person — do NOT add it.
    const wikiTitle = String(wikipedia.title || '').replace(/\s*\((?:volleyball|basketball|football|baseball|soccer|tennis|player|coach|athlete|disambiguation|born[^)]*)[^)]*\)\s*/ig, '').trim();
    const playerName = String(name || playerSlug || '').trim();
    const playerParts = playerName.toLowerCase().split(/\s+/).filter(Boolean);
    const playerLast = playerParts[playerParts.length - 1] || '';
    const playerFirst = playerParts[0] || '';
    const titleParts = wikiTitle.toLowerCase().replace(/[.,]/g, '').split(/\s+/).filter(Boolean);
    const titleLast = titleParts[titleParts.length - 1] || '';
    const titleFirst = titleParts[0] || '';
    const lastMatches = playerLast && titleLast && playerLast === titleLast;
    const firstMatches = playerFirst && titleFirst && playerFirst === titleFirst;
    const fullContains = playerName && wikiTitle.toLowerCase().includes(playerName.toLowerCase());
    const isValidWikipediaMatch = (lastMatches && firstMatches) || fullContains;
    if (isValidWikipediaMatch) {
      addCandidate({ url: wikipedia.thumbnail, source: 'Wikipedia', page_url: wikipedia.source_url });
    }
    // else: silently drop — wrong person. The frontend Sources Cited section
    // will still show the link with a "(verify — title doesn't match)" warning.
  }
  if (openWeb && Array.isArray(openWeb.images)) {
    for (const img of openWeb.images) addCandidate(img);
  }

  // v0.18: drop the blocking HEAD test. The trust filter below is the gate.
  // Frontend already has onerror handlers that hide broken photos silently —
  // the HEAD test was costing 1.5-3s per verdict for negligible quality gain.
  const TRUSTED_PHOTO_HOSTS = [
    'upload.wikimedia.org', 'commons.wikimedia.org',
    'i.ytimg.com', 'img.youtube.com',
    'sidearmsports.com', 'sidearmstatic.com',
    'huskers.com', 'lsusports.net', 'texassports.com',
    'goduke.com', 'gostanford.com', 'wsucougars.com',
    'pittsburghpanthers.com', 'fightingillini.com',
    'gobearcats.com', 'osubeavers.com'
  ];
  const isTrustedPhoto = (url) => {
    try {
      const host = new URL(url).hostname.toLowerCase();
      return TRUSTED_PHOTO_HOSTS.some(t => host.endsWith(t));
    } catch { return false; }
  };

  const tPhotos = Date.now();
  // Keep trusted-host photos always; for non-trusted, skip them rather than HEAD-test.
  // Open-web image candidates from random CDNs were the failure source anyway.
  const photos = photoCandidates.filter(p => isTrustedPhoto(p.url));
  timing.photo_head_test_ms = Date.now() - tPhotos;
  timing.photo_candidates = photoCandidates.length;
  timing.photos_kept = photos.length;

  // videos already fetched in the parallel wave above (8a-8b). Just use the const.

  // v0.22: Multi-sport pro pathway resolver (was volleyball-only in v0.16-v0.21).
  // Routes to sport-specific resolver; same shape across sports.
  // Field name kept as lovb_pathway for backward compat with UI render code +
  // existing cached encyclopedia objects. Contents now sport-aware.
  const lovbPathway = resolveProPathway(sport, name || playerSlug, schoolHint, evalGrid, facts);

  // v0.22: NIL estimate — derived from school + position + eval grid + pathway
  // v0.25: Calibrated against real NIL deal corpus when available (KV-cached calibration)
  const nilEstimate = await computeNILEstimateCalibrated(env, {
    sport,
    school: schoolHint || sourceResults.school_roster?.school || null,
    position: facts?.position_specific?.position || sourceResults.school_roster?.bio?.position || null,
    evalGrid,
    lovbPathway,
    facts
  });

  const encyclopedia = {
    facts: facts && facts.facts_available !== false ? facts : null,
    eval_grid: evalGrid && evalGrid.grid_available ? evalGrid : null,
    take: take && !take.error ? take : null,
    lovb_pathway: lovbPathway,
    nil_estimate: nilEstimate && !nilEstimate.error ? nilEstimate : null,
    photos,
    videos: mergedVideos,
    coaching_staff_source_url: coachingStaff?.source_url || null,
    sources_consulted: {
      wikipedia: wikipedia?.error ? null : { url: wikipedia?.source_url, title: wikipedia?.title },
      open_web: openWeb?.excerpts ? openWeb.excerpts.map(e => ({ url: e.url, title: e.title })) : [],
      school_roster: sourceResults.school_roster?.source_url || null,
      coaching_staff: coachingStaff?.source_url || null,
      sports_reference: sourceResults.sports_reference?.source_url || null
    }
  };

  // 9. Persist
  const id = 'pv_' + Date.now() + '_' + Math.random().toString(36).slice(2, 9);
  try {
    await dbExec(env,
      'INSERT INTO player_verdicts (id, slug, sport, verdict, scores_json, reasons_json, sources_json, narrative, created_at) VALUES (?,?,?,?,?,?,?,?,?)',
      [id, name || playerSlug, sport, verdict, JSON.stringify(scores), JSON.stringify(reasons),
       JSON.stringify(sourceResults), narrative, Date.now()]
    );
  } catch (e) { /* migration may be pending */ }

  timing.total_ms = Date.now() - t0;

  let result = {
    ok: true, id, track: 'player',
    name: name || playerSlug, sport, sport_label: cfg.label,
    verdict, scores, reasons, narrative,
    encyclopedia,
    recent_news_mentions: recentNewsMentions,
    foundation, resolution_status: resolution.status, candidates: resolution.candidates,
    trajectory_delta: trajectoryDelta,
    sources: sourceResults,
    timing,  // v0.15: phase-by-phase wall-clock breakdown
    methodology_url: 'https://fieldcheck.ai/methodology',
    generated_at: new Date().toISOString()
  };

  // v0.30.5.30: CURATED PLAYER PROFILE MERGE — the moat
  // If the player matches a hand-built profile in PLAYER_PROFILES, merge the curated
  // data into the verdict response. Curated wins for hard data (measurables, awards),
  // overrides eval grid scores, appends sources, and bumps the verdict tier when
  // appropriate. Eliminates "?/10" dead-ends for known marquee players.
  try {
    const curated = getPlayerProfile(name || playerSlug, schoolHint || '', sport);
    if (curated) {
      result = mergeCuratedPlayerProfile(result, curated);
    }
  } catch (e) {
    // Curated merge failure is non-fatal — fall through with LLM-only data
    console.error('curated_merge_error:', e?.message || String(e));
  }

  return result;
}

// ─── PROGRAM VERDICT HANDLER ─────────────────────────────────
async function handleProgramVerdict(env, body) {
  // v0.3: name-based program input + sport-aware + culture extraction
  // Name-based: { name: "Duke Blue Devils" } or { name: "San Jose State", sport: "tennis" }
  // Slug-based: { programSlug: "duke-blue-devils", sport: "mens-basketball" }
  const { name, programSlug, sport: rawSport, coachName, publicQuotes } = body;
  const sport = rawSport === 'basketball' ? 'mens-basketball' : (rawSport || 'mens-basketball');
  if (!name && !programSlug) return { error: 'name or programSlug required', status: 400 };
  if (!SPORTS[sport]) return { error: 'unknown_sport', sport, supported: Object.keys(SPORTS), status: 400 };

  // Resolve to a slug for our hardcoded ratings/data lookup
  const slug = programSlug || nameToSlug(name);

  const [apr, infractions, transferData] = await Promise.all([
    fetchNCAAAPR(slug),
    fetchNCAAInfractions(slug),
    fetchTransferPortal(slug)
  ]);

  let recentCatalysts = [];
  try {
    const rows = await dbAll(env,
      'SELECT type, sentiment, summary, confidence, captured_at FROM sport_catalysts ' +
      'WHERE expires_at > ? AND (entities_json LIKE ? OR affects_for_json LIKE ?) ORDER BY captured_at DESC LIMIT 10',
      [new Date().toISOString(), '%' + slug + '%', '%' + slug + '%']
    );
    recentCatalysts = rows || [];
  } catch (e) {}

  // v0.28: Look up rich program profile (LSU-level deep data for marquee programs)
  const profile = getProgramProfile(name || slug, sport);
  const indices = profile ? computeProgramIndices(profile) : null;

  const sourceResults = {
    ncaa_apr: apr,
    ncaa_infractions: infractions,
    transfer_portal: transferData,
    ...(profile ? { marquee_profile: { slug: profile.slug, title_count: (profile.tradition?.national_titles?.length || 0) } } : {})
  };
  const foundation = assessDataFoundation(sourceResults);

  // v0.29: 8-dim scoring derives from profile when present; falls back to legacy 4-dim
  const { scores, reasons, grid_version } = scoreProgram({ apr, infractions, transferData, sportsRefCoach: null, recentCatalysts, profile });

  // Coach Culture Extraction — Edge Engine 3
  let cultureProfile = null;
  if (coachName && publicQuotes && publicQuotes.length > 0) {
    cultureProfile = await extractCoachCulture(env, {
      coachName, programName: name || slug, publicQuotes,
      rosterOutcomes: transferData && transferData.data
        ? `Retention: ${transferData.data.retention_pct}%; Out: ${transferData.data.out_count}; In: ${transferData.data.in_count}.`
        : null
    });
    if (cultureProfile && cultureProfile.culture_score) {
      // Culture extraction overlays cultural_health and promise_delivery
      const blend = (scores.cultural_health + cultureProfile.culture_score) / 2;
      scores.cultural_health = Math.round(blend);
      reasons.cultural_health.push(`Coach Culture Engine: ${cultureProfile.profile?.summary || 'analysis available'} (confidence: ${cultureProfile.confidence}).`);
      if (cultureProfile.profile?.delivery_alignment === 'aligned') {
        scores.promise_delivery = Math.min(10, scores.promise_delivery + 1);
        reasons.promise_delivery.push('Coach Culture Engine: stated values align with roster outcomes.');
      } else if (cultureProfile.profile?.delivery_alignment === 'misaligned') {
        scores.promise_delivery = Math.max(1, scores.promise_delivery - 2);
        reasons.promise_delivery.push('Coach Culture Engine: stated values misalign with roster outcomes — promise-delivery gap flag.');
      }
    }
  }

  const verdict = programVerdict(scores, foundation, sourceResults, grid_version);
  const narrative = await generateProgramNarrative(env, {
    programName: name || slug, sport, scores, verdict, apr, infractions, transferData,
    foundation, cultureProfile, profile
  });

  const id = 'gv_' + Date.now() + '_' + Math.random().toString(36).slice(2, 9);
  try {
    await dbExec(env,
      'INSERT INTO program_verdicts (id, slug, sport, verdict, scores_json, reasons_json, sources_json, narrative, created_at) VALUES (?,?,?,?,?,?,?,?,?)',
      [id, slug, sport, verdict, JSON.stringify(scores), JSON.stringify(reasons),
       JSON.stringify(sourceResults), narrative, Date.now()]
    );
  } catch (e) {}

  return {
    ok: true, id, track: 'program',
    name: name || slug, sport, sport_label: SPORTS[sport].label,
    verdict, scores, reasons, narrative,
    grid_version,      // v0.29: tells frontend which dim labels to use
    foundation,
    culture_profile: cultureProfile,
    sources: sourceResults,
    catalysts_attached: recentCatalysts.length,
    profile,           // v0.28: full tradition/championship/NFL/NIL/iconic moments
    indices,           // v0.28: 6 ranking indices + composite (0-100)
    methodology_url: 'https://fieldcheck.ai/methodology',
    generated_at: new Date().toISOString()
  };
}

// Helper: convert a program display name to our hardcoded slug pattern
function nameToSlug(name) {
  if (!name) return null;
  return name.toLowerCase().normalize('NFKD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9 ]/g, '').trim().replace(/\s+/g, '-');
}

