// LOVB roster aggregates — used for projection benchmarking
function getLOVBRosterStats() {
  // Computed lazily, cached. Used for projection scoring.
  const stats = {
    total: LOVB_ROSTER.length,
    by_position: {},
    by_team: {},
    by_college: {},
    olympian_count: 0
  };
  for (const p of LOVB_ROSTER) {
    stats.by_position[p.position] = (stats.by_position[p.position] || 0) + 1;
    stats.by_team[p.team] = (stats.by_team[p.team] || 0) + 1;
    if (p.college) stats.by_college[p.college] = (stats.by_college[p.college] || 0) + 1;
    if (p.olympian) stats.olympian_count++;
  }
  return stats;
}

// Normalize a name for matching: lowercase, strip punctuation, common nicknames
function normalizeNameForMatch(name) {
  if (!name) return '';
  return name.toLowerCase()
    .replace(/[^\w\s]/g, '')
    .replace(/\b(alexis|alex|alexandra)\b/g, 'lexi')
    .replace(/\b(katherine|katie|kathryn)\b/g, 'kate')
    .replace(/\b(jennifer|jenn)\b/g, 'jen')
    .replace(/\b(michael|mike)\b/g, 'mike')
    .replace(/\s+/g, ' ')
    .trim();
}

// Match a college player against the LOVB roster
function findInLOVBRoster(playerName) {
  const norm = normalizeNameForMatch(playerName);
  if (!norm) return null;
  // Exact match first
  for (const p of LOVB_ROSTER) {
    if (normalizeNameForMatch(p.name) === norm) return p;
  }
  // Partial match: every word in query exists in a roster name (handles "Lexi Rodriguez" vs "Alexis Rodriguez")
  const queryWords = norm.split(' ').filter(w => w.length > 2);
  if (queryWords.length === 0) return null;
  for (const p of LOVB_ROSTER) {
    const rosterWords = normalizeNameForMatch(p.name).split(' ');
    const allMatch = queryWords.every(qw => rosterWords.some(rw => rw.includes(qw) || qw.includes(rw)));
    if (allMatch) return p;
  }
  return null;
}

// ════════════════════════════════════════════════════════════
// v0.22: Multi-sport pathway dispatcher
// Routes to the sport-specific resolver. All resolvers return the same
// shape so the UI doesn't branch:
//   { sport, status, tier?, headline, pathway_summary, deep_dive?, international_options? }
// ════════════════════════════════════════════════════════════
function resolveProPathway(sport, playerName, schoolHint, evalGrid, facts) {
  switch (sport) {
    case 'womens-volleyball':
    case 'mens-volleyball':
      return resolveLOVBPathway(sport, playerName, schoolHint, evalGrid, facts);
    case 'football':
      return resolveNFLPathway(playerName, schoolHint, evalGrid, facts);
    case 'mens-basketball':
      return resolveNBAPathway(playerName, schoolHint, evalGrid, facts);
    case 'womens-basketball':
      return resolveWNBAPathway(playerName, schoolHint, evalGrid, facts);
    case 'baseball':
      return resolveMLBPathway(playerName, schoolHint, evalGrid, facts);
    case 'mens-soccer':
      return resolveMLSPathway(playerName, schoolHint, evalGrid, facts);
    case 'tennis':
      return resolveATPWTAPathway(playerName, schoolHint, evalGrid, facts);
    default:
      return null;
  }
}

// ────────────────────────────────────────────────────────────
// v0.22: NFL Pathway resolver (football)
// Tiers: ELITE_PROSPECT (1st-2nd round projection), DRAFTABLE (3rd-7th),
// UDFA_CAMP (priority free agent), DEVELOPMENTAL (UFL/CFL track),
// EARLY_LOOK (insufficient data)
// ────────────────────────────────────────────────────────────
function resolveNFLPathway(playerName, schoolHint, evalGrid, facts) {
  const composite = evalGrid?.overall_grade?.composite;
  const production = evalGrid?.overall_grade?.production;
  const physical = evalGrid?.overall_grade?.physical;
  const projectability = evalGrid?.overall_grade?.projectability;

  if (composite == null) {
    return {
      sport: 'football',
      status: 'EARLY_LOOK',
      tier: 'INSUFFICIENT_DATA',
      headline: 'Insufficient data to project NFL pathway',
      pathway_summary: 'Run a full FieldCheck verdict to populate eval grid scores. NFL pathway projection requires production + physical + projectability scoring at minimum.',
      international_options: []
    };
  }

  let tier, headline, summary;
  if (composite >= 8.5 && physical >= 8.0) {
    tier = 'ELITE_PROSPECT';
    headline = 'First-round projection range';
    summary = 'Composite + physical profile in elite NFL range. Mock-draft tracking territory. Combine performance becomes the next signal — measurable thresholds (40-yard, vertical, position drills) are the differentiator within the top tier.';
  } else if (composite >= 7.5) {
    tier = 'DRAFTABLE';
    headline = 'Day 2-3 draft projection';
    summary = 'Eval grid in draftable range. Senior Bowl / East-West Shrine invite is the next high-leverage signal. Combine measurables determine round position.';
  } else if (composite >= 6.5) {
    tier = 'UDFA_CAMP';
    headline = 'Priority free agent / late-round';
    summary = 'Below typical draft range but rosterable as priority undrafted free agent. Pro Day performance + film coverage by 1-2 NFL teams is the path forward.';
  } else if (composite >= 5.0) {
    tier = 'DEVELOPMENTAL';
    headline = 'UFL / CFL / developmental track';
    summary = 'Below NFL signing range. UFL (US spring league) and CFL offer real pro paths with NFL upside on year-2 elevation. International League of American Football is rising.';
  } else {
    tier = 'EARLY_LOOK';
    headline = 'Significant gap to pro projection';
    summary = 'Composite below typical pro thresholds. Year-over-year improvement + position change consideration are the levers.';
  }

  return {
    sport: 'football',
    status: 'PROJECTED',
    tier,
    headline,
    pathway_summary: summary,
    deep_dive: {
      free_preview: {
        tier_summary: tier.replace(/_/g, ' ').toLowerCase() + ' tier',
        headline_signal: 'Composite ' + composite + '/10' + (physical != null ? ' · physical ' + physical + '/10' : '')
      },
      gated_content: {
        production_target: production != null && production < 8.0 ? 'Senior-year production jump: target +25% in primary stat (yards, sacks, INTs depending on position)' : 'Maintain elite production through senior season',
        physical_target: physical != null && physical < 8.0 ? 'Combine prep is critical — work with a Combine specialist (EXOS, Michael Johnson Performance) for spring training' : 'Physical profile in pro range',
        next_season_triggers: 'All-Conference recognition, NCAA tournament/bowl game performance, Senior Bowl invite',
        tier_climb_path: tier === 'DRAFTABLE' ? 'Path to ELITE_PROSPECT: combine measurables in 90th percentile + Senior Bowl invite' :
                         tier === 'UDFA_CAMP' ? 'Path to DRAFTABLE: senior season production jump + position-elite combine' :
                         'Path to UDFA_CAMP: production breakout + Pro Day visibility'
      }
    },
    international_options: ['UFL (United Football League — US spring)', 'CFL (Canadian Football League)', 'International League of American Football (Europe)']
  };
}

