// ────────────────────────────────────────────────────────────
// v0.22: ATP/WTA Pathway resolver (tennis)
// UTR-based (Universal Tennis Rating is the gold-standard recruiting metric)
// ────────────────────────────────────────────────────────────
function resolveATPWTAPathway(playerName, schoolHint, evalGrid, facts) {
  const composite = evalGrid?.overall_grade?.composite;
  // UTR proxy: composite × 1.6 + 6 gives rough UTR mapping
  const utrEstimate = composite != null ? Math.round((composite * 1.6 + 6) * 10) / 10 : null;

  if (composite == null) {
    return {
      sport: 'tennis',
      status: 'EARLY_LOOK',
      tier: 'INSUFFICIENT_DATA',
      headline: 'Insufficient data to project pro pathway',
      pathway_summary: 'Tennis pro projection benefits enormously from UTR rating. Run full verdict to populate eval grid; submit UTR if available for sharper read.',
      international_options: []
    };
  }

  let tier, headline, summary;
  if (utrEstimate >= 14.5) {
    tier = 'ATP_WTA_TOUR';
    headline = 'ATP/WTA tour projection';
    summary = 'UTR ' + utrEstimate + ' projects ATP/WTA-tour range. Most college tennis players in this range turn pro junior or senior year. ITF World Tennis Tour transition is immediate.';
  } else if (utrEstimate >= 13.0) {
    tier = 'CHALLENGER_LEVEL';
    headline = 'ATP Challenger / ITF World Tennis Tour';
    summary = 'UTR ' + utrEstimate + ' is Challenger-tour viable. Year-1 strategy: ITF $25K-$80K events to build ranking, then Challenger circuit.';
  } else if (utrEstimate >= 11.5) {
    tier = 'ITF_FUTURES';
    headline = 'ITF Futures / coaching pathway';
    summary = 'UTR ' + utrEstimate + ' is ITF Futures range. Many players combine playing schedule with academy coaching role. Pickleball pro circuit is rising parallel option.';
  } else if (utrEstimate >= 10.0) {
    tier = 'TEACHING_PRO';
    headline = 'Teaching pro / academy track';
    summary = 'Below tour-projection range. USPTA / PTR teaching certification + academy pathway is the realistic professional outcome.';
  } else {
    tier = 'EARLY_LOOK';
    headline = 'Below typical pro projection';
    summary = 'Year-over-year UTR improvement is the only path back into projection range.';
  }

  return {
    sport: 'tennis',
    status: 'PROJECTED',
    tier,
    headline,
    pathway_summary: summary + ' UTR-based projection.',
    deep_dive: {
      free_preview: {
        tier_summary: tier.replace(/_/g, ' ').toLowerCase() + ' tier',
        headline_signal: 'Composite ' + composite + '/10 · UTR estimate ~' + utrEstimate
      },
      gated_content: {
        production_target: 'UTR jump: 0.8+ rating gain per year is elite improvement; 0.4 is average',
        next_season_triggers: 'ITA All-American, NCAA Singles championship round, verified UTR event participation',
        tier_climb_path: tier === 'CHALLENGER_LEVEL' ? 'Path to TOUR: UTR 14.5+ via ITF circuit performance' : 'UTR climb via verified event play + Challenger qualifier wins'
      }
    },
    international_options: ['ATP / WTA Tour', 'ATP Challenger Tour', 'ITF World Tennis Tour ($25K-$80K events)', 'College circuits + UTR events (post-college bridge)', 'Pickleball Pro Tour (PPA, MLP — rising parallel)', 'Padel pro circuit (international)']
  };
}

// LOVB Pathway resolver — the core function called from the player verdict handler.
// Returns null for non-volleyball sports.
// For volleyball: returns a structured pathway object that drives the UI card.
function resolveLOVBPathway(sport, playerName, schoolHint, evalGrid, facts) {
  // Only volleyball gets LOVB pathway
  if (sport !== 'womens-volleyball' && sport !== 'mens-volleyball') return null;

  // Men's volleyball doesn't have a domestic pro pipeline like LOVB yet.
  // Be honest about it instead of pretending.
  if (sport === 'mens-volleyball') {
    return {
      sport: 'mens-volleyball',
      status: 'NOT_APPLICABLE',
      headline: 'No domestic men\'s pro league equivalent to LOVB',
      explainer: 'LOVB Pro is women\'s-only as of 2025. Elite men\'s NCAA volleyball players go to Italian SuperLega, Polish PlusLiga, Russian Super League, Japanese V.League, or U.S. Men\'s National Team / VNL.',
      international_options: [
        'Italian SuperLega (top global men\'s league)',
        'Polish PlusLiga',
        'Japanese V.League',
        'U.S. Men\'s National Team / VNL'
      ]
    };
  }

  // Women's volleyball: do the lookup
  const rosterMatch = findInLOVBRoster(playerName);

  // Get position from eval grid if available
  const position = evalGrid?.position_label?.split(' ')[0] || null;
  const positionKey = position === 'Outside' ? 'OH' : position === 'Middle' ? 'MB' : position === 'Setter' ? 'S' : position === 'Libero' ? 'L' : position === 'Opposite' ? 'OPP' : null;

  if (rosterMatch) {
    // VERIFIED — player is on LOVB roster
    const rosterStats = getLOVBRosterStats();

    // Position-specific deep dive: WHY this player made the LOVB cut.
    // These are the structured reasons + role markers + monetization-gated signals.
    const positionRolePlaybook = {
      OH: {
        cut_reasons: [
          'Outside hitters are LOVB\'s highest-volume signing position. Six-rotation OHs with passing carry premium value.',
          'Production threshold for signing: kills/set above 3.0 starter median + hitting efficiency above .220.',
          'NCAA tournament reps and championship-level coaching exposure are weighted heavily by LOVB scouts.'
        ],
        role_projection: 'Likely 6-rotation outside hitter — both front-row attacking and back-row passing. LOVB systems lean 5-1, putting OHs in receive on most rotations.',
        cap_markers: 'Rookie LOVB salary band typically $50K-$80K base + per-game bonuses + housing stipend. Top-of-class OH rookies (e.g., Olympic appearance + NCAA award) clear $100K total comp.',
        risk_factors: [
          'OH position is competitive — most LOVB teams carry 4-5 OHs, so role carve-out is the year-2 challenge.',
          'International offers from Italian Serie A1 / Turkish Sultanlar can match or exceed LOVB rookie comp; retention through year 3 is the league-level question.'
        ]
      },
      MB: {
        cut_reasons: [
          'Middle blockers are positional premium — block reach (10\'2"+) and quick-attack tempo are scarce skills.',
          'Hitting % threshold (.300+) and block touch rate (1.0+ per set) are the two primary signing filters.',
          'Sustained NCAA tournament reps validate the high-pressure tempo execution.'
        ],
        role_projection: 'Quick-attack MB in a 5-1 system. Blocking responsibility against opposing OH is primary defensive load. Limited back-row reps (subbed for libero).',
        cap_markers: 'MB rookies sign in similar band to OH ($50K-$80K) but elite blockers with Olympic ties push $100K-$130K total comp. Block touch height is the most-paid physical metric in the league.',
        risk_factors: [
          'MB role is shorter than OH on a per-match basis — back-row substitution means lower minute counts.',
          'Injury rate at MB (knees from landings, ankles) is highest of any position in pro volleyball.'
        ]
      },
      S: {
        cut_reasons: [
          'Setters are the rarest position to sign — LOVB rosters carry 1-2 setters per team and value 5-1 system experience.',
          'The signal is team hitting % under the setter, not raw assist count. NCAA team hitting % .280+ is the threshold.',
          'Floor leadership and serving aggression separate signed setters from college-only setters.'
        ],
        role_projection: 'Primary setter in a 5-1 system means every-rotation responsibility. Tempo control + dump kills + back-row defense.',
        cap_markers: 'Setter comp is highly variable — top setters with Team USA ties clear $120K+ total comp. Rookie setters often start at OH-equivalent base but escalate fast.',
        risk_factors: [
          'Setter is the hardest position to develop — many rookie setters need 1-2 years before LOVB-level chemistry with hitters.',
          'Coaching change risk is highest at this position — setter-coach systems are intricate.'
        ]
      },
      L: {
        cut_reasons: [
          'Liberos signed by LOVB show 4.0+ career digs/set and elite reception grades (2.30+ on the AVCA 3.0 scale).',
          'Liberos are signing for production over physical specs — height under 5\'9" is fine, lateral quickness and platform discipline are the real currency.',
          'Career consistency and program record-holders (career digs leader) are top-tier signals.'
        ],
        role_projection: 'Defensive specialist + serve-receive primary. Will play 6 rotations of back-row coverage. Modern liberos also serve, so service ace rate matters.',
        cap_markers: 'Libero comp is the lowest base band ($40K-$70K) but performance bonuses based on dig count and reception grade are aggressive — top liberos can match OH total comp.',
        risk_factors: [
          'Libero is a thankless position by design — selflessness and receive-grade ceiling determine pro longevity.',
          'Knee wear from floor work is the long-term durability concern.'
        ]
      },
      OPP: {
        cut_reasons: [
          'Opposite hitters are the highest-volume terminators in pro volleyball — rookie OPPs need elite kill rate (3.5+ per set) and back-row attack capability.',
          'Approach reach 10\'0"+ and frame above 6\'1" are typical physical thresholds.',
          'Front-row blocking against opposing OH is a non-trivial requirement — OPPs that can\'t block are limited-rotation only.'
        ],
        role_projection: 'High-volume terminator in 5-1 system. Right-side blocking + back-row attacking. Often the team\'s point-per-rotation leader.',
        cap_markers: 'OPP comp tracks similar to OH — $50K-$100K rookie band, $130K+ for elite kill-rate signings.',
        risk_factors: [
          'OPP carries closer mentality risk — high-volume swings mean shoulder/back wear earlier than other positions.',
          'International leagues (Italian, Turkish, Polish) heavily target OPP role — retention pressure is real.'
        ]
      }
    };

    const playbook = positionRolePlaybook[rosterMatch.position] || {
      cut_reasons: ['Position-specific signing rationale not yet calibrated.'],
      role_projection: 'See position playbook for general context.',
      cap_markers: 'Cap data unavailable for this position.',
      risk_factors: []
    };

    return {
      sport: 'womens-volleyball',
      status: 'VERIFIED_LOVB',
      headline: `Currently rostered: LOVB ${rosterMatch.team}`,
      lovb_team: rosterMatch.team,
      lovb_position: rosterMatch.position,
      college: rosterMatch.college,
      olympian: rosterMatch.olympian || false,
      pathway_summary: `${playerName} is on LOVB ${rosterMatch.team}'s roster as a ${rosterMatch.position}. ${rosterMatch.college ? `College pathway: ${rosterMatch.college} → LOVB ${rosterMatch.team}.` : ''}${rosterMatch.olympian ? ' 2024 Team USA Olympian.' : ''}`,
      college_to_pro_validated: !!rosterMatch.college,
      roster_context: {
        league_total: rosterStats.total,
        teams: 6,
        olympians_in_league: rosterStats.olympian_count,
        same_position_in_league: rosterStats.by_position[rosterMatch.position] || 0
      },
      // v0.17: Deep dive — clickable detail panel.
      deep_dive: {
        gated: true,  // signals UI to show "Sign in for full analysis" gate
        free_preview: {
          // Visible without sign-in
          why_they_made_cut: playbook.cut_reasons.slice(0, 2),
          role_projection: playbook.role_projection
        },
        gated_content: {
          // Behind sign-in gate (Pro tier)
          why_they_made_cut_full: playbook.cut_reasons,
          cap_markers: playbook.cap_markers,
          risk_factors: playbook.risk_factors,
          year_one_watch_signals: [
            `Starting role secured: minutes per set above league median for ${rosterMatch.position} position.`,
            'Hitting % / dig rate / block rate trending at or above rookie-year cohort medians.',
            'Healthy through training camp + first 5 matches (durability gate).',
            'No coaching staff turnover at LOVB ' + rosterMatch.team + ' — system continuity matters most year 1.'
          ],
          year_two_watch_signals: [
            'Production growth from rookie season (kills/set, hitting %, dig rate per position).',
            'International offer comparison — if Italian Serie A1 offers >130% LOVB comp, retention risk.',
            'U.S. National Team / VNL inclusion as the next-rung signal.',
            'Role expansion — moving from rotational to primary at the position.'
          ]
        }
      }
    };
  }

  // Not on roster — generate projection
  // Pull eval grid scores if available
  const physical = evalGrid?.overall_grade?.physical;
  const production = evalGrid?.overall_grade?.production;
  const projectability = evalGrid?.overall_grade?.projectability;
  const composite = evalGrid?.overall_grade?.composite;

  // Position-specific gap-to-close playbook for projected players
  const positionGapPlaybook = {
    OH: {
      production_target: 'Hit 3.5+ kills/set with hitting % .250+ as a senior. Add 2.0+ digs/set for 6-rotation viability.',
      physical_target: 'Approach reach 9\'10" or higher. Standing reach 7\'11"+ ideal.',
      next_season_triggers: [
        'AVCA All-American (any team) → moves WATCH to HIGH_PROBABILITY.',
        'Conference Player of the Year → moves any tier up by one.',
        'NCAA tournament Sweet 16+ run with elevated personal stats → roster invite likely.'
      ],
      decision_levers: [
        'Transfer to a higher-major program (Big Ten, SEC, ACC, Pac-12 → Big 12) increases visibility 2-3x.',
        'Position flex — secondary OPP reps in 5-1 system show coaches versatility.',
        'Olympic Trials / VNL camp invite is the single strongest LOVB signal.'
      ]
    },
    MB: {
      production_target: 'Hit .320+ as a senior with 1.2+ blocks/set. Anything below .280 hitting % is a hard ceiling.',
      physical_target: 'Block touch 10\'2"+ measurable. Standing reach 8\'2"+ ideal.',
      next_season_triggers: [
        'AVCA All-American MB (any team) → roster-tier signal.',
        'NCAA championship game appearance (any role) → multiplies signing probability.',
        'Block per set leader in conference → tier upgrade.'
      ],
      decision_levers: [
        'Quick-attack tempo development — pair with a 5-1 setter for fast slides.',
        'Pin-block angles + closing speed work in offseason.',
        'Olympic Trials Camp invite is the elite signal.'
      ]
    },
    S: {
      production_target: 'Lead a team to .280+ team hitting % as the primary setter in a 5-1.',
      physical_target: 'Height 5\'10"+ helps but is not gating. Setter dump kills + serving aces matter.',
      next_season_triggers: [
        'AVCA Setter of the Year nomination → automatic HIGH_PROBABILITY tier.',
        'NCAA team hitting % top-10 nationally under your distribution → signing tier.',
        'U.S. Collegiate National Team invite → near-guaranteed pathway.'
      ],
      decision_levers: [
        'Develop dump kill above 0.5/set as a counter weapon.',
        'Service ace rate above 0.4/set — modern setters serve aggressively.',
        'High-major transfer if currently mid-major.'
      ]
    },
    L: {
      production_target: '4.5+ digs/set as a senior with reception grade 2.40+ (3.0 scale).',
      physical_target: 'Lateral quickness and platform discipline matter more than height. 5\'5"-5\'9" is fine.',
      next_season_triggers: [
        'AVCA Libero of the Year (any team) → roster tier.',
        'Program career digs record → strong signal.',
        'NCAA tournament Final Four with 5.0+ digs/set → near-automatic LOVB cut.'
      ],
      decision_levers: [
        'Service ace rate above 0.3/set differentiates modern liberos.',
        'Setter-libero chemistry (out-of-system passing) is the highest-value film signal.',
        'High-major transfer if mid-major — visibility is the gating factor.'
      ]
    },
    OPP: {
      production_target: '3.8+ kills/set with hitting % .280+ as a senior. Back-row attack capability adds 1-1.5 K/S.',
      physical_target: 'Approach reach 10\'0"+ and frame 6\'1"+ are typical thresholds.',
      next_season_triggers: [
        'AVCA All-American OPP → roster tier.',
        'Conference kills leader → tier upgrade.',
        'NCAA tournament personal kill record → signing tier.'
      ],
      decision_levers: [
        'Right-side blocking against OH must improve to non-rotational starter.',
        'Back-row attack reps in offseason training.',
        'Olympic Trials / Pan Am invite is the elite signal.'
      ]
    }
  };

  let tier, headline, projection_signals, international_signal;

  if (composite == null) {
    tier = 'INSUFFICIENT_DATA';
    headline = 'LOVB pathway projection unavailable — insufficient eval data';
    projection_signals = ['No composite eval grid score on file. Pathway projection requires production + physical scoring at minimum.'];
    international_signal = 'Cannot project international fit without baseline metrics.';
  } else if (composite >= 8.0) {
    tier = 'HIGH_PROBABILITY';
    headline = 'LOVB pathway: high-probability projection';
    projection_signals = [
      `Composite ${composite}/10 places this player in elite NCAA tier — directly comparable to current LOVB roster averages.`,
      production != null ? `Production ${production}/10 — at or above LOVB starter median (kills/set 3.0+, hitting % .220+, blocks/set 1.0+ depending on position).` : 'Production score unavailable.',
      physical != null ? `Physical ${physical}/10 — within LOVB roster physical distribution.` : 'Physical score unavailable.',
      'NCAA-to-LOVB pathway is a real and growing 2025-2026 trend; rookie LOVB Icons First Team selections are coming primarily from elite NCAA programs.'
    ];
    international_signal = 'Italian Serie A1 + Turkish Sultanlar Ligi are realistic alternatives if LOVB doesn\'t have positional need. Brazilian Superliga and Polish Liga A also tier-1 options.';
  } else if (composite >= 6.5) {
    tier = 'WATCH';
    headline = 'LOVB pathway: watch tier — needs another season of separation';
    projection_signals = [
      `Composite ${composite}/10 is solid D1 starter level but below current LOVB roster averages.`,
      production != null && production < 7 ? `Production ${production}/10 is below the per-set output threshold for LOVB rookie consideration.` : '',
      'A senior-year jump in production would move this player into HIGH_PROBABILITY tier.',
      'Athletes Unlimited Volleyball is a viable parallel pathway and recruits at a slightly lower production threshold than LOVB.'
    ].filter(Boolean);
    international_signal = 'European 2nd-tier leagues (Italian A2, Turkish 1. Lig, French Ligue B) are realistic starting points for international career.';
  } else if (composite >= 5.0) {
    tier = 'LONG_SHOT';
    headline = 'LOVB pathway: long shot — production gap from roster medians';
    projection_signals = [
      `Composite ${composite}/10 is below LOVB Pro and Athletes Unlimited typical signing thresholds.`,
      'Domestic pro pathway (LOVB / AU) requires production well above current eval grid scores.',
      'European 2nd/3rd tier or Brazilian Superliga B more realistic near-term.'
    ];
    international_signal = 'European 3rd-tier or South American regional leagues are plausible. NCAA D1 transfer to a higher-major program could change the projection.';
  } else {
    tier = 'UNLIKELY';
    headline = 'LOVB pathway: unlikely on current data';
    projection_signals = [
      `Composite ${composite}/10 is below pro-pipeline thresholds.`,
      'The eval grid does not support LOVB or international pro projection.',
      'Would need significant year-over-year improvement to reposition.'
    ];
    international_signal = 'No clear international pathway from current evaluation.';
  }

  // Build deep dive for projection
  const gapPlay = positionGapPlaybook[positionKey] || null;
  const projectedDeepDive = {
    gated: true,
    free_preview: {
      headline_signal: projection_signals[0] || 'No projection signal available.',
      tier_summary: `Tier: ${tier}. Composite ${composite ?? 'N/A'}/10 vs LOVB roster averages.`
    },
    gated_content: gapPlay ? {
      production_target: gapPlay.production_target,
      physical_target: gapPlay.physical_target,
      next_season_triggers: gapPlay.next_season_triggers,
      decision_levers: gapPlay.decision_levers,
      tier_climb_path: tier === 'WATCH'
        ? 'Path WATCH → HIGH_PROBABILITY: hit production targets above + secure AVCA recognition or NCAA tournament Final Four with elevated personal stats.'
        : tier === 'LONG_SHOT'
        ? 'Path LONG_SHOT → WATCH: close production gap to D1 starter median + earn conference-level recognition.'
        : tier === 'HIGH_PROBABILITY'
        ? 'Already in signing range. Year-1 conversion levers: senior season conference performance + national team camp invite + agent representation by senior spring.'
        : 'Significant year-over-year improvement needed to enter projection range. Transfer to higher-major program may be a structural move.',
      year_by_year_watch: [
        'This season: stat trajectory tracking (kills/set, hitting %, blocks/set, digs/set per position).',
        'Next season: AVCA award candidacy + NCAA tournament run.',
        'Senior year: signing-tier production + national team camp invite.',
        'Post-college: agent representation + LOVB scout viewing window (typically Nov-Jan after senior season).'
      ]
    } : {
      tier_climb_path: 'Position-specific gap targets unavailable — eval grid did not resolve a playbook position. Generic guidance: increase production above starter medians, target AVCA recognition, secure exposure at high-major program.',
      year_by_year_watch: ['Track production growth year over year.', 'Target conference-level recognition.', 'Senior year is the signing window.']
    }
  };

  return {
    sport: 'womens-volleyball',
    status: 'PROJECTED',
    tier,
    headline,
    projection_signals,
    international_signal,
    composite_score: composite,
    physical_score: physical,
    production_score: production,
    projectability_score: projectability,
    position_key: positionKey,
    honest_note: 'This is FieldCheck\'s analytic projection based on the eval grid against LOVB roster benchmarks. It is not a draft prediction or guarantee. LOVB roster decisions involve coaching fit, market need, age, and intangibles not in this evaluation.',
    league_context: {
      lovb_teams: 6,
      league_total: getLOVBRosterStats().total,
      olympians_in_league: getLOVBRosterStats().olympian_count,
      first_season: '2025 (launched January 8, 2025)'
    },
    deep_dive: projectedDeepDive
  };
}

// ════════════════════════════════════════════════════════════
// THE EVAL GRID GENERATOR
// Strict prompt. Score only what we have evidence for. Everything else null.
// ════════════════════════════════════════════════════════════
async function generateCoachEvalGrid(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) return { error: 'no_api_key' };

  const facts = ctx.facts || {};
  const id = facts.identity || {};
  const positionStr = id.position || ctx.fallbackPosition || null;

  const resolved = resolvePositionPlaybook(ctx.sport, positionStr);
  if (!resolved) {
    return {
      grid_available: false,
      reason: 'no_playbook_for_position',
      position_attempted: positionStr,
      sport: ctx.sport,
      note: 'v0.9 position playbooks: football:S, football:QB, mens-basketball:G. Other positions coming.'
    };
  }

  const { key: playbookKey, playbook, benchmarks } = resolved;

  // Pull every fact-bearing source for the prompt
  const factsText = JSON.stringify(facts, null, 2);
  const benchmarksText = benchmarks ? JSON.stringify(benchmarks, null, 2) : '(no benchmarks loaded for this position)';

  const dimensionList = [
    ...playbook.physical.map(d => ({ ...d, layer: 'physical' })),
    ...playbook.production.map(d => ({ ...d, layer: 'production' })),
    ...playbook.projectability.map(d => ({ ...d, layer: 'projectability' }))
  ];
  const dimensionsForPrompt = dimensionList.map(d => `  ${d.layer}.${d.id} ("${d.label}"): ${d.explainer}`).join('\n');

  const prompt = `You are FieldCheck — building a Coach Evaluation Grid for a college ${ctx.sportLabel} ${playbook.label}.

PLAYER FACTS (extracted from real sources, never invent):
${factsText}

POSITION BENCHMARKS (use these to contextualize scores; cite when relevant):
${benchmarksText}

DIMENSIONS TO SCORE:
${dimensionsForPrompt}

═══ YOUR TASK ═══

For EACH dimension above, output a score object. The score is 1-10, OR null if you don't have evidence to score it. Output ONLY valid JSON:

{
  "playbook_key": "${playbookKey}",
  "position_label": "${playbook.label}",
  "scored_at": "<ISO timestamp>",
  "dimensions": {
    "physical": {
      "size": { "score": 7, "evidence": "Player listed at 6'0, 206 lbs (per LSU roster). Median SEC safety is 6'1, 208 lbs — slightly under-height but at-weight.", "data_source": "school_roster", "gap": null },
      "speed": { "score": null, "evidence": null, "data_source": null, "gap": "No 40-yard dash time on record. Not in combine database." },
      ...
    },
    "production": {
      "tackling": { "score": 8, "evidence": "72 tackles in 13 starts at LSU 2025 (5.5/g). PFF tackle grade 75.4 at NC State 2024. Both at or above SEC starter median.", "data_source": "career_history + PFF", "gap": null },
      ...
    },
    "projectability": {
      "frame_ceiling": { "score": 5, "evidence": "Already at 206 lbs at 6'0; appears close to maxed-out frame for safety position.", "data_source": "interpreted from listed measurables", "gap": null },
      "character": { "score": 6, "evidence": "Two transfers in two years (Maryland → NC State → LSU) is a yellow flag in pattern. Coaches at all three stops praised work ethic publicly.", "data_source": "career_history + quotes", "gap": null },
      ...
    }
  },
  "overall_grade": {
    "physical": 6.5,
    "production": 7.5,
    "projectability": 6.0,
    "composite": 6.7,
    "interpretation": "Above-average SEC starting safety profile with a thin physical-measurables file. Projection bound by frame ceiling more than production."
  },
  "honest_caveats": [
    "No combine data on file — physical layer is partial.",
    "Coverage grade for LSU 2025 not yet ingested (only NC State 2024)."
  ]
}

═══ CRITICAL RULES ═══

1. **Score only on evidence.** If the facts contain no 40-time, speed.score MUST be null with a gap note. Do not guess from height/weight to project a 40 time.
2. **Cite the data_source** for every non-null score. e.g., "career_history", "school_roster", "quotes", "PFF", "interpreted from X".
3. **Use the benchmarks** to contextualize. Don't just say "good size" — say "at or below the SEC median of 6'1, 208 lbs."
4. **'Interpreted from X' is allowed** for projectability dimensions like character, scheme fit, durability — these are inherently judgment calls. SAY so explicitly in evidence text.
5. **The take is interpretive, the facts are not.** Scoring is interpretive. Being honest about that earns trust.
6. **Composite math:** average of layer scores you actually scored (skip null layers in the math).`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-5-20250929',
        max_tokens: 2000,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!r.ok) {
      const errBody = await r.text();
      return { grid_available: false, error: 'anthropic_' + r.status, detail: errBody.slice(0, 200) };
    }
    const data = await r.json();
    const responseText = data.content?.[0]?.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { grid_available: false, error: 'no_json' };
    try {
      const parsed = JSON.parse(jsonMatch[0]);
      parsed.grid_available = true;
      parsed.playbook_meta = {
        physical_dims: playbook.physical,
        production_dims: playbook.production,
        projectability_dims: playbook.projectability
      };
      parsed.benchmarks_used = benchmarks;
      return parsed;
    } catch (e) {
      return { grid_available: false, error: 'json_parse_failed', raw: responseText.slice(0, 400) };
    }
  } catch (e) {
    return { grid_available: false, error: 'request_failed', detail: String(e).slice(0, 200) };
  }
}

// ════════════════════════════════════════════════════════════
// PLAYER ENCYCLOPEDIA — two-pass facts-only generator (v0.8)
// ════════════════════════════════════════════════════════════
// Pass 1 (extractPlayerFacts): given all fetched text, produce a strict
// JSON of structured facts. Anything not in the text → null. No priors.
// Pass 2 (generateTake): given those facts + live coaching staff +
// recent news mentions, write THE TAKE only. The page renders the facts
// directly from Pass 1; Claude doesn't write the body of the page.

async function extractPlayerFacts(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) return { error: 'no_api_key' };

  // Stitch every text source we have into one corpus
  const blocks = [];
  if (ctx.wikipedia && ctx.wikipedia.extract) {
    blocks.push(`=== WIKIPEDIA: ${ctx.wikipedia.title || ''} ===\n${ctx.wikipedia.extract}\nSource: ${ctx.wikipedia.source_url}`);
  }
  if (ctx.schoolRoster && ctx.schoolRoster.bio && ctx.schoolRoster.bio.bio_text) {
    const b = ctx.schoolRoster.bio;
    const facts = [];
    if (b.position) facts.push(`Position: ${b.position}`);
    if (b.height) facts.push(`Height: ${b.height}`);
    if (b.weight) facts.push(`Weight: ${b.weight}`);
    if (b.class_year) facts.push(`Class: ${b.class_year}`);
    if (b.hometown) facts.push(`Hometown: ${b.hometown}`);
    blocks.push(`=== SCHOOL ROSTER PAGE (${ctx.schoolRoster.school}) ===\n${facts.join(', ')}\n${b.bio_text}\nSource: ${ctx.schoolRoster.source_url}`);
  } else if (ctx.schoolRoster && ctx.schoolRoster.roster_confirmed) {
    blocks.push(`=== SCHOOL ROSTER PAGE (${ctx.schoolRoster.school}) ===\nName confirmed on ${ctx.schoolRoster.detected_program || ctx.schoolRoster.sport} roster.\nSource: ${ctx.schoolRoster.source_url}`);
  }
  if (ctx.openWeb && Array.isArray(ctx.openWeb.excerpts)) {
    for (const ex of ctx.openWeb.excerpts) {
      blocks.push(`=== ${ex.title || 'Web Result'} ===\n${ex.excerpt}\nSource: ${ex.url}`);
    }
  }
  if (ctx.sportsRef && ctx.sportsRef.career_stats) {
    blocks.push(`=== SPORTS REFERENCE ===\n${JSON.stringify(ctx.sportsRef.career_stats)}\nSource: ${ctx.sportsRef.source_url}`);
  }
  if (ctx.composite247 && ctx.composite247.composite_rank) {
    blocks.push(`=== 247SPORTS COMPOSITE ===\nRank: ${ctx.composite247.composite_rank}, Stars: ${ctx.composite247.stars || 'unknown'}, Position: ${ctx.composite247.position || 'unknown'}`);
  }
  if (ctx.recentNewsMentions && ctx.recentNewsMentions.length > 0) {
    blocks.push(`=== RECENT CATALYST CORPUS (last 30 days) ===\n` + ctx.recentNewsMentions.map(m => `[${m.captured_at?.slice(0,10) || ''}][${m.source_label || ''}] ${m.summary}`).join('\n'));
  }

  if (blocks.length === 0) {
    return { facts_available: false, reason: 'no_source_text' };
  }

  const corpus = blocks.join('\n\n').slice(0, 18000);

  const prompt = `You are an analyst extracting STRUCTURED FACTS about a college sports player from source text. The source text is below. You must extract ONLY facts that are explicitly stated in the text. If a fact is not in the text, set the field to null. Do not use prior knowledge. Do not infer. Do not guess. If the text says "Cooley played at NC State" — record that. If the text doesn't mention his hometown — set hometown to null even if you "know" it.

Player target: ${ctx.playerName}
School target: ${ctx.schoolHint || '(none provided — extract whatever school is in the text)'}
Sport target: ${ctx.sportLabel}

═══ SOURCE TEXT ═══
${corpus}
═══ END SOURCE TEXT ═══

Output ONLY valid JSON. No preamble, no markdown fences. Schema:

{
  "identity": {
    "full_name": "as appears in source, or null",
    "current_school": "school name from source, or null",
    "position": "position abbreviation or full, from source, or null",
    "jersey_number": "number from source, or null",
    "class_year": "Freshman / Sophomore / Junior / Senior / Graduate / Redshirt X / null",
    "height": "e.g. 6'1\\" — from source, or null",
    "weight": "e.g. 205 lbs — from source, or null"
  },
  "origin": {
    "hometown": "City, State / null",
    "high_school": "high school name / null",
    "recruit_class_year": "year of HS graduation / null",
    "recruit_stars": "3, 4, 5 / null",
    "recruit_ranking": "free text from source, e.g. 'No. 988 overall (247Sports 2023)' / null",
    "primary_sport_position_HS": "position they played in HS / null"
  },
  "career_history": [
    {
      "school": "string",
      "years": "e.g. 2023, or 2023-2024",
      "stats_summary": "one-line stats from text, or null",
      "notable_moments": "from source, or null"
    }
  ],
  "transfer_history": [
    {
      "from": "school", "to": "school", "when": "date or season", "reason_if_stated": "from source or null"
    }
  ],
  "nil": {
    "deals_mentioned": "list of brands or partners from text, or null",
    "valuation_estimate": "if any number cited, or null"
  },
  "recent_news_summary": "1-2 sentences synthesizing what the recent news mentions are saying about this player. From the catalyst corpus block AND the open-web excerpts. If no mentions, null.",
  "recent_news_items": [
    {"date_or_period": "e.g. 'January 2025' or '2025-04-15' or 'Spring 2025' — extract from the source text or context, never invent", "headline": "short summary of the news item, in your own words", "source_label": "outlet name from source if known, e.g. 'On3', 'ESPN', 'nola.com'", "source_url": "url where the item was found"}
  ],
  "quotes_about_him": [
    {"quote": "exact quote from source", "speaker": "name and title from source", "speaker_role_at_time": "speaker's role and date context, e.g. 'LSU head coach (Jan 2025, since fired Oct 2025)' — be honest about historical context if known from the source text", "source_url": "url"}
  ],
  "quotes_by_him": [
    {"quote": "exact quote from source", "context": "from source", "date_or_period": "when the quote was made if known, or null", "source_url": "url"}
  ],
  "injury_or_status_notes": "from source if any, or null",
  "facts_extracted_count": "integer — count of non-null fields you populated",
  "source_count": "integer — count of source blocks that contributed at least one fact"
}

CRITICAL RULES:
1. EXACT QUOTES ONLY. If the text doesn't contain the quote in those words, leave it out.
2. NEVER use prior knowledge. If you "know" the head coach is Lane Kiffin but the text doesn't say so, leave it null.
3. Career history must reflect what the text actually says, in order.
4. Empty arrays are OK. Null is OK. Never make things up.`;

  const playerSport = (ctx.sport || '').toLowerCase();
  const isWomensSport = playerSport.startsWith('womens-') || playerSport.includes('women');
  const isMensSport = playerSport.startsWith('mens-') || playerSport === 'football' || playerSport === 'baseball';
  const inferredGender = isWomensSport ? 'female' : (isMensSport ? 'male' : 'unspecified');
  const pronounHint = isWomensSport
    ? 'IMPORTANT: This is a women\'s sport. The player is female. Use she/her pronouns when paraphrasing or summarizing facts. Refer to coaches and teammates by their actual names from the source text.'
    : isMensSport
    ? 'NOTE: This is a men\'s sport. Player pronouns: he/him.'
    : 'NOTE: Sport not gender-categorized. Use neutral language.';

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 2000,
        messages: [{ role: 'user', content: prompt + '\n\n' + pronounHint }]
      })
    });
    if (!r.ok) {
      const errBody = await r.text();
      return { error: 'anthropic_' + r.status, detail: errBody.slice(0, 200) };
    }
    const data = await r.json();
    const responseText = data.content?.[0]?.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { error: 'no_json' };
    try {
      const parsed = JSON.parse(jsonMatch[0]);
      parsed.facts_available = true;

      // v0.30.3: Stamp inferred gender on identity for downstream renderers.
      if (!parsed.identity) parsed.identity = {};
      if (!parsed.identity.gender && inferredGender !== 'unspecified') {
        parsed.identity.gender = inferredGender;
      }

      // v0.30.3: Mirror quotes to gender-correct field names for renderers that prefer them.
      // Frontend reads quotes_about_him first, then quotes_about_her, then quotes_about_player.
      if (isWomensSport) {
        if (Array.isArray(parsed.quotes_about_him) && parsed.quotes_about_him.length > 0 && !parsed.quotes_about_her) {
          parsed.quotes_about_her = parsed.quotes_about_him;
        }
        if (Array.isArray(parsed.quotes_by_him) && parsed.quotes_by_him.length > 0 && !parsed.quotes_by_her) {
          parsed.quotes_by_her = parsed.quotes_by_him;
        }
      }

      return parsed;
    } catch (e) {
      return { error: 'json_parse_failed', raw: responseText.slice(0, 400) };
    }
  } catch (e) {
    return { error: 'request_failed', detail: String(e).slice(0, 200) };
  }
}

// Pass 2: generate THE TAKE only. Inputs: structured facts + live coaching staff text + recent news.
async function generateTakeOnly(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) return { error: 'no_api_key' };
  const facts = ctx.facts || {};
  const coachStaffText = ctx.coachingStaff && ctx.coachingStaff.excerpt
    ? `=== ${ctx.schoolHint} CURRENT COACHING STAFF (live from school's site) ===\n${ctx.coachingStaff.excerpt.slice(0, 3000)}\nSource: ${ctx.coachingStaff.source_url}`
    : '(No live coaching staff data was retrievable for this school.)';

  const recentNews = (ctx.recentNewsMentions || []).slice(0, 5).map(m => `[${m.captured_at?.slice(0,10) || ''}] ${m.summary}`).join('\n');

  // Eval grid context — the scout's interpretive scores per dimension
  let gridText = '(no eval grid available — position playbook not yet defined)';
  if (ctx.evalGrid && ctx.evalGrid.grid_available) {
    const og = ctx.evalGrid.overall_grade || {};
    const summarizeLayer = (layerObj) => {
      if (!layerObj) return '(none)';
      return Object.entries(layerObj).map(([k, v]) =>
        `  ${k}: ${v.score == null ? 'N/A (' + (v.gap || 'no data') + ')' : v.score + '/10'} — ${v.evidence || ''}`
      ).join('\n');
    };
    gridText = `Position: ${ctx.evalGrid.position_label}
Overall: physical ${og.physical || '?'} · production ${og.production || '?'} · projectability ${og.projectability || '?'} · composite ${og.composite || '?'}
Interpretation: ${og.interpretation || ''}

PHYSICAL:
${summarizeLayer(ctx.evalGrid.dimensions?.physical)}

PRODUCTION:
${summarizeLayer(ctx.evalGrid.dimensions?.production)}

PROJECTABILITY:
${summarizeLayer(ctx.evalGrid.dimensions?.projectability)}`;
  }

  // v0.15: sport-specific pro pipeline context. Helps the take ground career arc
  // discussion in the actual pro pathways that exist for the sport, not generic NFL/NBA assumptions.
  const proPipelineByGuide = {
    'mens-basketball': 'NBA → G-League → European top leagues (EuroLeague, Liga ACB, Lega A). NIL deals + transfer portal also relevant for late-college decisions.',
    'womens-basketball': 'WNBA → European pro (Turkey, Italy, France) is standard offseason. Elite players often play year-round between WNBA + overseas.',
    'football': 'NFL Draft → undrafted free agent → CFL/UFL fallback. NIL collective deals are the immediate-economy reality during college.',
    'baseball': 'MLB Draft → minor league system (AAA/AA/A). Top JUCO arms can also go pro before D1. Career arc is years longer than other sports.',
    'mens-soccer': 'MLS SuperDraft → USL Championship/MLS Next Pro → European pro (Bundesliga 2, Eredivisie, Liga MX). MLS Homegrown signings bypass college entirely.',
    'tennis': 'ATP/WTA Tour → ATP Challenger / ITF Futures → exhibition tours. UTR climb is the trackable signal. Some elite juniors skip college entirely.',
    'womens-volleyball': 'LOVB Pro (League One Volleyball, launched Jan 2025, six U.S. teams) → Athletes Unlimited Volleyball → top international leagues (Italian Serie A1, Turkish Sultanlar Ligi, Brazilian Superliga, Polish PlusLiga for women too in some cases). The U.S. Olympic team pipeline runs through these. LOVB Pro and AU are now real American pathways that didn\'t exist 3 years ago — ground the career arc here.',
    'mens-volleyball': 'Limited U.S. pro pipeline (men\'s NCAA volleyball is small, ~24 D1 programs). Elite men go to Italian SuperLega, Polish PlusLiga, Russian Super League, Japanese V.League, or Volleyball Nations League / U.S. National Team training. Pro options domestically remain thin compared to women\'s post-LOVB.'
  };
  const proPipelineContext = proPipelineByGuide[ctx.sport] || '(generic college-to-pro context)';

  // v0.16: trim facts JSON to essential keys to cut prompt size by ~30-40%.
  // The full facts dump was the take prompt's biggest token cost.
  const trimFactsForTake = (f) => {
    if (!f || typeof f !== 'object') return f;
    const trimmed = {};
    const keep = ['identity', 'career_history', 'recruit_ranking', 'transfer_history',
                  'recent_news_summary', 'recent_news_items', 'injury_or_status_notes',
                  'quotes_about_him', 'quotes_by_him', 'awards_and_honors',
                  'pro_pathway_signals'];
    for (const k of keep) {
      if (f[k] !== undefined) trimmed[k] = f[k];
    }
    return trimmed;
  };
  const factsTrimmed = trimFactsForTake(facts);

  // v0.16: pull LOVB pathway resolution into the take prompt so the take grounds
  // career arc language in the verified roster + projection. Volleyball only.
  let lovbContextBlock = '';
  if (ctx.sport === 'womens-volleyball') {
    const lovbForTake = (() => {
      try {
        return resolveLOVBPathway(ctx.sport, ctx.playerName, ctx.schoolHint, ctx.evalGrid, facts);
      } catch (e) { return null; }
    })();
    if (lovbForTake) {
      if (lovbForTake.status === 'VERIFIED_LOVB') {
        lovbContextBlock = `\n═══ LOVB PATHWAY RESOLUTION (verified roster lookup) ═══
This player IS currently rostered on LOVB ${lovbForTake.lovb_team} as a ${lovbForTake.lovb_position}.
${lovbForTake.olympian ? '2024 Team USA Olympian. ' : ''}College pathway: ${lovbForTake.college} → LOVB ${lovbForTake.lovb_team}.
The take MUST reference this verified pro placement explicitly.\n`;
      } else if (lovbForTake.status === 'PROJECTED') {
        lovbContextBlock = `\n═══ LOVB PATHWAY PROJECTION (analytic — not draft prediction) ═══
Tier: ${lovbForTake.tier}. ${lovbForTake.headline}
Composite ${lovbForTake.composite_score ?? 'N/A'}/10. Production ${lovbForTake.production_score ?? 'N/A'}/10. Physical ${lovbForTake.physical_score ?? 'N/A'}/10.
Signals: ${(lovbForTake.projection_signals || []).join(' | ')}
International: ${lovbForTake.international_signal || ''}
The take should reference the LOVB pathway by name and tier, with appropriate hedging — this is a projection, not a guarantee.\n`;
      }
    }
  }

  // v0.30.3: Sport-aware pronoun guidance for the take narrative.
  const takeSport = (ctx.sport || '').toLowerCase();
  const takeIsWomens = takeSport.startsWith('womens-') || takeSport.includes('women');
  const takeIsMens = takeSport.startsWith('mens-') || takeSport === 'football' || takeSport === 'baseball';
  const pronounDirective = takeIsWomens
    ? `\n═══ PRONOUN DIRECTIVE ═══\nThis is a women's sport. The player is female. ALWAYS use she/her/hers when referring to the player. NEVER use he/him/his. Refer to teammates and coaches by their actual names from the source text. If you slip into masculine pronouns the take is unusable.\n`
    : takeIsMens
    ? `\n═══ PRONOUN DIRECTIVE ═══\nThis is a men's sport. Use he/him/his when referring to the player.\n`
    : `\n═══ PRONOUN DIRECTIVE ═══\nGender not specified. Use neutral language ("the player", "they") when pronouns are needed.\n`;

  const prompt = `You are FieldCheck — an independent scout writing THE TAKE on a college ${ctx.sportLabel} player.
${pronounDirective}
Player: ${ctx.playerName}
Verdict tier provided: ${ctx.verdict}
Foundation: ${ctx.foundation?.tier || 'unknown'} (${ctx.foundation?.signal_count || 0} signal sources)

═══ STRUCTURED FACTS ABOUT THIS PLAYER (extracted from real sources) ═══
${JSON.stringify(factsTrimmed, null, 2)}

═══ COACH EVALUATION GRID (FieldCheck's scored interpretation) ═══
${gridText}

═══ ${ctx.schoolHint || 'PROGRAM'} CURRENT COACHING STAFF ═══
${coachStaffText}

═══ RECENT NEWS MENTIONS ═══
${recentNews || '(none)'}

═══ PRO PIPELINE CONTEXT FOR THIS SPORT ═══
${proPipelineContext}
${lovbContextBlock}
═══ TONE FOR THIS SPORT ═══
${takeIsWomens
  ? `This is a women's sport with a serious pro pathway (LOVB Pro launched Jan 2025, Athletes Unlimited Volleyball, Italian Serie A1, Turkish Sultanlar Ligi, Brazilian Superliga, plus Olympic team pipeline). Treat this player with the same scouting seriousness you'd treat any elite men's prospect — full pro track, real career economics. When data is thin, lead with what IS known (program pedigree, coach trust signals, hometown momentum, multi-sport athleticism) before honestly naming the gap. Never frame thin data as a verdict against the player; frame it as the next chapter to be written. Voice: respected program insider, not draft-service gatekeeper.`
  : takeIsMens
  ? `Standard scouting voice — direct, evidence-based, willing to make a call.`
  : `Neutral, evidence-based scouting voice.`}

═══ YOUR TASK ═══
Output ONLY valid JSON. No preamble. Schema:

{
  "take": "3-5 sentences. The scout's ACTUAL OPINION on this player's path to greatness. Direct, not hedged. Reference specific dimensions from the eval grid by NAME (e.g., 'tackling 8/10', 'frame ceiling 5/10'). Reference specific facts from the structured data. If you mention a coach, use ONLY a name that appears in the coaching staff text — do NOT use any name not in that text. When discussing career arc or pro projection, ground it in the PRO PIPELINE CONTEXT for this sport (e.g., for volleyball ALWAYS mention LOVB Pro by name, plus Athletes Unlimited or international leagues when relevant). For volleyball with a LOVB PATHWAY block above, the take MUST reference the LOVB pathway status explicitly. Tone: a scout who sees the path forward — not a gatekeeper looking for reasons to walk away. Celebrate the real signal where it exists. Be honest about the gap when it doesn't. No marketing language. Make a real call.",
  "next_jump_triggers": [
    "3-5 specific monitorable signals that would meaningfully change the eval. Each starts with a condition and what it would mean. Example: 'If he starts in the season opener at safety → role secured, signing window opens.' / 'If kills/set crosses 3.5 with hitting % above .280 → moves into LOVB consideration.' Frame these as path-to-greatness milestones — what to watch for, not what to fear."
  ],
  "roadmap_to_cut": [
    "If the player is NOT yet at the signing/starter tier, list 2-4 concrete steps they would need to climb. Example: 'Add 15+ lbs of frame mass before fall camp.' / 'Earn AVCA All-Region recognition senior year.' If the player IS already at the cut tier (rostered, signed, or grid composite ≥7.5), return an empty array — no roadmap needed."
  ],
  "honest_unknowns": [
    "1-3 specific gaps in our data that would change the take if filled. Example: 'No PFF coverage grade integrated.' / 'Spring practice depth chart not yet published.'"
  ]
}

ABSOLUTE RULES:
1. Names of coaches, coordinators, AD: ONLY from the live coaching staff text. If a coach's name is not there, do not name them.
2. Stats and rankings: ONLY from the structured facts above.
3. Don't say "historically does X" — that's prior knowledge. Stick to what's in front of you.
4. Reference grid scores by name in the take where relevant. The take should feel like it's built ON the grid, not parallel to it.
5. Career arc / pro projection language must use the ACTUAL pro pathways listed above for this sport. For VOLLEYBALL specifically, the take MUST name LOVB Pro explicitly. If the LOVB PATHWAY block shows the player is rostered, lead with celebration of that.
6. The take should be 3-5 sentences max. Direct. Punchy. Inspirational where the data supports it; honest where it doesn't.
7. NEVER write the take in a defensive/avoidance frame. Frame is "find the path" — what does this player need to do, what are they already doing right.`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-5-20250929',
        max_tokens: 1200,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!r.ok) return { error: 'anthropic_' + r.status };
    const data = await r.json();
    const responseText = data.content?.[0]?.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { error: 'no_json' };
    try {
      return JSON.parse(jsonMatch[0]);
    } catch (e) {
      return { error: 'json_parse_failed', raw: responseText.slice(0, 400) };
    }
  } catch (e) {
    return { error: 'request_failed', detail: String(e).slice(0, 200) };
  }
}

// Backwards-compat wrapper that the existing player verdict handler still calls
async function generateScoutDossier(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) {
    return {
      identity: 'Dossier requires ANTHROPIC_API_KEY.',
      trajectory: null, fit: null, take: null, watchlist: []
    };
  }

  const sportLabel = SPORTS[ctx.sport]?.label || ctx.sport;

  // Gather every signal we have, label it, drop nothing.
  const signals = [];
  const sr = ctx.sourceResults?.school_roster;
  if (sr && sr.roster_confirmed) {
    signals.push(`ROSTER (school: ${sr.school}, sport: ${sr.detected_program || sr.sport}):`);
    if (sr.bio) {
      const b = sr.bio;
      const facts = [];
      if (b.position) facts.push(`Position ${b.position}`);
      if (b.height) facts.push(`Height ${b.height}`);
      if (b.weight) facts.push(`Weight ${b.weight}`);
      if (b.class_year) facts.push(`Class ${b.class_year}`);
      if (b.hometown) facts.push(`Hometown ${b.hometown}`);
      if (facts.length) signals.push(`  ${facts.join(' · ')}`);
      if (b.bio_text) signals.push(`  Bio: ${b.bio_text.slice(0, 1500)}`);
    } else if (sr.player_record) {
      const pr = sr.player_record;
      const facts = [];
      if (pr.position) facts.push(`Position ${pr.position}`);
      if (pr.class_year) facts.push(`Class ${pr.class_year}`);
      if (pr.height) facts.push(`Height ${pr.height}`);
      if (pr.hometown) facts.push(`Hometown ${pr.hometown}`);
      if (pr.previous_school) facts.push(`Previous school ${pr.previous_school}`);
      if (facts.length) signals.push(`  ${facts.join(' · ')}`);
    }
  }

  const srRef = ctx.sourceResults?.sports_reference;
  if (srRef && !srRef.error) {
    if (srRef.career_stats) {
      signals.push(`SPORTS REFERENCE: ${srRef.name || ctx.playerName} — ${srRef.school || ''} ${srRef.position || ''} — career_stats: ${JSON.stringify(srRef.career_stats).slice(0, 300)}`);
    } else if (srRef.name) {
      signals.push(`SPORTS REFERENCE: profile exists for ${srRef.name}, stats not extracted (likely current freshman or first-season transfer).`);
    }
  }

  const c247 = ctx.composite247 || ctx.sourceResults?.composite_247;
  if (c247 && c247.composite_rank) {
    signals.push(`247SPORTS: composite rank ${c247.composite_rank}${c247.stars ? `, ${c247.stars}-star` : ''}${c247.position ? `, position ${c247.position}` : ''}.`);
  }

  const utr = ctx.sourceResults?.utr;
  if (utr && utr.utr) signals.push(`UTR: ${utr.utr}`);

  const nil = ctx.sourceResults?.nil;
  if (nil && nil.deals_disclosed > 0) signals.push(`NIL: ${nil.deals_disclosed} disclosed deals.`);

  // Recent news mentions of this player from the catalyst corpus
  if (ctx.recentNewsMentions && ctx.recentNewsMentions.length > 0) {
    signals.push(`RECENT NEWS (last 30 days, ${ctx.recentNewsMentions.length} mentions):`);
    ctx.recentNewsMentions.slice(0, 6).forEach(m => {
      signals.push(`  ${m.captured_at?.slice(0, 10) || ''} [${m.source_label || ''}] ${(m.summary || '').slice(0, 200)}`);
    });
  }

  const trajectoryText = ctx.trajectoryDelta && ctx.trajectoryDelta.confidence !== 'insufficient_data'
    ? `TRAJECTORY DELTA: ${ctx.trajectoryDelta.delta >= 0 ? '+' : ''}${ctx.trajectoryDelta.delta} — ${ctx.trajectoryDelta.interpretation}`
    : null;
  if (trajectoryText) signals.push(trajectoryText);

  const haveSignal = signals.length > 0;

  // v0.30.3: Sport-aware pronoun guidance
  const narrSport = (ctx.sport || '').toLowerCase();
  const narrIsWomens = narrSport.startsWith('womens-') || narrSport.includes('women');
  const narrIsMens = narrSport.startsWith('mens-') || narrSport === 'football' || narrSport === 'baseball';
  const narrPronouns = narrIsWomens
    ? `\n═══ PRONOUN DIRECTIVE ═══\nWomen's sport. The player is female. Use she/her/hers throughout. Never he/him/his.\n`
    : narrIsMens
    ? `\n═══ PRONOUN DIRECTIVE ═══\nMen's sport. Use he/him/his.\n`
    : `\n═══ PRONOUN DIRECTIVE ═══\nGender unspecified. Use neutral language ("the player", "they").\n`;

  const prompt = `You are FieldCheck — an independent scouting analyst for college ${sportLabel}. You write dossiers on players that coaches and parents use to make real decisions. Your reputation depends on honesty: you write what you actually know, you never fabricate stats or quotes, and your "take" is what an experienced scout would tell a friend over coffee. No recruiting-service marketing language.
${narrPronouns}
Player: ${ctx.playerName}
Sport: ${sportLabel}
Provided verdict tier: ${ctx.verdict}
Foundation: ${ctx.foundation?.tier || 'unknown'} (${ctx.foundation?.signal_count || 0} signal-bearing sources)

═══ SIGNALS WE HAVE ═══
${haveSignal ? signals.join('\n') : '(No signals returned from any data source for this player.)'}

═══ YOUR TASK ═══
Output ONLY valid JSON. No preamble. No markdown fences.

{
  "identity": "2-3 sentences. Who is this player. School, position, height, hometown, transfer story if any. Lead with the most identifying fact. If we don't have a position or school confirmed, say so honestly: 'We could not confirm this player against any of our 11 data sources. Likely candidates if you meant a different spelling: ...' Use ONLY facts from the signals provided.",
  "trajectory": "2-3 sentences on career arc. Where did they come from, where are they now, what is the inflection point. If they're a transfer, note both schools and what changed. If we have no career data, say so plainly and offer the next-best framing (e.g., 'incoming freshman from a 4-star high school class with no college reps yet').",
  "fit": "2-3 sentences on the school/coach/scheme fit. If we have culture data on the program, use it. If not, ground in the public-knowledge style of the program (e.g., LSU under Brian Kelly historically prioritizes X). Be specific. Don't invent quotes from coaches.",
  "take": "3-4 sentences. The scout's actual opinion. This is FieldCheck's call. Honest, not hedged. If the data is thin, the take should be 'we can't form a strong take yet; here's what we'd need to see to move off the fence.' If the data is strong, the take is direct: 'this is a buy / this is a fade / verify these specific things first.' Reference the verdict tier (${ctx.verdict}) and explain why.",
  "watchlist": [
    "3-5 specific, actionable bullets. Each starts with a trigger and an action. e.g., 'If he starts in season opener → upgrade to REASONABLE_ADD.' / 'If he's third on depth chart by August → downgrade to WALK_AWAY.' / 'If position coach changes → re-evaluate fit entirely.' Make these things a coach can actually monitor."
  ],
  "honest_unknowns": [
    "1-3 short bullets. What we don't know that would change the verdict. e.g., 'Spring practice reports not yet ingested.' / 'No PFF grade data integrated for FBS yet.' Be specific about gaps."
  ]
}

ABSOLUTE RULES:
- Never invent stats, quotes, rankings, or biographical facts not in the signals.
- If the signals are empty, the dossier should say so honestly. Don't fill it with generic platitudes.
- Tone: spare, direct, scout-not-publicist. No "exciting prospect," no "promising future," no marketing fluff.
- The "take" is the most important field. It is FieldCheck's actual opinion. Make it count.`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-5-20250929',
        max_tokens: 1500,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!r.ok) {
      const errBody = await r.text();
      return { error: 'anthropic_' + r.status, detail: errBody.slice(0, 200) };
    }
    const data = await r.json();
    const responseText = data.content?.[0]?.text || '';
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { error: 'no_json_in_dossier_response' };
    try {
      return JSON.parse(jsonMatch[0]);
    } catch (e) {
      return { error: 'dossier_json_parse_failed', raw: responseText.slice(0, 400) };
    }
  } catch (e) {
    return { error: 'dossier_request_failed', detail: String(e).slice(0, 200) };
  }
}

// Helper: pull catalysts from KV/D1 that mention a player by name token
async function findRecentNewsMentions(env, playerName) {
  if (!playerName) return [];
  const tokens = playerName.toLowerCase().split(/\s+/).filter(t => t.length >= 3);
  if (tokens.length === 0) return [];
  try {
    const rows = await dbAll(env,
      `SELECT id, source_label, captured_at, type, sentiment, summary, confidence
       FROM sport_catalysts
       WHERE expires_at > ?
       ORDER BY captured_at DESC LIMIT 100`,
      [new Date().toISOString()]
    );
    const all = rows.results || [];
    return all.filter(r => {
      const blob = (r.summary || '').toLowerCase();
      return tokens.every(t => blob.includes(t));
    }).slice(0, 8);
  } catch (e) {
    return [];
  }
}

async function generatePlayerNarrative(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) return 'Narrative requires ANTHROPIC_API_KEY.';

  // Insufficient-data narratives — we tell the truth instead of forcing a verdict
  if (ctx.foundation && ctx.foundation.tier === 'insufficient') {
    const knownSourcesText = Object.entries(ctx.sourceResults || {})
      .filter(([k, v]) => v && !v.error)
      .map(([k]) => k.replace(/_/g, ' '))
      .join(', ') || 'none';
    return `**Insufficient data for verdict.** We could not establish a strong-enough data foundation on ${ctx.playerName} in our current sources. ${knownSourcesText !== 'none' ? `Sources reachable: ${knownSourcesText}, but signal density is below threshold.` : 'No source returned signal-bearing data.'}\n\n**This is the integrity move.** Other tools in this category fake confidence on athletes they don't have data on. We refuse to. A coach showing this verdict to an athletic director is showing exactly what we know and don't know.\n\n**To upgrade the verdict:** paste a UTR profile URL (tennis), a Sports Reference player URL, or a school athletics roster URL. The resolver will re-run with the additional sources and produce a real verdict.`;
  }

  const sportLabel = SPORTS[ctx.sport]?.label || ctx.sport;

  // CONFIRMED FACTS — what we actually know (don't let Claude hallucinate around these)
  const confirmedFacts = [];
  const sr = ctx.sourceResults?.school_roster;
  if (sr && sr.roster_confirmed) {
    confirmedFacts.push(`✓ ${ctx.playerName} is confirmed on the official ${sr.school} ${sr.detected_program || sr.sport} varsity roster (verified at ${sr.source_url}).`);
    if (sr.player_record) {
      const pr = sr.player_record;
      const facts = [];
      if (pr.position) facts.push(`position ${pr.position}`);
      if (pr.class_year) facts.push(`class ${pr.class_year}`);
      if (pr.height) facts.push(`height ${pr.height}`);
      if (pr.hometown) facts.push(`hometown ${pr.hometown}`);
      if (pr.previous_school) facts.push(`previous school ${pr.previous_school}`);
      if (facts.length) confirmedFacts.push(`✓ Roster record: ${facts.join(', ')}.`);
    }
  }
  const srRef = ctx.sourceResults?.sports_reference || ctx.sportsRef;
  if (srRef && srRef.career_stats && Object.keys(srRef.career_stats).length > 0) {
    confirmedFacts.push(`✓ Sports Reference career stats available: ${JSON.stringify(srRef.career_stats).slice(0, 200)}.`);
  } else if (srRef && srRef.name) {
    confirmedFacts.push(`⚠ Sports Reference has a profile page for ${srRef.name} but career stats parsing returned empty (common for current freshmen whose page structure differs from career-veterans).`);
  }
  const c247 = ctx.composite247 || ctx.sourceResults?.composite_247;
  if (c247 && c247.composite_rank) {
    confirmedFacts.push(`✓ 247Sports composite rank: ${c247.composite_rank}${c247.stars ? `, ${c247.stars}-star` : ''}.`);
  }
  const utr = ctx.sourceResults?.utr;
  if (utr && utr.utr) {
    confirmedFacts.push(`✓ UTR rating: ${utr.utr}.`);
  }
  const nil = ctx.sourceResults?.nil;
  if (nil && nil.deals_disclosed > 0) {
    confirmedFacts.push(`✓ NIL disclosures: ${nil.deals_disclosed} deal(s) on file.`);
  }

  const trajectoryText = ctx.trajectoryDelta && ctx.trajectoryDelta.confidence !== 'insufficient_data'
    ? `Trajectory Delta: ${ctx.trajectoryDelta.delta >= 0 ? '+' : ''}${ctx.trajectoryDelta.delta} — ${ctx.trajectoryDelta.interpretation}`
    : 'Trajectory Delta: not computable (career stats not extracted).';

  const prompt = `You are an analyst writing a 3-paragraph verdict summary for a college ${sportLabel} player evaluation.

═══════════════════════════════════════════
CONFIRMED FACTS — these are verified. DO NOT contradict them or claim we lack them.
═══════════════════════════════════════════
${confirmedFacts.length > 0 ? confirmedFacts.join('\n') : '(No facts confirmed yet — narrative should reflect this honestly.)'}

═══════════════════════════════════════════
SCORES & VERDICT
═══════════════════════════════════════════
Player: ${ctx.playerName}
Sport: ${sportLabel}
Verdict: ${ctx.verdict}
Foundation tier: ${ctx.foundation?.tier || 'unknown'} (${ctx.foundation?.signal_count || 0} signal-bearing sources)
Scores (1-10): ${JSON.stringify(ctx.scores)}
${trajectoryText}

═══════════════════════════════════════════
WRITING RULES
═══════════════════════════════════════════
1. NEVER claim a fact we don't know AND NEVER deny a fact in the CONFIRMED FACTS list.
   Example: if the facts say "confirmed on Duke roster," do not write "we cannot confirm what school he plays for."
2. If career stats are missing but roster is confirmed, the correct framing is:
   "Roster confirmed at [school], but career stats not yet available in our data sources — verdict reflects this gap."
3. The verdict reflects what we KNOW, scaled by what we CAN'T verify yet. State both clearly.
4. Voice: direct, no clichés, no hype. We protect coaches from misrepresentation. We are not selling them on prospects.

═══════════════════════════════════════════
WRITE 3 PARAGRAPHS
═══════════════════════════════════════════
1. The verdict and what drives it — citing CONFIRMED FACTS, not absences.
2. The single most important data point or gap that shaped the verdict.
3. What would change the verdict (specific data improvement).`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify({ model: 'claude-sonnet-4-5-20250929', max_tokens: 800, messages: [{ role: 'user', content: prompt }] })
    });
    if (!r.ok) { const body = await r.text(); return 'Narrative generation failed (HTTP ' + r.status + '): ' + body.slice(0, 250); }
    const data = await r.json();
    return data.content?.[0]?.text || '';
  } catch (e) { return 'Narrative generation error: ' + String(e).slice(0, 100); }
}

async function generateProgramNarrative(env, ctx) {
  if (!env.ANTHROPIC_API_KEY) return 'Narrative requires ANTHROPIC_API_KEY.';

  // v0.29: Marquee programs with rich profiles never show "insufficient" — even if NCAA scrapers fail
  if (!ctx.profile && ctx.foundation && ctx.foundation.tier === 'insufficient') {
    return `**Insufficient data for program verdict.** ${ctx.programName} is not yet in our marquee program coverage set or returned thin source data. We refuse to fake a verdict on a program we don't have honest data on.\n\n**To upgrade:** future versions expand hardcoded marquee data to full conference-wide D1 coverage across all six sports. Today, program coverage is concentrated on a curated marquee set published in Trust Ratings. For other programs, the verdict is honestly suspended.\n\n**Coverage roadmap published at /trust.**`;
  }

  const sportLabel = SPORTS[ctx.sport]?.label || ctx.sport;

  // CONFIRMED FACTS — what we actually know about this program
  const confirmedFacts = [];

  // v0.29: Marquee profile facts come first (they're the bedrock)
  if (ctx.profile) {
    const p = ctx.profile;
    const t = p.tradition || {};
    const titleCount = (t.national_titles || []).length || t.national_titles_count || 0;
    if (titleCount > 0) {
      const recentList = (t.national_titles || []).slice(-3).map(x => x.year).join(', ');
      confirmedFacts.push(`✓ ${titleCount} national championship${titleCount === 1 ? '' : 's'}${recentList ? ' (most recent: ' + recentList + ')' : ''}.`);
    }
    if ((t.heisman_winners || []).length > 0) {
      confirmedFacts.push(`✓ ${t.heisman_winners.length} Heisman Trophy winner${t.heisman_winners.length === 1 ? '' : 's'}.`);
    }
    const np = p.nfl_pipeline || p.pro_pipeline || {};
    if (np.total_drafted_all_time) {
      confirmedFacts.push(`✓ ${np.total_drafted_all_time} all-time pro draft picks${np.first_round_picks_all_time ? ' (' + np.first_round_picks_all_time + ' first-rounders)' : ''}${np.current_nfl_roster_count_2024 ? ', ' + np.current_nfl_roster_count_2024 + ' currently on NFL rosters' : ''}.`);
    }
    if (np.ranking_note) confirmedFacts.push(`✓ ${np.ranking_note}`);
    const current = (p.coach_lineage || []).find(c => c.current);
    if (current) confirmedFacts.push(`✓ Current head coach: ${current.name} (${current.years || ''}).`);
    if (p.nil) {
      const mid = ((p.nil.annual_spend_estimate_low || 0) + (p.nil.annual_spend_estimate_high || 0)) / 2;
      if (mid > 0) confirmedFacts.push(`✓ NIL collective: ${p.nil.collective_name || 'unnamed'} — $${(mid/1000000).toFixed(0)}M annual spend midpoint estimate.`);
    }
    if (p.stadium && p.stadium.name) {
      confirmedFacts.push(`✓ Plays at ${p.stadium.name}${p.stadium.nickname ? ' ("' + p.stadium.nickname + '")' : ''}, capacity ${(p.stadium.capacity || 0).toLocaleString()}.`);
    }
  }

  if (ctx.apr) {
    if (ctx.apr.apr || ctx.apr.four_year_avg) {
      confirmedFacts.push(`✓ NCAA APR: ${ctx.apr.apr || '—'} (4-year average ${ctx.apr.four_year_avg || '—'}).`);
    }
  }
  if (ctx.infractions && ctx.infractions.cases) {
    if (ctx.infractions.cases.length === 0) {
      confirmedFacts.push(`✓ NCAA Infractions: zero cases on file in queried window.`);
    } else {
      confirmedFacts.push(`⚠ NCAA Infractions: ${ctx.infractions.cases.length} case(s) on file.`);
    }
  }
  if (ctx.transferData && ctx.transferData.data) {
    const td = ctx.transferData.data;
    if (td.retention_pct) confirmedFacts.push(`✓ Roster retention: ${td.retention_pct}%.`);
    if (td.in_count !== undefined && td.out_count !== undefined) {
      confirmedFacts.push(`✓ Transfer flow: ${td.in_count} in, ${td.out_count} out.`);
    }
  }
  if (ctx.cultureProfile && ctx.cultureProfile.profile) {
    const cp = ctx.cultureProfile.profile;
    confirmedFacts.push(`✓ Coach Culture Engine ran (${ctx.cultureProfile.confidence} confidence): ${cp.summary || cp.player_treatment_signal}.`);
    if (cp.delivery_alignment) confirmedFacts.push(`✓ Promise-vs-delivery alignment: ${cp.delivery_alignment}.`);
  }

  const prompt = `You are an analyst writing a 3-paragraph verdict summary for a college ${sportLabel} program evaluation, FOR a player or parent considering committing.

═══════════════════════════════════════════
CONFIRMED FACTS — these are verified. DO NOT contradict them or claim we lack them.
═══════════════════════════════════════════
${confirmedFacts.length > 0 ? confirmedFacts.join('\n') : '(No facts confirmed yet — narrative should reflect this honestly.)'}

═══════════════════════════════════════════
SCORES & VERDICT
═══════════════════════════════════════════
Program: ${ctx.programName}
Sport: ${sportLabel}
Verdict: ${ctx.verdict}
Foundation tier: ${ctx.foundation?.tier || 'unknown'}
Scores (1-10): ${JSON.stringify(ctx.scores)}

═══════════════════════════════════════════
WRITING RULES
═══════════════════════════════════════════
1. NEVER claim a fact we don't know AND NEVER deny a fact in the CONFIRMED FACTS list.
2. The verdict reflects what we KNOW about how this program treats players, not just won-loss records.
3. Voice: direct, integrity-first. Default tone is "walk away unless given a reason to commit." We protect the player/family, not the program's PR.

═══════════════════════════════════════════
WRITE 3 PARAGRAPHS
═══════════════════════════════════════════
1. The verdict in plain language and what drives it. Reference Coach Culture Profile if available.
2. The single most important data point that informed the verdict, sourced.
3. What would change the verdict.`;

  try {
    const r = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'x-api-key': env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: JSON.stringify({ model: 'claude-sonnet-4-5-20250929', max_tokens: 800, messages: [{ role: 'user', content: prompt }] })
    });
    if (!r.ok) { const body = await r.text(); return 'Narrative generation failed (HTTP ' + r.status + '): ' + body.slice(0, 250); }
    const data = await r.json();
    return data.content?.[0]?.text || '';
  } catch (e) { return 'Narrative generation error: ' + String(e).slice(0, 100); }
}


