  'sporting news first team all-american':   { tier: 'SELECTOR_AA_1ST', weight: 6.5, sport: 'all' },
  'baseball america first team all-american':{ tier: 'SELECTOR_AA_1ST', weight: 7.5, sport: 'baseball' },
  'ncbwa first team all-american':           { tier: 'SELECTOR_AA_1ST', weight: 7.5, sport: 'baseball' },
  // ─── CONFERENCE ───
  'sec player of the year':                  { tier: 'CONFERENCE_POY', weight: 7.0, sport: 'all' },
  'big ten player of the year':              { tier: 'CONFERENCE_POY', weight: 7.0, sport: 'all' },
  'acc player of the year':                  { tier: 'CONFERENCE_POY', weight: 6.5, sport: 'all' },
