  // ─── RECRUIT RANKING ───
  '#1 overall recruit':                      { tier: 'RECRUIT_NATIONAL_TOP1', weight: 7.0, sport: 'all' },
  'top-10 overall recruit':                  { tier: 'RECRUIT_NATIONAL_TOP10', weight: 6.0, sport: 'all' },
  'top-50 overall recruit':                  { tier: 'RECRUIT_NATIONAL_TOP50', weight: 5.0, sport: 'all' },
  'top-100 overall recruit':                 { tier: 'RECRUIT_NATIONAL_TOP100', weight: 4.5, sport: 'all' },
