function getCoachQuoteAnchor(coachName) {
  if (!coachName) return null;
  // Normalize: lowercase, remove diacritics, collapse spaces to hyphens
  const key = String(coachName).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  if (COACH_QUOTE_ANCHORS[key]) return { ...COACH_QUOTE_ANCHORS[key], slug: key };
  // Loose match: try just the last name
  const lastName = key.split('-').pop();
  for (const slug of Object.keys(COACH_QUOTE_ANCHORS)) {
    if (slug.endsWith('-' + lastName)) return { ...COACH_QUOTE_ANCHORS[slug], slug };
  }
  return null;
}

function listCoachQuoteAnchors() {
  return {
    schema_version: COACH_QUOTE_LIBRARY_VERSION,
    total: Object.keys(COACH_QUOTE_ANCHORS).length,
    coaches: Object.entries(COACH_QUOTE_ANCHORS).map(([slug, c]) => ({
      slug, sport: c.sport, program: c.program, role: c.role, quote_count: c.quotes.length
    }))
  };
}


//
// The moat is the curated DB. Honest moat-building means publishing what
// we have AND what we don't have. This module surfaces the curation
// depth per sport — so a user running a verdict for, say, men's soccer
// (which we haven't deeply curated yet) sees: "Light coverage. Verdict
// derived from public data; no curated marquee profile yet."
//
// That's the opposite of how most rating products work (claim coverage
// you don't have). Surfacing the gap is the trust amplifier.
// ════════════════════════════════════════════════════════════════════════

const COVERAGE_VERSION = '1.0';

const CURATED_COVERAGE = {
  'womens-volleyball':   { tier: 'deep',  rationale: 'Most-curated sport. 14 marquee profiles (Nebraska, LOVB Pro, Olympic pathway). LOVB integration is sport-exclusive.' },
  'football':            { tier: 'broad', rationale: '15 marquee profiles (QBs, skill, EDGE, safety). NFL Round 1-3 projection coverage strong. Mid-major and Group of 5 still light.' },
  'mens-basketball':     { tier: 'broad', rationale: '15 marquee profiles (lottery picks, NCAA POYs). NBA Lottery / Round 1 projection coverage strong.' },
  'baseball':            { tier: 'targeted', rationale: '10 marquee profiles (Top-10 MLB Draft + reigning college POYs). Pitcher + position-player parity. Below-Round-1 coverage is lighter.' },
  'womens-basketball':   { tier: 'targeted', rationale: '10 marquee profiles (Naismith POY tier + NCAA Final Four leaders). WNBA Top-10 coverage strong.' },
  'mens-volleyball':     { tier: 'light', rationale: 'No hand-curated marquee profiles yet. Verdicts will derive from public roster + Wikipedia + school athletics only. Curated coverage scheduled for the next data sprint.' },
  'mens-soccer':         { tier: 'light', rationale: 'No hand-curated marquee profiles yet. NCAA men\'s soccer coverage is on the roadmap; current verdicts derive from public data only.' },
  'tennis':              { tier: 'light', rationale: 'No hand-curated marquee profiles yet. NCAA tennis is a niche curation track; current verdicts derive from public ranking data and school rosters.' }
};

function getCuratedCoverage(sport) {
  const sportN = String(sport || '').toLowerCase();
  const cov = CURATED_COVERAGE[sportN];
  if (!cov) {
    return {
      schema_version: COVERAGE_VERSION,
      sport: sportN,
      tier: 'unknown',
      profile_count: 0,
      rationale: 'Sport not in coverage registry. Verdict may proceed with public-data-only depth.'
    };
  }

  // Count curated profiles for this sport from PLAYER_PROFILES
  let count = 0;
  for (const slug of Object.keys(PLAYER_PROFILES || {})) {
    if (PLAYER_PROFILES[slug] && PLAYER_PROFILES[slug].sport === sportN) count++;
  }

  return {
    schema_version: COVERAGE_VERSION,
    sport: sportN,
    tier: cov.tier,
    profile_count: count,
    rationale: cov.rationale,
    last_verified: '2026-05-16',
    notes: cov.tier === 'light'
      ? 'Public-data fallback only. The verdict will be sourced and audited but will not carry curated-DB confidence.'
      : cov.tier === 'targeted'
      ? 'Targeted curation — top-tier names well-covered, lower-tier names lean on public-data fallback.'
      : cov.tier === 'broad'
      ? 'Broad curation — most marquee names covered with full eval-grid + awards + pro projection.'
      : 'Deep curation — the moat sport. Sport-specific eval pillars and pathway data.'
  };
}

function listAllCoverage() {
  // v0.30.5.179: compute photo coverage per sport + overall, surface alongside depth tier.
  const profiles = PLAYER_PROFILES || {};
  const photoStatsBySport = {};
  let totalProfiles = 0;
  let totalWithPhoto = 0;
  for (const slug of Object.keys(profiles)) {
    const p = profiles[slug];
    if (!p || !p.sport) continue;
    photoStatsBySport[p.sport] = photoStatsBySport[p.sport] || { total: 0, with_photo: 0 };
    photoStatsBySport[p.sport].total++;
    totalProfiles++;
    if (p.photo_url) {
      photoStatsBySport[p.sport].with_photo++;
      totalWithPhoto++;
    }
  }

  const sports = Object.keys(CURATED_COVERAGE).map(s => {
    const base = getCuratedCoverage(s);
    const ps = photoStatsBySport[s] || { total: 0, with_photo: 0 };
    return {
      ...base,
      photo_coverage: {
        total: ps.total,
        with_photo: ps.with_photo,
        pct: ps.total > 0 ? Math.round((ps.with_photo / ps.total) * 1000) / 10 : 0
      }
    };
  });

  return {
    schema_version: COVERAGE_VERSION,
    sports,
    overall_photo_coverage: {
      total: totalProfiles,
      with_photo: totalWithPhoto,
      pct: totalProfiles > 0 ? Math.round((totalWithPhoto / totalProfiles) * 1000) / 10 : 0
    },
    pledge: 'We publish what we have AND what we don\'t. No moat theater.',
    last_verified: '2026-05-21'
  };
}


