// v0.20: computeCompPlayers — find 3-5 verified-outcome players
// matching the input profile. For volleyball, matches against LOVB roster.
// Honest: only returns comps where we have verified outcomes.
// Future: outcome-corpus ML expands this to all sports.
// ════════════════════════════════════════════════════════════
function computeCompPlayers(ctx) {
  const { sport, position, school } = ctx || {};

  // Volleyball uses the verified LOVB roster (real outcome corpus).
  if (sport === 'womens-volleyball') {
    return computeCompPlayersVolleyball(position, school);
  }

  // v0.22: Other sports use curated public-record pathway examples.
  const curated = getCuratedPathwayComps(sport, position);
  return {
    comps: curated.comps,
    sport,
    position: position || 'all',
    school_filter: school || null,
    methodology: 'curated_examples_v1',
    note: curated.note,
    honest_caveats: [
      'These are well-known publicly-verified college-to-pro pathway examples.',
      'Not statistical ML comp matching — that ships as outcome corpora map per sport.',
      'Comps are illustrative — your path is your own.',
      'Volleyball comp library is verified against LOVB Pro inaugural roster (different methodology).'
    ]
  };
}

// ════════════════════════════════════════════════════════════
// v0.22: NIL Estimator — rules-based valuation projection
// Combines: school tier × position scarcity × performance × pro pathway × social proxy
// Honest framing: estimated RANGE, not actual deal data. Helps athletes and
// families understand what they're worth in the public NIL market AND what
// levers they can pull to grow it.
// ════════════════════════════════════════════════════════════

// School NIL-tier multipliers (rough public-market proxy)
const SCHOOL_NIL_TIER = {
  // Top NIL collectives + national-brand programs
  'tier_1': 1.6, // Texas, Ohio State, Alabama, Michigan, Georgia, USC, Notre Dame, LSU, Tennessee
  'tier_2': 1.2, // Power 5 with strong NIL infrastructure
  'tier_3': 0.85, // Power 5 mid-tier
  'tier_4': 0.55, // Group of 5 / mid-major
  'tier_5': 0.30  // FCS / non-football D1 below mid-major
};

const TIER_1_SCHOOLS = ['Texas', 'Ohio State', 'Alabama', 'Michigan', 'Georgia', 'USC', 'Notre Dame', 'LSU', 'Tennessee', 'Oregon', 'Florida', 'Oklahoma', 'Penn State', 'Auburn', 'Texas A&M', 'Miami'];
const TIER_2_SCHOOLS = ['Stanford', 'UCLA', 'Wisconsin', 'Iowa', 'Nebraska', 'Florida State', 'Clemson', 'Washington', 'Michigan State', 'Arkansas', 'Mississippi', 'Mississippi State', 'South Carolina', 'NC State', 'Virginia Tech', 'Pittsburgh', 'Maryland', 'Indiana', 'Illinois', 'Minnesota', 'Purdue', 'Northwestern', 'Boston College', 'Wake Forest', 'Duke', 'North Carolina', 'Kansas', 'Kansas State', 'Iowa State', 'Texas Tech', 'TCU', 'Baylor', 'Oklahoma State', 'BYU', 'Utah', 'Arizona', 'Arizona State', 'Cincinnati', 'UCF', 'Houston', 'West Virginia', 'Kentucky', 'Vanderbilt'];

function getSchoolNILTier(school) {
  if (!school) return 'tier_4';
  const s = school.toString();
  if (TIER_1_SCHOOLS.some(t => s.includes(t))) return 'tier_1';
  if (TIER_2_SCHOOLS.some(t => s.includes(t))) return 'tier_2';
  if (s.match(/State|University/)) return 'tier_3';
  return 'tier_4';
}

// Sport NIL economics — base annual NIL valuation midpoint per tier
const SPORT_NIL_BASE = {
  'football': {
    base: 50000, // mid-tier starter baseline
    star_player_floor: 350000, // high-profile starter QB/WR/RB
    superstar_floor: 1500000 // Heisman-tier players
  },
  'mens-basketball': {
    base: 75000,
    star_player_floor: 500000,
    superstar_floor: 2000000
  },
  'womens-basketball': {
    base: 25000,
    star_player_floor: 300000,
    superstar_floor: 3200000 // Caitlin Clark broke the ceiling
  },
  'baseball': {
    base: 8000,
    star_player_floor: 80000,
    superstar_floor: 250000
  },
  'mens-soccer': {
    base: 5000,
    star_player_floor: 40000,
    superstar_floor: 150000
  },
  'tennis': {
    base: 6000,
    star_player_floor: 50000,
    superstar_floor: 200000
  },
  'womens-volleyball': {
    base: 12000,
    star_player_floor: 80000, // top volleyball NIL deals (Olivia Babcock, etc) reaching 6 figures
    superstar_floor: 350000
  },
  'mens-volleyball': {
    base: 4000,
    star_player_floor: 25000,
    superstar_floor: 75000
  }
};

// Premium positions get a multiplier (scarcity-driven)
const POSITION_NIL_PREMIUM = {
  'QB': 1.8, 'Quarterback': 1.8,
  'WR': 1.3, 'Wide Receiver': 1.3,
  'RB': 1.2, 'Running Back': 1.2,
  'EDGE': 1.2, 'Edge': 1.2, 'DE': 1.15, 'Defensive End': 1.15,
  'CB': 1.15, 'Cornerback': 1.15,
  'PG': 1.4, 'Point Guard': 1.4, 'G': 1.3, 'Guard': 1.3,
  'C': 1.1, 'Center': 1.1,
  'P': 1.4, 'Pitcher': 1.4,
  'SS': 1.2, 'Shortstop': 1.2,
  'OH': 1.2, 'Outside Hitter': 1.2,
  'Setter': 1.15, 'S': 1.15,
  'Singles': 1.2,
  'F': 1.2, 'Forward': 1.2,
  'MF': 1.0, 'Midfielder': 1.0
};

function computeNILEstimate(ctx) {
  const { sport, school, position, evalGrid, lovbPathway, facts } = ctx || {};

  if (!sport) {
    return {
      error: 'missing_sport',
      note: 'NIL estimator requires sport at minimum.'
    };
  }

  const sportEcon = SPORT_NIL_BASE[sport];
  if (!sportEcon) {
    return {
      sport,
      estimated_low: null,
      estimated_high: null,
      tier: 'UNAVAILABLE',
      methodology: 'rules_based_v1',
      note: 'NIL estimator does not yet cover ' + sport + '. Volleyball, football, basketball, baseball, soccer, tennis are supported.'
    };
  }

  const schoolTier = getSchoolNILTier(school);
  const schoolMult = SCHOOL_NIL_TIER[schoolTier];
  const positionMult = position ? (POSITION_NIL_PREMIUM[position] || 1.0) : 1.0;

  const composite = evalGrid?.overall_grade?.composite;
  const performanceMult = composite != null
    ? Math.max(0.3, Math.min(2.5, (composite - 5.5) * 0.6 + 1.0)) // composite 7=1.9x, 5.5=1.0x, 8.5=2.8x capped 2.5
    : 1.0;

  // Pro pathway tier signal (pathway tier = future earning power signal)
  let pathwayMult = 1.0;
  if (lovbPathway) {
    if (lovbPathway.status === 'VERIFIED_LOVB') pathwayMult = 3.5; // already at the cut
    else if (lovbPathway.tier === 'ELITE_PROSPECT' || lovbPathway.tier === 'LOTTERY' || lovbPathway.tier === 'TOP_PICK' || lovbPathway.tier === 'TOP_100' || lovbPathway.tier === 'ATP_WTA_TOUR' || lovbPathway.tier === 'HIGH_PROBABILITY') pathwayMult = 2.5;
    else if (lovbPathway.tier === 'DRAFTABLE' || lovbPathway.tier === 'FIRST_ROUND' || lovbPathway.tier === 'EARLY_ROUNDS' || lovbPathway.tier === 'CHALLENGER_LEVEL' || lovbPathway.tier === 'WATCH' || lovbPathway.tier === 'MLS_FIRST_TEAM') pathwayMult = 1.8;
    else if (lovbPathway.tier === 'SECOND_ROUND' || lovbPathway.tier === 'UDFA_CAMP' || lovbPathway.tier === 'SECOND_THIRD_ROUND' || lovbPathway.tier === 'MID_LATE_ROUNDS' || lovbPathway.tier === 'ITF_FUTURES' || lovbPathway.tier === 'MLS_DRAFT_EARLY') pathwayMult = 1.3;
  }

  const baseEstimate = sportEcon.base * schoolMult * positionMult * performanceMult * pathwayMult;
  // Range: ±35% to be honest about uncertainty
  let estimatedLow = Math.round(baseEstimate * 0.65 / 100) * 100;
  let estimatedHigh = Math.round(baseEstimate * 1.35 / 100) * 100;

  // Ceiling-floor at superstar / star player thresholds for known elite tiers
  if (lovbPathway?.status === 'VERIFIED_LOVB') {
    estimatedLow = Math.max(estimatedLow, sportEcon.star_player_floor);
    estimatedHigh = Math.max(estimatedHigh, sportEcon.superstar_floor);
  } else if (composite != null && composite >= 9.0) {
    estimatedLow = Math.max(estimatedLow, sportEcon.star_player_floor);
  }

  // Tier classification for display
  const midpoint = (estimatedLow + estimatedHigh) / 2;
  let tier, tier_label;
  if (midpoint >= sportEcon.superstar_floor) { tier = 'SUPERSTAR'; tier_label = 'Superstar tier'; }
  else if (midpoint >= sportEcon.star_player_floor) { tier = 'STAR'; tier_label = 'Star tier'; }
  else if (midpoint >= sportEcon.base * 3) { tier = 'STARTER_PLUS'; tier_label = 'Starter-plus tier'; }
  else if (midpoint >= sportEcon.base) { tier = 'STARTER'; tier_label = 'Starter tier'; }
  else { tier = 'EMERGING'; tier_label = 'Emerging tier'; }

  // Levers — what moves the number
  const levers = [];
  if (composite != null && composite < 8.0) {
    levers.push({
      lever: 'Performance',
      current: composite + '/10 composite',
      action: 'Push composite to 8.0+ → ' + (Math.round(((8.0 - 5.5) * 0.6 + 1.0) / performanceMult * 100) - 100) + '% NIL multiplier increase'
    });
  }
  if (schoolTier === 'tier_3' || schoolTier === 'tier_4' || schoolTier === 'tier_5') {
    levers.push({
      lever: 'School tier',
      current: 'Tier ' + schoolTier.replace('tier_', ''),
      action: schoolTier === 'tier_4' || schoolTier === 'tier_5' ? 'Transfer portal to a tier-2/tier-1 program → 2-3x NIL multiplier' : 'Transfer to tier-1 SEC/Big Ten flagship → +30-40% NIL multiplier'
    });
  }
  if (lovbPathway && lovbPathway.status === 'PROJECTED' && (lovbPathway.tier === 'WATCH' || lovbPathway.tier === 'LONG_SHOT' || lovbPathway.tier === 'UDFA_CAMP' || lovbPathway.tier === 'SECOND_ROUND')) {
    levers.push({
      lever: 'Pro pathway tier',
      current: lovbPathway.tier.replace(/_/g, ' '),
      action: 'Climb a pathway tier → 30-50% NIL valuation multiplier (proves earning ceiling)'
    });
  }
  // Social/audience lever (always relevant in NIL)
  levers.push({
    lever: 'Social audience',
    current: 'Not yet measured',
    action: '10K+ Instagram followers → +15-25% NIL valuation. 50K+ → +40-80%. NIL is brand × performance.'
  });
  // Awards lever
  levers.push({
    lever: 'Recognition',
    current: 'Not yet measured',
    action: 'All-Conference recognition → +20-40% multiplier. All-American → 2-3x. Conference POY → 3-5x.'
  });

  return {
    sport,
    estimated_low: estimatedLow,
    estimated_high: estimatedHigh,
    estimated_midpoint: Math.round(midpoint / 100) * 100,
    tier,
    tier_label,
    methodology: 'rules_based_v1',
    composition: {
      base_for_sport: sportEcon.base,
      school_multiplier: { tier: schoolTier, multiplier: schoolMult },
      position_multiplier: position ? { position, multiplier: positionMult } : null,
      performance_multiplier: composite != null ? { composite, multiplier: Math.round(performanceMult * 100) / 100 } : null,
      pathway_multiplier: pathwayMult > 1.0 ? { tier: lovbPathway?.tier || 'verified_pro', multiplier: pathwayMult } : null
    },
    levers,
    honest_caveats: [
      'Rules-based v1 estimate — based on public-record proxies, not actual deal data.',
      'Real NIL deals depend heavily on social audience, agent quality, and market timing — only partially captured here.',
      'Range is ±35% to reflect real uncertainty in the public NIL market.',
      'School NIL collective strength varies year-to-year; ours is a rough proxy.',
      'Use this as a directional benchmark for negotiations, not a contract figure.'
    ]
  };
}

// ════════════════════════════════════════════════════════════
// v0.25: Calibrated NIL Estimator — applies live calibration data
// Wraps computeNILEstimate; pulls calibration multipliers from KV (refreshed
// nightly via /nil/recalibrate). Returns calibrated estimate alongside raw.
// ════════════════════════════════════════════════════════════
async function computeNILEstimateCalibrated(env, ctx) {
  const raw = computeNILEstimate(ctx);
  if (!raw || raw.error || raw.estimated_low == null) return raw;

  // Fetch calibration data from KV
  let calibration = null;
  if (env && env.FIELDCHECK_KV) {
    try {
      calibration = await env.FIELDCHECK_KV.get('nil:calibration:current', 'json');
    } catch {}
  }

  if (!calibration || !calibration.calibration_by_sport || !calibration.calibration_by_sport[ctx.sport]) {
    // No calibration data yet — return raw with note
    return {
      ...raw,
      calibration_applied: false,
      calibration_note: 'No corpus data yet for ' + ctx.sport + '. Estimator using rules-based v1 baseline.'
    };
  }

  const sportCal = calibration.calibration_by_sport[ctx.sport];
  // Only apply if corpus is meaningful (10+ deals minimum)
  if (sportCal.corpus_size < 10) {
    return {
      ...raw,
      calibration_applied: false,
      calibration_note: 'Calibration corpus for ' + ctx.sport + ' is ' + sportCal.corpus_size + ' deals; need 10+ to apply.',
      calibration_pending: { corpus_size: sportCal.corpus_size, target_size: 10 }
    };
  }

  // Apply median ratio as multiplier (cap to prevent wild swings: 0.5x to 2.0x)
  const multiplier = Math.max(0.5, Math.min(2.0, sportCal.median_ratio));
  const calLow = Math.round(raw.estimated_low * multiplier / 100) * 100;
  const calHigh = Math.round(raw.estimated_high * multiplier / 100) * 100;
  const calMid = Math.round((calLow + calHigh) / 2 / 100) * 100;

  return {
    ...raw,
    raw_estimate: { low: raw.estimated_low, high: raw.estimated_high, midpoint: raw.estimated_midpoint },
    estimated_low: calLow,
    estimated_high: calHigh,
    estimated_midpoint: calMid,
    methodology: 'rules_based_v1_calibrated',
    calibration_applied: true,
    calibration_multiplier: Math.round(multiplier * 100) / 100,
    calibration_corpus_size: sportCal.corpus_size,
    calibration_note: 'Estimator calibrated from ' + sportCal.corpus_size + ' real ' + ctx.sport + ' NIL deals. Multiplier: ' + multiplier.toFixed(2) + 'x.',
    calibration_last_updated: calibration.computed_at
  };
}


// ════════════════════════════════════════════════════════════
// v0.22: NIL Fine-Tuning Advisor — what the player should DO
// to grow their NIL based on the gap between current and target tier
// ════════════════════════════════════════════════════════════
function generateNILFineTuningPlan(currentEstimate, targetTier) {
  if (!currentEstimate || !currentEstimate.sport) return null;

  const sportEcon = SPORT_NIL_BASE[currentEstimate.sport];
  if (!sportEcon) return null;

  // Map target to a numeric goal
  const targetMidpoint = {
    'STARTER': sportEcon.base,
    'STARTER_PLUS': sportEcon.base * 3,
    'STAR': sportEcon.star_player_floor,
    'SUPERSTAR': sportEcon.superstar_floor
  }[targetTier] || (currentEstimate.estimated_midpoint * 2);

  const currentMidpoint = currentEstimate.estimated_midpoint || 0;
  const gap = targetMidpoint - currentMidpoint;
  const multiplier_needed = currentMidpoint > 0 ? Math.round((targetMidpoint / currentMidpoint) * 10) / 10 : 'N/A';

  // Build action plan from levers
  const actions = currentEstimate.levers.map(l => ({
    lever: l.lever,
    current: l.current,
    do_this: l.action,
    estimated_impact: l.lever === 'Performance' ? '+30-50% NIL value' :
                      l.lever === 'School tier' ? '+50-200% NIL value (largest single lever)' :
                      l.lever === 'Pro pathway tier' ? '+30-80% NIL value' :
                      l.lever === 'Social audience' ? '+15-80% NIL value' :
                      l.lever === 'Recognition' ? '+20-200% NIL value (compounds with others)' : 'variable'
  }));

  // Sequencing — what to attack first
  const sequence = [
    { rank: 1, focus: 'Performance baseline', why: 'Without performance, no other lever matters. Composite 7.5+ is the gating signal.' },
    { rank: 2, focus: 'Recognition cascade', why: 'All-Conference → All-American → POY. Each tier unlocks NIL valuation jumps.' },
    { rank: 3, focus: 'Social audience build', why: 'Brand value compounds — 6-12 month lead time for audience to scale. Start now.' },
    { rank: 4, focus: 'Pro pathway proof', why: 'Pre-draft / combine / showcase performance signals earning ceiling to NIL collectives.' },
    { rank: 5, focus: 'School tier (if needed)', why: 'Transfer portal is the nuclear option. Use only if other levers maxed.' }
  ];

  return {
    target_tier: targetTier,
    current_tier: currentEstimate.tier,
    current_midpoint: currentMidpoint,
    target_midpoint: targetMidpoint,
    gap_dollar_amount: gap,
    multiplier_needed,
    actions,
    sequence,
    honest_caveats: [
      'Plans are directional — actual outcomes depend on execution, market timing, and luck.',
      'Most successful NIL athletes work multiple levers simultaneously over 12-24 months.',
      'Performance baseline is the only non-negotiable. Without it, everything else is moot.',
      'Social audience is the single most undervalued lever for non-football, non-basketball athletes.'
    ]
  };
}


function computeCompPlayersVolleyball(position, school) {
  const positionKey = position === 'Outside' ? 'OH' :
                      position === 'Middle' ? 'MB' :
                      position === 'Setter' ? 'S' :
                      position === 'Libero' ? 'L' :
                      position === 'Opposite' ? 'OPP' :
                      position;

  const matches = LOVB_ROSTER.filter(p => !positionKey || p.position === positionKey);
  const sortedMatches = matches.sort((a, b) => {
    if (school) {
      const aMatch = (a.college || '').toLowerCase().includes((school || '').toLowerCase());
      const bMatch = (b.college || '').toLowerCase().includes((school || '').toLowerCase());
      if (aMatch && !bMatch) return -1;
      if (!aMatch && bMatch) return 1;
    }
    if (a.olympian && !b.olympian) return -1;
    if (!a.olympian && b.olympian) return 1;
    return 0;
  });

  const comps = sortedMatches.slice(0, 5).map(p => ({
    name: p.name,
    college: p.college,
    pro_team: 'LOVB ' + p.team,
    position: p.position,
    olympian: !!p.olympian,
    pathway_one_liner: p.olympian
      ? `${p.college || 'College'} → 2024 Team USA Olympian → LOVB ${p.team}`
      : `${p.college || 'College'} → LOVB ${p.team} (inaugural 2025 season)`
  }));

  return {
    comps,
    sport: 'womens-volleyball',
    position: positionKey || 'all',
    school_filter: school || null,
    methodology: 'verified_outcomes_v1',
    note: comps.length === 0
      ? 'No same-position matches in current corpus. Try without position filter, or check back as the corpus grows.'
      : `${comps.length} verified pro pathway${comps.length === 1 ? '' : 's'} matched on position${school ? ' and school priority' : ''}. These players walked the path. Their college-to-LOVB transitions are public record.`,
    honest_caveats: [
      'Currently uses LOVB Pro inaugural roster (~46 players) as verified-outcome corpus.',
      'Comp algorithm matches on position first, then school overlap, then Olympian status.',
      'Eval-grid-aware comp matching (same physical/production tier) ships in v0.23 as the corpus grows.',
      'Other sports activate as outcome corpora map (AU Volleyball, NFL Combine, NBA G League, etc.).'
    ]
  };
}

