// ════════════════════════════════════════════════════════════
// v0.19: MakeTheCut score — rules-based v1
// Combines eval grid + position playbook + LOVB roster medians (when available)
// into a 0-100 likelihood with full explainability. Honest about being rules-based;
// ML upgrade ships when corpus reaches outcome-mapped scale.
// ════════════════════════════════════════════════════════════
function computeMakeTheCutScore(ctx) {
  const { evalGrid, sport, position, lovbPathway } = ctx || {};

  // Hard short-circuit for already-rostered players
  if (lovbPathway && lovbPathway.status === 'VERIFIED_LOVB') {
    return {
      score: 100,
      tier: 'AT_THE_CUT',
      tier_label: 'Already at the cut',
      methodology: 'rules_based_v1',
      explanation: 'Player is currently rostered on a LOVB Pro team. The cut has been made. Focus shifts to year-1 starting role and year-2 retention.',
      breakdown: {
        roster_status: { score: 100, weight: 1.0, signal: 'verified_lovb_roster' }
      },
      next_actions: [
        'Track year-1 starter role: minutes per set above league median',
        'Year-1 health gate: full training camp + first 5 matches',
        'Year-2 international offer monitoring (Italian Serie A1 retention risk)'
      ]
    };
  }

  // Need eval grid scores to project
  if (!evalGrid || !evalGrid.overall_grade) {
    return {
      score: null,
      tier: 'INSUFFICIENT_DATA',
      tier_label: 'Insufficient data',
      methodology: 'rules_based_v1',
      explanation: 'No eval grid scores on file. MakeTheCut projection requires production + physical scoring at minimum.',
      breakdown: {},
      next_actions: [
        'Run a FieldCheck verdict on this player to populate the eval grid',
        'Ensure school + sport are correct for accurate position playbook resolution'
      ]
    };
  }

  const og = evalGrid.overall_grade;
  const composite = og.composite;
  const production = og.production;
  const physical = og.physical;
  const projectability = og.projectability;

  // Base score from composite (0-100 from 0-10 grid)
  // 10/10 = 100, 5/10 = 50. Linear mapping plus position-adjusted bumps.
  let score = composite != null ? composite * 10 : null;
  const breakdown = {};
  const next_actions = [];

  if (composite != null) {
    breakdown.composite_grade = {
      score: Math.round(composite * 10),
      weight: 0.55,
      signal: `Eval grid composite ${composite}/10`,
      note: 'Base score from FieldCheck eval grid'
    };

    // Production weighting — most important for cut projection
    if (production != null) {
      const prodSignal = production >= 8.5 ? 'Elite production — at or above LOVB starter median'
                       : production >= 7.0 ? 'Strong production — within signing range'
                       : production >= 5.5 ? 'Solid D1 production — gap to close before cut'
                       : 'Production gap is the primary barrier';
      breakdown.production = {
        score: Math.round(production * 10),
        weight: 0.20,
        signal: prodSignal
      };
      // Apply production multiplier
      if (production >= 8.5) score = Math.min(100, score + 5);
      else if (production < 5.5 && score != null) score = Math.max(0, score - 8);
    }

    // Physical
    if (physical != null) {
      breakdown.physical = {
        score: Math.round(physical * 10),
        weight: 0.15,
        signal: physical >= 7.5 ? 'Physical profile within pro range' :
                physical >= 6.0 ? 'Physical profile at D1 starter range' :
                'Physical profile below typical pro thresholds'
      };
    }

    // Projectability — career arc, durability, character
    if (projectability != null) {
      breakdown.projectability = {
        score: Math.round(projectability * 10),
        weight: 0.10,
        signal: projectability >= 8.0 ? 'Strong trajectory + durability + character signals' :
                projectability >= 6.5 ? 'Trajectory is positive — needs sustained season' :
                'Trajectory needs the next-jump signal'
      };
    }
  }

  // v0.22: Multi-sport pathway tier bonuses for PROJECTED status.
  // Each sport's tier ladder maps to score adjustment.
  if (lovbPathway && lovbPathway.status === 'PROJECTED') {
    // Sport-specific tier-bonus maps. Higher tier = bigger positive adjustment.
    const tierBonusMap = {
      // Volleyball (LOVB)
      'HIGH_PROBABILITY': 8, 'WATCH': 0, 'LONG_SHOT': -8, 'UNLIKELY': -15,
      // Football (NFL)
      'ELITE_PROSPECT': 12, 'DRAFTABLE': 6, 'UDFA_CAMP': -3, 'DEVELOPMENTAL': -10,
      // Men's Basketball (NBA)
      'LOTTERY': 12, 'FIRST_ROUND': 8, 'SECOND_ROUND': 2, 'G_LEAGUE_TWO_WAY': -5, 'EUROLEAGUE_TRACK': -10,
      // Women's Basketball (WNBA)
      'TOP_PICK': 12, 'SECOND_THIRD_ROUND': 0, 'OVERSEAS_PRIMARY': -8,
      // Baseball (MLB)
      'TOP_100': 12, 'EARLY_ROUNDS': 6, 'MID_LATE_ROUNDS': 0, 'INDY_BALL': -10,
      // Soccer (MLS)
      'MLS_FIRST_TEAM': 10, 'MLS_DRAFT_EARLY': 5, 'MLS_NEXT_PRO': -2, 'USL_LEAGUE_ONE': -10,
      // Tennis (ATP/WTA)
      'ATP_WTA_TOUR': 12, 'CHALLENGER_LEVEL': 6, 'ITF_FUTURES': -2, 'TEACHING_PRO': -10,
      // Universal
      'INSUFFICIENT_DATA': 0, 'EARLY_LOOK': -5
    };
    const bonus = tierBonusMap[lovbPathway.tier] !== undefined ? tierBonusMap[lovbPathway.tier] : 0;
    if (score != null) {
      score = Math.max(0, Math.min(100, score + bonus));
      breakdown.pro_pathway = {
        score: Math.max(0, Math.min(100, 50 + bonus * 3)),
        weight: 0.10,
        signal: `Pro pathway tier: ${(lovbPathway.tier || '').replace(/_/g, ' ')} (${sport})`,
        adjustment: bonus > 0 ? `+${bonus} bonus for ${lovbPathway.tier} tier` :
                    bonus < 0 ? `${bonus} adjustment — composite below ${lovbPathway.tier} median` : 'Neutral'
      };
    }
  }

  // Verified-rostered short-circuit was for VERIFIED_LOVB at top of fn — that's volleyball-only.
  // Future: VERIFIED_NFL, VERIFIED_NBA etc. when we have current-roster lookups for each sport.

  // Round
  if (score != null) score = Math.round(score);

  // Tier classification
  let tier, tier_label;
  if (score == null) {
    tier = 'INSUFFICIENT_DATA';
    tier_label = 'Insufficient data';
  } else if (score >= 80) {
    tier = 'CUT_LIKELY';
    tier_label = 'On the cut path';
  } else if (score >= 65) {
    tier = 'BUILDING';
    tier_label = 'Building toward the cut';
  } else if (score >= 50) {
    tier = 'GAP_REAL';
    tier_label = 'Real gap to close';
  } else if (score >= 35) {
    tier = 'LONG_PATH';
    tier_label = 'Long path forward';
  } else {
    tier = 'EARLY_LOOK';
    tier_label = 'Very early look';
  }

  // Next actions based on tier + position
  if (score != null) {
    if (score >= 80) {
      next_actions.push('Maintain production through senior season — no regression');
      next_actions.push('Secure agent representation by senior spring');
      next_actions.push('Hit AVCA / All-American honors to lock in scout windows');
    } else if (score >= 65) {
      next_actions.push('Senior-year production jump is the next signal — target +0.5 K/S or +.030 hitting %');
      next_actions.push('Conference recognition (Player of the Year nomination) shifts tier');
      next_actions.push('NCAA tournament Sweet 16+ run with elevated personal stats');
    } else if (score >= 50) {
      next_actions.push('Production gap is the primary barrier — set position-specific stat targets');
      next_actions.push('Consider transfer to higher-major program for visibility (if mid-major)');
      next_actions.push('Olympic Trials / VNL camp invite is the elite differentiator');
    } else if (score >= 35) {
      next_actions.push('Athletes Unlimited Volleyball is a viable parallel — recruits at lower threshold');
      next_actions.push('European 2nd-tier (Italian A2, Turkish 1. Lig) realistic starting points');
      next_actions.push('Year-over-year stat improvement is the only path back into projection range');
    } else {
      next_actions.push('Significant year-over-year improvement needed before pro projection');
      next_actions.push('Focus on D1 starting role first; pro pipeline is later concern');
      next_actions.push('European 3rd-tier or domestic semi-pro may be near-term path');
    }
  }

  return {
    score,
    tier,
    tier_label,
    methodology: 'rules_based_v1',
    explanation: composite != null
      ? `Based on FieldCheck eval grid composite of ${composite}/10, with weighting by production (most predictive), physical profile, and projectability. ${lovbPathway && lovbPathway.status === 'PROJECTED' ? 'LOVB Pathway tier adjustment applied.' : ''} Honest framing: this is rules-based, not ML — accuracy is bounded by playbook calibration. ML projection ships when our outcome corpus reaches scale.`
      : 'No eval grid composite available; cannot project.',
    breakdown,
    next_actions,
    honest_caveats: [
      'Rules-based v1 — not yet trained on outcomes (ML projection ships v0.20+).',
      'Accuracy depends on eval grid quality, which depends on public-record completeness.',
      'Coaching fit, intangibles, and market need are not captured in the score.',
      'Physical and production weights are calibrated to LOVB roster medians; other pro pathways (AU, international) use the same bones with different thresholds.'
    ]
  };
}
